{
  "name": "SquareMaster AI",
  "description": "A high-speed square number drill app inspired by Zetamac, featuring AI-powered mental math tips and study assistance."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppView {
  HOME = 'HOME',
  GAME = 'GAME',
  RESULTS = 'RESULTS',
  STUDY = 'STUDY'
}

export interface GameSettings {
  min: number;
  max: number;
  duration: number; // in seconds
}

export interface Question {
  base: number;
  answer: number;
}

export interface AnswerRecord {
  question: Question;
  userAnswer: number;
  isCorrect: boolean;
  timeTaken: number; // ms
}

export interface GameStats {
  totalQuestions: number;
  correct: number;
  score: number;
  history: AnswerRecord[];
  startTime: number;
  endTime: number;
}

import { GoogleGenAI } from "@google/genai";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY is missing from environment variables.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const getMentalMathTip = async (number: number): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "AI unavailable (Missing API Key).";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide a very short, catchy mental math trick or mnemonic to instantly calculate or remember the square of ${number}. Keep it under 2 sentences. Focus on patterns (like ending in 5, near 50, near 100) if applicable.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // fast response
      }
    });
    return response.text || "No tip available.";
  } catch (error) {
    console.error("Error fetching tip:", error);
    return "Could not load tip at this time.";
  }
};

export const getGeneralStudyAdvice = async (topic: string): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "AI unavailable.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a friendly and encouraging math tutor. The user asks: "${topic}". Provide a clear, concise explanation with examples. Use Markdown formatting.`,
    });
    return response.text || "No advice available.";
  } catch (error) {
    console.error("Error fetching advice:", error);
    return "Could not load advice.";
  }
};

import React, { useState } from 'react';
import { AppView, GameSettings } from '../types';
import { Play, BookOpen, BrainCircuit } from 'lucide-react';

interface HomeProps {
  settings: GameSettings;
  setSettings: (settings: GameSettings) => void;
  changeView: (view: AppView) => void;
}

const Home: React.FC<HomeProps> = ({ settings, setSettings, changeView }) => {
  const [localSettings, setLocalSettings] = useState<GameSettings>(settings);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setLocalSettings(prev => ({
      ...prev,
      [name]: parseInt(value) || 0
    }));
  };

  const handleStart = () => {
    // Basic validation
    let { min, max, duration } = localSettings;
    if (min > max) [min, max] = [max, min];
    if (duration < 10) duration = 10;

    const finalSettings = { min, max, duration };
    setSettings(finalSettings);
    changeView(AppView.GAME);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-slate-900 via-indigo-950 to-slate-900 p-6">
      <div className="max-w-md w-full bg-slate-800/50 backdrop-blur-xl p-8 rounded-3xl border border-white/10 shadow-2xl">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-indigo-500 mb-4 shadow-lg shadow-indigo-500/20">
            <BrainCircuit className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-4xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-indigo-300 to-purple-300">
            SquareMaster
          </h1>
          <p className="text-slate-400 mt-2 text-sm">Master your squares. Beat the clock.</p>
        </div>

        <div className="space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs font-semibold text-slate-300 uppercase tracking-wider">Min Range</label>
              <input
                type="number"
                name="min"
                value={localSettings.min}
                onChange={handleChange}
                className="w-full bg-slate-900/50 border border-slate-700 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-center font-mono text-lg"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-semibold text-slate-300 uppercase tracking-wider">Max Range</label>
              <input
                type="number"
                name="max"
                value={localSettings.max}
                onChange={handleChange}
                className="w-full bg-slate-900/50 border border-slate-700 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-center font-mono text-lg"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-semibold text-slate-300 uppercase tracking-wider">Duration (Seconds)</label>
            <input
              type="number"
              name="duration"
              value={localSettings.duration}
              onChange={handleChange}
              className="w-full bg-slate-900/50 border border-slate-700 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-center font-mono text-lg"
            />
          </div>

          <button
            onClick={handleStart}
            className="w-full group relative flex items-center justify-center gap-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-4 px-8 rounded-xl transition-all duration-200 shadow-lg shadow-indigo-600/20 active:scale-[0.98] mt-4"
          >
            <Play className="w-5 h-5 fill-current" />
            <span className="text-lg">Start Assessment</span>
          </button>

          <button
            onClick={() => changeView(AppView.STUDY)}
            className="w-full flex items-center justify-center gap-3 bg-slate-700/50 hover:bg-slate-700 text-slate-200 font-semibold py-3 px-8 rounded-xl transition-all duration-200 border border-white/5"
          >
            <BookOpen className="w-5 h-5" />
            <span>Study Mode</span>
          </button>
        </div>
      </div>

      <div className="mt-8 text-slate-500 text-xs text-center max-w-sm">
        <p>Inspired by Zetamac. Use the AI tutor to learn tricks for calculation.</p>
      </div>
    </div>
  );
};

export default Home;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { X, ArrowRight } from 'lucide-react';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());

  // Stats
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);
  const questionStartTimeRef = useRef<number>(Date.now());

  const generateQuestion = useCallback(() => {
    const range = settings.max - settings.min + 1;
    const base = Math.floor(Math.random() * range) + settings.min;
    return {
      base,
      answer: base * base
    };
  }, [settings]);

  // Initial Question
  useEffect(() => {
    setCurrentQuestion(generateQuestion());
    questionStartTimeRef.current = Date.now();
    setStartTime(Date.now());
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Only run once on mount

  // Timer
  useEffect(() => {
    if (timeLeft <= 0) {
      handleFinish();
      return;
    }

    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);

    return () => clearInterval(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [timeLeft]);

  const handleFinish = () => {
    onFinish({
      totalQuestions: history.length,
      correct: correctCount,
      score,
      history,
      startTime,
      endTime: Date.now()
    });
  };

  const handleAnswer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentQuestion) return;

    const userVal = parseInt(inputValue);
    const isCorrect = userVal === currentQuestion.answer;

    // Record
    const record: AnswerRecord = {
      question: currentQuestion,
      userAnswer: isNaN(userVal) ? 0 : userVal,
      isCorrect,
      timeTaken: Date.now() - questionStartTimeRef.current
    };

    setHistory(prev => [...prev, record]);

    if (isCorrect) {
      setScore(prev => prev + 1); // Simple scoring: 1 point per correct answer
      setCorrectCount(prev => prev + 1);
    } else {
      // In Zetamac style, you just move on, but your score doesn't go up. 
      // Some versions show the correct answer briefly, but for high speed we usually just clear.
      // We will just flash the input red? No, just move next for speed.
    }

    // Next Question
    setInputValue('');
    setCurrentQuestion(generateQuestion());
    questionStartTimeRef.current = Date.now();
  };

  // Keep focus
  useEffect(() => {
    const handleBlur = () => {
        inputRef.current?.focus();
    };
    // Re-focus if user clicks away
    document.addEventListener('click', handleBlur);
    return () => document.removeEventListener('click', handleBlur);
  }, []);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-slate-900 relative overflow-hidden">
      {/* Background decorations */}
      <div className="absolute top-0 left-0 w-full h-2 bg-slate-800">
        <div 
          className="h-full bg-indigo-500 transition-all duration-1000 ease-linear"
          style={{ width: `${(timeLeft / settings.duration) * 100}%` }}
        />
      </div>

      <div className="absolute top-6 right-6 font-mono text-2xl font-bold text-slate-500">
        {timeLeft}s
      </div>

      <div className="absolute top-6 left-6">
        <button 
          onClick={onExit}
          className="p-2 hover:bg-white/10 rounded-full transition-colors text-slate-400 hover:text-white"
        >
          <X className="w-6 h-6" />
        </button>
      </div>

      <div className="w-full max-w-2xl text-center px-4">
        <div className="mb-12">
            <h2 className="text-8xl md:text-9xl font-bold text-white tracking-tighter">
              {currentQuestion?.base}
              <span className="text-indigo-400 align-top text-5xl md:text-6xl mt-4 inline-block">2</span>
            </h2>
        </div>

        <form onSubmit={handleAnswer} className="w-full flex justify-center">
          <input
            ref={inputRef}
            type="number"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            className="w-full max-w-md bg-transparent border-b-4 border-slate-700 focus:border-indigo-500 text-center text-6xl md:text-7xl font-bold text-white focus:outline-none placeholder-slate-800 py-4 transition-colors font-mono"
            placeholder="?"
            autoFocus
          />
        </form>

        <div className="mt-12 text-slate-500 text-lg font-mono">
          Score: <span className="text-indigo-400">{score}</span>
        </div>
      </div>

      <div className="absolute bottom-10 text-slate-600 text-sm flex items-center gap-2">
         Type answer & press Enter <ArrowRight className="w-4 h-4" />
      </div>
    </div>
  );
};

export default Game;

import React, { useState } from 'react';
import { GameStats, AppView, AnswerRecord } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { RefreshCcw, Home as HomeIcon, Lightbulb, CheckCircle2, XCircle, Brain } from 'lucide-react';
import { getMentalMathTip } from '../services/geminiService';

interface ResultsProps {
  stats: GameStats;
  onRestart: () => void;
  onHome: () => void;
}

const Results: React.FC<ResultsProps> = ({ stats, onRestart, onHome }) => {
  const incorrect = stats.totalQuestions - stats.correct;
  const accuracy = stats.totalQuestions > 0 ? Math.round((stats.correct / stats.totalQuestions) * 100) : 0;

  const chartData = [
    { name: 'Correct', value: stats.correct },
    { name: 'Incorrect', value: incorrect },
  ];

  const COLORS = ['#6366f1', '#ef4444']; // Indigo-500, Red-500

  // AI Tip State
  const [loadingTip, setLoadingTip] = useState<number | null>(null);
  const [tips, setTips] = useState<Record<number, string>>({});

  const handleGetTip = async (num: number) => {
    if (tips[num]) return; // Already fetched
    setLoadingTip(num);
    const tip = await getMentalMathTip(num);
    setTips(prev => ({ ...prev, [num]: tip }));
    setLoadingTip(null);
  };

  const mistakes = stats.history.filter(h => !h.isCorrect);

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-6 md:p-12 overflow-y-auto">
      <div className="max-w-5xl mx-auto">
        <div className="flex justify-between items-center mb-12">
          <h2 className="text-3xl font-bold">Session Report</h2>
          <div className="flex gap-4">
            <button onClick={onHome} className="p-3 bg-slate-800 rounded-xl hover:bg-slate-700 transition-colors">
              <HomeIcon className="w-5 h-5" />
            </button>
            <button onClick={onRestart} className="px-6 py-3 bg-indigo-600 rounded-xl font-bold hover:bg-indigo-500 transition-colors flex items-center gap-2">
              <RefreshCcw className="w-5 h-5" />
              Play Again
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-12">
          {/* Main Stats Card */}
          <div className="bg-slate-800/50 border border-white/5 rounded-3xl p-8 flex flex-col items-center justify-center text-center">
             <div className="text-sm text-slate-400 uppercase tracking-widest font-semibold mb-2">Total Score</div>
             <div className="text-6xl font-black text-indigo-400 mb-4">{stats.score}</div>
             <div className="grid grid-cols-2 gap-8 w-full mt-4 border-t border-white/5 pt-6">
                <div>
                   <div className="text-2xl font-bold text-white">{accuracy}%</div>
                   <div className="text-xs text-slate-500">Accuracy</div>
                </div>
                <div>
                   <div className="text-2xl font-bold text-white">{Math.round((stats.totalQuestions / ((stats.endTime - stats.startTime)/60000)) || 0)}</div>
                   <div className="text-xs text-slate-500">Ans/Min</div>
                </div>
             </div>
          </div>

          {/* Chart Card */}
          <div className="bg-slate-800/50 border border-white/5 rounded-3xl p-8 relative h-80 flex items-center justify-center">
            {stats.totalQuestions > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                    data={chartData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                    >
                    {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                    </Pie>
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', borderRadius: '12px' }}
                        itemStyle={{ color: '#fff' }}
                    />
                </PieChart>
                </ResponsiveContainer>
            ) : (
                <div className="text-slate-500">No data available</div>
            )}
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="text-center">
                    <div className="text-3xl font-bold">{stats.totalQuestions}</div>
                    <div className="text-xs text-slate-500">Attempts</div>
                </div>
             </div>
          </div>

          {/* Speed Card (Placeholder for more stats) */}
          <div className="bg-gradient-to-br from-indigo-900/50 to-slate-800/50 border border-indigo-500/20 rounded-3xl p-8 flex flex-col justify-center">
             <div className="flex items-center gap-3 mb-4">
                 <Brain className="w-8 h-8 text-indigo-400" />
                 <h3 className="text-xl font-bold text-white">AI Analysis</h3>
             </div>
             <p className="text-slate-300 text-sm leading-relaxed">
                 {incorrect === 0 && stats.totalQuestions > 5 
                    ? "Perfect run! You are calculating squares faster than most. Try increasing the range for a harder challenge."
                    : incorrect > 5 
                    ? "It looks like you're struggling with accuracy. Use the 'Learning Mode' to memorize the tricky squares."
                    : "Great effort. Review your mistakes below and use the AI Tip feature to learn mnemonics for them."
                 }
             </p>
          </div>
        </div>

        {/* Detailed History with AI Tips */}
        <div className="space-y-6">
            <h3 className="text-xl font-bold text-slate-200">Review Mistakes</h3>
            {mistakes.length === 0 ? (
                <div className="p-8 bg-emerald-900/10 border border-emerald-500/20 rounded-2xl text-center text-emerald-400">
                    <CheckCircle2 className="w-8 h-8 mx-auto mb-2" />
                    No mistakes! Excellent work.
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {mistakes.map((record, idx) => {
                        const num = record.question.base;
                        const tip = tips[num];

                        return (
                            <div key={idx} className="bg-slate-800/40 border border-red-500/10 rounded-2xl p-5 hover:bg-slate-800/60 transition-colors">
                                <div className="flex justify-between items-start mb-3">
                                    <div>
                                        <div className="text-2xl font-bold text-white mb-1">
                                            {num}² = <span className="text-indigo-400">{record.question.answer}</span>
                                        </div>
                                        <div className="text-xs text-red-400 flex items-center gap-1">
                                            <XCircle className="w-3 h-3" />
                                            You answered: {record.userAnswer}
                                        </div>
                                    </div>
                                    <button 
                                        onClick={() => handleGetTip(num)}
                                        disabled={loadingTip === num || !!tip}
                                        className="p-2 bg-indigo-500/10 text-indigo-400 hover:bg-indigo-500 hover:text-white rounded-lg transition-all"
                                        title="Get AI Tip"
                                    >
                                        <Lightbulb className={`w-5 h-5 ${loadingTip === num ? 'animate-pulse' : ''}`} />
                                    </button>
                                </div>

                                {tip && (
                                    <div className="mt-3 p-3 bg-indigo-900/20 rounded-lg border border-indigo-500/20 text-sm text-indigo-200 animate-in fade-in slide-in-from-top-2">
                                        <span className="font-bold text-indigo-400 block text-xs uppercase mb-1">AI Tip:</span>
                                        {tip}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default Results;

import React, { useState } from 'react';
import { AppView, GameSettings } from '../types';
import { ArrowLeft, Search, Sparkles, Send } from 'lucide-react';
import { getGeneralStudyAdvice } from '../services/geminiService';
import ReactMarkdown from 'react-markdown';

interface StudyProps {
  settings: GameSettings;
  onBack: () => void;
}

const Study: React.FC<StudyProps> = ({ settings, onBack }) => {
  const [activeTab, setActiveTab] = useState<'reference' | 'ai-tutor'>('reference');

  // Reference Table Generation
  const squares: { base: number; sq: number }[] = [];
  for (let i = 1; i <= 50; i++) {
    squares.push({ base: i, sq: i * i });
  }

  // AI Chat State
  const [prompt, setPrompt] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'ai', content: string}[]>([
      {role: 'ai', content: 'Hello! I am your Math Tutor. Ask me how to calculate specific squares, or for general mental math tricks!'}
  ]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
      if (!prompt.trim()) return;
      const userMsg = prompt;
      setPrompt('');
      setChatHistory(prev => [...prev, {role: 'user', content: userMsg}]);
      setLoading(true);

      const response = await getGeneralStudyAdvice(userMsg);

      setChatHistory(prev => [...prev, {role: 'ai', content: response}]);
      setLoading(false);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col">
      {/* Header */}
      <header className="border-b border-white/5 bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
            <div className="flex items-center gap-4">
                <button onClick={onBack} className="p-2 hover:bg-white/10 rounded-full text-slate-400 hover:text-white transition-colors">
                    <ArrowLeft className="w-5 h-5" />
                </button>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-300 to-purple-300">
                    Study Center
                </h1>
            </div>
            <div className="flex bg-slate-800 p-1 rounded-lg">
                <button 
                    onClick={() => setActiveTab('reference')}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'reference' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                >
                    Reference
                </button>
                <button 
                    onClick={() => setActiveTab('ai-tutor')}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'ai-tutor' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                >
                    <Sparkles className="w-3 h-3" />
                    AI Tutor
                </button>
            </div>
        </div>
      </header>

      <div className="flex-1 max-w-6xl w-full mx-auto p-4 md:p-8">
        {activeTab === 'reference' ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="mb-6 flex flex-col md:flex-row justify-between items-end gap-4">
                    <div>
                        <h2 className="text-2xl font-bold text-white mb-2">Square Table (1-50)</h2>
                        <p className="text-slate-400">Memorize these common squares to speed up your mental math.</p>
                    </div>
                </div>

                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3">
                    {squares.map((item) => (
                        <div key={item.base} className="bg-slate-800 border border-white/5 p-4 rounded-xl flex justify-between items-center hover:bg-indigo-900/20 hover:border-indigo-500/30 transition-all group">
                            <span className="text-lg font-mono font-semibold text-slate-400 group-hover:text-indigo-300">{item.base}²</span>
                            <span className="text-2xl font-bold text-white">{item.sq}</span>
                        </div>
                    ))}
                </div>
            </div>
        ) : (
            <div className="h-[calc(100vh-140px)] flex flex-col animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="flex-1 bg-slate-800/30 border border-white/5 rounded-2xl p-4 overflow-y-auto mb-4 space-y-4">
                    {chatHistory.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[80%] rounded-2xl p-4 ${
                                msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-br-none' 
                                : 'bg-slate-700 text-slate-100 rounded-bl-none'
                            }`}>
                                {msg.role === 'ai' ? (
                                    <div className="prose prose-invert prose-sm max-w-none">
                                        <ReactMarkdown>{msg.content}</ReactMarkdown>
                                    </div>
                                ) : (
                                    <p>{msg.content}</p>
                                )}
                            </div>
                        </div>
                    ))}
                    {loading && (
                        <div className="flex justify-start">
                             <div className="bg-slate-700 rounded-2xl p-4 rounded-bl-none flex items-center gap-2">
                                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" />
                                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-.3s]" />
                                <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-.5s]" />
                             </div>
                        </div>
                    )}
                </div>

                <div className="relative">
                    <input
                        type="text"
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        placeholder="Ask for a math trick..."
                        className="w-full bg-slate-800 border border-slate-600 rounded-xl pl-4 pr-12 py-4 text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                    />
                    <button 
                        onClick={handleSend}
                        disabled={!prompt.trim() || loading}
                        className="absolute right-2 top-2 p-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:hover:bg-indigo-600 text-white rounded-lg transition-colors"
                    >
                        <Send className="w-5 h-5" />
                    </button>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

