import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { X, ArrowRight, Zap } from 'lucide-react';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());

  // Stats
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);
  const questionStartTimeRef = useRef<number>(Date.now());

  // Smart Mode Weights
  // Map of number -> weight. Higher weight = higher probability.
  const weightsRef = useRef<Record<number, number>>({});

  useEffect(() => {
    // Initialize weights
    const initialWeights: Record<number, number> = {};
    for (let i = settings.min; i <= settings.max; i++) {
      initialWeights[i] = 1;
    }
    weightsRef.current = initialWeights;
  }, [settings]);

  const generateQuestion = useCallback(() => {
    // Standard Random
    if (!settings.smartMode) {
        const range = settings.max - settings.min + 1;
        const base = Math.floor(Math.random() * range) + settings.min;
        return { base, answer: base * base };
    }

    // Smart Random (Weighted)
    const weights = weightsRef.current;
    let totalWeight = 0;
    const candidates: { val: number; weight: number }[] = [];

    for (let i = settings.min; i <= settings.max; i++) {
        const w = weights[i] || 1; // Default to 1 just in case
        candidates.push({ val: i, weight: w });
        totalWeight += w;
    }

    let random = Math.random() * totalWeight;
    let selected = candidates[candidates.length - 1].val;

    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) {
            selected = item.val;
            break;
        }
    }

    return {
      base: selected,
      answer: selected * selected
    };
  }, [settings]);

  // Initial Question
  useEffect(() => {
    setCurrentQuestion(generateQuestion());
    questionStartTimeRef.current = Date.now();
    setStartTime(Date.now());
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  // Timer
  useEffect(() => {
    if (timeLeft <= 0) {
      handleFinish();
      return;
    }

    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);

    return () => clearInterval(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [timeLeft]);

  const handleFinish = () => {
    // Calculate problematic numbers (Weight > 1.5)
    const problematic: number[] = [];
    if (settings.smartMode) {
        Object.entries(weightsRef.current).forEach(([numStr, weight]) => {
            if (weight > 1.5) {
                problematic.push(parseInt(numStr));
            }
        });
    }

    onFinish({
      totalQuestions: history.length,
      correct: correctCount,
      score,
      history,
      startTime,
      endTime: Date.now(),
      problematicNumbers: problematic
    });
  };

  const handleAnswer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentQuestion) return;

    const userVal = parseInt(inputValue);
    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    // Record
    const record: AnswerRecord = {
      question: currentQuestion,
      userAnswer: isNaN(userVal) ? 0 : userVal,
      isCorrect,
      timeTaken
    };

    setHistory(prev => [...prev, record]);

    // Update Weights for Smart Mode
    if (settings.smartMode) {
        const base = currentQuestion.base;
        let newWeight = weightsRef.current[base] || 1;

        if (!isCorrect) {
            // Massive penalty for wrong answers, make it appear very soon
            newWeight += 5;
        } else {
            if (timeTaken > 4000) {
                // Correct but very slow (> 4s)
                newWeight += 2;
            } else if (timeTaken > 2000) {
                // Correct but moderately slow (> 2s)
                newWeight += 0.5;
            } else {
                // Correct and fast, decrease weight but keep minimum
                newWeight = Math.max(0.5, newWeight - 1);
            }
        }
        // Cap max weight to prevent a single number from hijacking the entire session
        weightsRef.current[base] = Math.min(newWeight, 20);
    }

    if (isCorrect) {
      setScore(prev => prev + 1); 
      setCorrectCount(prev => prev + 1);
    }

    // Next Question
    setInputValue('');

    // Prevent immediate repeat unless range is tiny
    let nextQ = generateQuestion();
    const rangeSize = settings.max - settings.min;
    if (rangeSize > 2 && nextQ.base === currentQuestion.base) {
        nextQ = generateQuestion();
    }

    setCurrentQuestion(nextQ);
    questionStartTimeRef.current = Date.now();
  };

  // Keep focus
  useEffect(() => {
    const handleBlur = () => {
        inputRef.current?.focus();
    };
    document.addEventListener('click', handleBlur);
    return () => document.removeEventListener('click', handleBlur);
  }, []);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-slate-900 relative overflow-hidden">
      {/* Background decorations */}
      <div className="absolute top-0 left-0 w-full h-2 bg-slate-800">
        <div 
          className="h-full bg-indigo-500 transition-all duration-1000 ease-linear"
          style={{ width: `${(timeLeft / settings.duration) * 100}%` }}
        />
      </div>

      <div className="absolute top-6 right-6 font-mono text-2xl font-bold text-slate-500">
        {timeLeft}s
      </div>

      <div className="absolute top-6 left-6 flex gap-4 items-center">
        <button 
          onClick={onExit}
          className="p-2 hover:bg-white/10 rounded-full transition-colors text-slate-400 hover:text-white"
        >
          <X className="w-6 h-6" />
        </button>
        {settings.smartMode && (
            <div className="flex items-center gap-2 px-3 py-1 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-xs font-bold animate-pulse">
                <Zap className="w-3 h-3" />
                SMART MODE
            </div>
        )}
      </div>

      <div className="w-full max-w-2xl text-center px-4">
        <div className="mb-12">
            <h2 className="text-8xl md:text-9xl font-bold text-white tracking-tighter">
              {currentQuestion?.base}
              <span className="text-indigo-400 align-top text-5xl md:text-6xl mt-4 inline-block">2</span>
            </h2>
        </div>

        <form onSubmit={handleAnswer} className="w-full flex justify-center">
          <input
            ref={inputRef}
            type="number"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            className="w-full max-w-md bg-transparent border-b-4 border-slate-700 focus:border-indigo-500 text-center text-6xl md:text-7xl font-bold text-white focus:outline-none placeholder-slate-800 py-4 transition-colors font-mono"
            placeholder="?"
            autoFocus
          />
        </form>

        <div className="mt-12 text-slate-500 text-lg font-mono">
          Score: <span className="text-indigo-400">{score}</span>
        </div>
      </div>

      <div className="absolute bottom-10 text-slate-600 text-sm flex items-center gap-2">
         Type answer & press Enter <ArrowRight className="w-4 h-4" />
      </div>
    </div>
  );
};

export default Game;

