import React, { useState } from 'react';
import { AppView, GameSettings, GameStats } from './types';
import Home from './components/Home';
import Game from './components/Game';
import Results from './components/Results';
import Study from './components/Study';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);

  const [settings, setSettings] = useState<GameSettings>({
    mode: 'SQUARES',
    min: 2,
    max: 20,
    duration: 120,
    smartMode: true
  });

  const [lastStats, setLastStats] = useState<GameStats | null>(null);

  const handleGameFinish = (stats: GameStats) => {
    setLastStats(stats);
    setCurrentView(AppView.RESULTS);
  };

  const renderView = () => {
    switch (currentView) {
      case AppView.HOME:
        return (
          <Home 
            settings={settings} 
            setSettings={setSettings} 
            changeView={setCurrentView} 
          />
        );
      case AppView.GAME:
        return (
          <Game 
            settings={settings} 
            onFinish={handleGameFinish} 
            onExit={() => setCurrentView(AppView.HOME)}
          />
        );
      case AppView.RESULTS:
        return lastStats ? (
          <Results 
            stats={lastStats} 
            onRestart={() => setCurrentView(AppView.GAME)} 
            onHome={() => setCurrentView(AppView.HOME)} 
          />
        ) : (
          <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />
        );
      case AppView.STUDY:
        return (
          <Study 
            settings={settings}
            onBack={() => setCurrentView(AppView.HOME)}
          />
        );
      default:
        return <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />;
    }
  };

  return (
    <div className="antialiased">
      {renderView()}
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { Question } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY is missing from environment variables.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const getMentalMathTip = async (question: Question): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "AI unavailable (Missing API Key).";

  const isSquare = question.mode === 'SQUARES';
  const prompt = isSquare 
    ? `Provide a very short, catchy mental math trick or mnemonic to instantly calculate or remember the square of ${question.val1}. Keep it under 2 sentences.`
    : `Provide a very short, catchy mental math trick to calculate ${question.val1} multiplied by ${question.val2} mentally. Keep it under 2 sentences.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // fast response
      }
    });
    return response.text || "No tip available.";
  } catch (error) {
    console.error("Error fetching tip:", error);
    return "Could not load tip at this time.";
  }
};

export const getGeneralStudyAdvice = async (topic: string): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "AI unavailable.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a friendly and encouraging math tutor. The user asks: "${topic}". Provide a clear, concise explanation with examples. Use Markdown formatting.`,
    });
    return response.text || "No advice available.";
  } catch (error) {
    console.error("Error fetching advice:", error);
    return "Could not load advice.";
  }
};

