import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { X, ArrowRight, Zap, Repeat, Flame } from 'lucide-react';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());

  // Stats
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [streak, setStreak] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);
  const questionStartTimeRef = useRef<number>(Date.now());

  // Smart Mode Logic
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);

  // Initialize Weights
  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode);
        const activeWeights: Record<number, number> = {};

        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) {
                    activeWeights[i] = getInitialWeight(i, persisted[i]);
                }
            }
        };

        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') {
            initRange(settings.min2, settings.max2);
        }

        weightsRef.current = activeWeights;
    }
  }, [settings]);

  // Save weights
  useEffect(() => {
    return () => {
        if (settings.smartMode) {
            saveWeights(settings.mode, weightsRef.current);
        }
    };
  }, [settings]);

  const getWeightedRandom = (min: number, max: number) => {
    const candidates: { val: number; weight: number }[] = [];
    const weights = weightsRef.current;

    for (let i = min; i <= max; i++) {
        const w = weights[i] !== undefined ? weights[i] : getInitialWeight(i);
        candidates.push({ val: i, weight: w }); 
    }

    let totalWeight = 0;
    for (const item of candidates) totalWeight += item.weight;

    let random = Math.random() * totalWeight;
    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) return item.val;
    }
    return candidates[candidates.length - 1]?.val || min;
  };

  const generateQuestion = useCallback(() => {
    // 1. Retry Logic
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }

    questionsSinceRetryRef.current++;

    // 2. Generation Logic
    let val1, val2, answer;

    const getRandom = (min: number, max: number) => {
        if (settings.smartMode) return getWeightedRandom(min, max);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    switch (settings.mode) {
        case 'SQUARES':
            val1 = getRandom(settings.min, settings.max);
            return {
                mode: 'SQUARES',
                val1,
                answer: val1 * val1,
                isRetry: false
            } as Question;

        case 'ADDITION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            return {
                mode: 'ADDITION',
                val1,
                val2,
                answer: val1 + val2,
                isRetry: false
            } as Question;

        case 'SUBTRACTION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            // Optional: Bias towards positive results for standard drills?
            // Standard behavior allows negatives if ranges allow it. 
            return {
                mode: 'SUBTRACTION',
                val1,
                val2,
                answer: val1 - val2,
                isRetry: false
            } as Question;

        case 'MULTIPLICATION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            // Smart mode biasing for multiplication
            if (settings.smartMode && weightsRef.current[val1] > 1.2 && Math.random() > 0.7) {
                 val2 = getRandom(settings.min2, settings.max2);
            }
            return {
                mode: 'MULTIPLICATION',
                val1,
                val2,
                answer: val1 * val2,
                isRetry: false
            } as Question;

        case 'DIVISION':
            // Smart Division: val2 is Divisor (Range 2). answer is Quotient (Range 1).
            // val1 (Dividend) = val2 * answer.
            // This ensures integer division.
            val2 = getRandom(settings.min2, settings.max2); // Divisor
            answer = getRandom(settings.min, settings.max); // Quotient
            val1 = val2 * answer;

            return {
                mode: 'DIVISION',
                val1, // Displayed Dividend
                val2, // Displayed Divisor
                answer, // Expected answer
                isRetry: false
            } as Question;

        default:
             return { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
    }
  }, [settings]);

  // Initial Question
  useEffect(() => {
    setCurrentQuestion(generateQuestion());
    questionStartTimeRef.current = Date.now();
    setStartTime(Date.now());
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  // Timer
  useEffect(() => {
    if (timeLeft <= 0) {
      handleFinish();
      return;
    }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [timeLeft]);

  const handleFinish = () => {
    if (settings.smartMode) {
        saveWeights(settings.mode, weightsRef.current);
    }
    onFinish({
      totalQuestions: history.length,
      correct: correctCount,
      score,
      history,
      startTime,
      endTime: Date.now(),
      problematicKeys: [] // Simplified for now
    });
  };

  const updateWeights = (q: Question, isCorrect: boolean, timeTaken: number) => {
      if (!settings.smartMode) return;

      const calcNewWeight = (currentW: number) => {
          let newW = currentW;
          if (!isCorrect) newW += 2.0;
          else {
              if (timeTaken > 5000) newW += 1.0;
              else if (timeTaken > 3000) newW += 0.2;
              else if (timeTaken < 1500) newW = Math.max(0.5, newW - 0.2);
          }
          return Math.min(newW, 10);
      };

      if (q.mode === 'SQUARES') {
          weightsRef.current[q.val1] = calcNewWeight(weightsRef.current[q.val1] || 1);
      } else if (q.mode === 'DIVISION') {
          // For division A / B = C, we really test B * C = A.
          // Weight the divisor (val2) and quotient (answer)
          if (q.val2) weightsRef.current[q.val2] = calcNewWeight(weightsRef.current[q.val2] || 1);
          weightsRef.current[q.answer] = calcNewWeight(weightsRef.current[q.answer] || 1);
      } else if (q.val2) {
          weightsRef.current[q.val1] = calcNewWeight(weightsRef.current[q.val1] || 1);
          weightsRef.current[q.val2] = calcNewWeight(weightsRef.current[q.val2] || 1);
      }
  };

  const handleAnswer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentQuestion) return;

    // Handle standard minus sign (hyphen) and generic minus
    const cleanInput = inputValue.replace('−', '-');
    const userVal = parseInt(cleanInput);
    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    const record: AnswerRecord = {
      question: currentQuestion,
      userAnswer: isNaN(userVal) ? 0 : userVal,
      isCorrect,
      timeTaken
    };

    setHistory(prev => [...prev, record]);
    updateWeights(currentQuestion, isCorrect, timeTaken);

    if (isCorrect) {
      setScore(prev => prev + 1); 
      setCorrectCount(prev => prev + 1);
      setStreak(prev => prev + 1);
    } else {
      setStreak(0);
      if (settings.smartMode) {
          retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      }
    }

    setInputValue('');

    let nextQ = generateQuestion();
    // Simple dedupe
    let attempts = 0;
    while (attempts < 5 && !nextQ.isRetry) {
        if (nextQ.val1 === currentQuestion.val1 && nextQ.val2 === currentQuestion.val2) {
            // try again
        } else {
            break;
        }
        nextQ = generateQuestion();
        attempts++;
    }

    setCurrentQuestion(nextQ);
    questionStartTimeRef.current = Date.now();
  };

  // Keep focus
  useEffect(() => {
    const handleBlur = () => { inputRef.current?.focus(); };
    document.addEventListener('click', handleBlur);
    return () => document.removeEventListener('click', handleBlur);
  }, []);

  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-slate-900 relative overflow-hidden font-inter">
      {/* Background decorations */}
      <div className="absolute top-0 left-0 w-full h-2 bg-slate-800">
        <div 
          className="h-full bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,0.5)] transition-all duration-1000 ease-linear"
          style={{ width: `${(timeLeft / settings.duration) * 100}%` }}
        />
      </div>

      <div className="absolute top-6 right-6 font-mono text-2xl font-bold text-slate-500/50">
        {timeLeft}s
      </div>

      <div className="absolute top-6 left-6 flex gap-4 items-center">
        <button 
          onClick={onExit}
          className="p-3 bg-white/5 hover:bg-white/10 rounded-full transition-colors text-slate-400 hover:text-white"
        >
          <X className="w-5 h-5" />
        </button>
        {settings.smartMode && (
            <div className="flex items-center gap-2 px-3 py-1 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-xs font-bold animate-pulse">
                <Zap className="w-3 h-3" />
                SMART
            </div>
        )}
      </div>

      {streak > 2 && (
          <div className="absolute top-20 right-6 animate-in fade-in slide-in-from-right-4">
              <div className="flex items-center gap-2 text-orange-400 font-bold">
                  <Flame className="w-5 h-5 fill-current animate-pulse" />
                  <span className="text-xl">{streak}</span>
              </div>
          </div>
      )}

      <div className="w-full max-w-2xl text-center px-4">
        {/* Retry Indicator */}
        <div className="h-8 mb-4 flex items-center justify-center">
            {currentQuestion?.isRetry && (
                <div className="flex items-center gap-2 text-amber-400 text-sm font-bold bg-amber-400/10 px-3 py-1 rounded-full animate-in fade-in zoom-in duration-300">
                    <Repeat className="w-3 h-3" />
                    Reviewing Mistake
                </div>
            )}
        </div>

        <div className="mb-12 scale-110 md:scale-125 transition-transform duration-500">
            <h2 className="text-7xl md:text-9xl font-bold text-white tracking-tighter flex items-center justify-center gap-4 drop-shadow-2xl">
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    {currentQuestion.val1}
                    <span className="text-indigo-400 align-top text-5xl md:text-6xl -mt-8 inline-block opacity-80">2</span>
                  </>
              ) : (
                  <>
                    {currentQuestion?.val1}
                    <span className="text-indigo-500 text-6xl md:text-7xl opacity-80 mx-2">{getOperator()}</span>
                    {currentQuestion?.val2}
                  </>
              )}
            </h2>
        </div>

        <form onSubmit={handleAnswer} className="w-full flex justify-center">
          <input
            ref={inputRef}
            type="number"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            className={`w-full max-w-xs bg-transparent border-b-4 text-center text-7xl font-bold text-white focus:outline-none placeholder-slate-800 py-4 transition-all font-mono ${
                currentQuestion?.isRetry 
                ? 'border-amber-500/50 focus:border-amber-500' 
                : 'border-slate-700 focus:border-indigo-500'
            }`}
            placeholder=""
            autoFocus
          />
        </form>

        <div className="mt-16 flex justify-center">
             <div className="px-6 py-2 bg-slate-800/50 rounded-full border border-white/5 backdrop-blur-sm">
                <span className="text-slate-500 font-medium uppercase tracking-widest text-xs mr-3">Score</span>
                <span className="text-2xl font-bold text-indigo-400 font-mono">{score}</span>
             </div>
        </div>
      </div>

      <div className="absolute bottom-10 text-slate-600 text-sm flex items-center gap-2 animate-pulse">
         Type answer & press Enter <ArrowRight className="w-4 h-4" />
      </div>
    </div>
  );
};

