import React, { useState } from 'react';
import { GameStats, AnswerRecord } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { RefreshCcw, Home as HomeIcon, Lightbulb, XCircle, Brain, Target, Zap } from 'lucide-react';
import { getMentalMathTip } from '../services/geminiService';

interface ResultsProps {
  stats: GameStats;
  onRestart: () => void;
  onHome: () => void;
}

const Results: React.FC<ResultsProps> = ({ stats, onRestart, onHome }) => {
  const incorrect = stats.totalQuestions - stats.correct;
  const accuracy = stats.totalQuestions > 0 ? Math.round((stats.correct / stats.totalQuestions) * 100) : 0;

  const chartData = [
    { name: 'Correct', value: stats.correct },
    { name: 'Incorrect', value: incorrect },
  ];

  const COLORS = ['#6366f1', '#ef4444']; 
  const [loadingTip, setLoadingTip] = useState<string | null>(null);
  const [tips, setTips] = useState<Record<string, string>>({});

  const getQuestionKey = (q: AnswerRecord['question']) => {
      if (q.mode === 'SQUARES') return `sq_${q.val1}`;
      return `${q.mode}_${q.val1}_${q.val2}`;
  };

  const handleGetTip = async (record: AnswerRecord) => {
    const key = getQuestionKey(record.question);
    if (tips[key]) return; 
    setLoadingTip(key);
    const tip = await getMentalMathTip(record.question);
    setTips(prev => ({ ...prev, [key]: tip }));
    setLoadingTip(null);
  };

  const mistakes = stats.history.filter(h => !h.isCorrect);
  const formatQuestion = (q: AnswerRecord['question']) => {
      let op = '';
      switch (q.mode) {
          case 'MULTIPLICATION': op = '×'; break;
          case 'ADDITION': op = '+'; break;
          case 'SUBTRACTION': op = '−'; break;
          case 'DIVISION': op = '÷'; break;
          default: op = '';
      }
      if (q.mode === 'SQUARES') return <span>{q.val1}<sup className="text-indigo-400">2</sup></span>;
      return <span>{q.val1} <span className="text-indigo-400">{op}</span> {q.val2}</span>;
  };

  return (
    <div className="min-h-screen p-6 md:p-12 overflow-y-auto">
      <div className="max-w-5xl mx-auto space-y-8">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-center gap-6">
          <div>
            <h2 className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400">Performance Report</h2>
            <p className="text-slate-400 mt-1">Session completed on {new Date(stats.endTime).toLocaleTimeString()}</p>
          </div>
          <div className="flex gap-4">
            <button onClick={onHome} className="p-4 glass rounded-2xl hover:bg-white/10 transition-colors text-slate-300 hover:text-white">
              <HomeIcon className="w-6 h-6" />
            </button>
            <button onClick={onRestart} className="px-8 py-4 bg-indigo-600 rounded-2xl font-bold hover:bg-indigo-500 transition-all shadow-lg hover:shadow-indigo-500/30 flex items-center gap-3">
              <RefreshCcw className="w-5 h-5" />
              Play Again
            </button>
          </div>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

          {/* Main Score */}
          <div className="glass rounded-3xl p-8 flex flex-col justify-between relative overflow-hidden group">
             <div className="absolute top-0 right-0 p-32 bg-indigo-600/10 rounded-full blur-[60px] group-hover:bg-indigo-600/20 transition-all" />
             <div className="flex items-center gap-3 text-indigo-400 mb-4">
                 <Target className="w-5 h-5" />
                 <span className="text-xs font-bold uppercase tracking-widest">Score</span>
             </div>
             <div className="text-7xl font-black text-white tracking-tighter mb-2">{stats.score}</div>
             <div className="text-slate-400 text-sm">Total points accumulated</div>
          </div>

          {/* Accuracy & Speed */}
          <div className="glass rounded-3xl p-8 flex flex-col justify-between relative overflow-hidden">
             <div className="flex items-center gap-3 text-emerald-400 mb-6">
                 <Zap className="w-5 h-5" />
                 <span className="text-xs font-bold uppercase tracking-widest">Efficiency</span>
             </div>
             <div className="grid grid-cols-2 gap-8">
                <div>
                   <div className="text-4xl font-bold text-white mb-1">{accuracy}%</div>
                   <div className="text-xs text-slate-500 uppercase tracking-wider font-bold">Accuracy</div>
                </div>
                <div>
                   <div className="text-4xl font-bold text-white mb-1">{Math.round((stats.totalQuestions / ((stats.endTime - stats.startTime)/60000)) || 0)}</div>
                   <div className="text-xs text-slate-500 uppercase tracking-wider font-bold">Ans/Min</div>
                </div>
             </div>
          </div>

          {/* Chart */}
          <div className="glass rounded-3xl p-6 flex items-center justify-center relative">
            {stats.totalQuestions > 0 ? (
                <div className="w-full h-48">
                    <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie
                        data={chartData}
                        cx="50%"
                        cy="50%"
                        innerRadius={50}
                        outerRadius={70}
                        paddingAngle={8}
                        dataKey="value"
                        stroke="none"
                        cornerRadius={6}
                        >
                        {chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} className="drop-shadow-lg" />
                        ))}
                        </Pie>
                        <Tooltip contentStyle={{ backgroundColor: 'rgba(15, 23, 42, 0.9)', borderColor: 'rgba(255,255,255,0.1)', borderRadius: '12px' }} itemStyle={{ color: '#fff' }} />
                    </PieChart>
                    </ResponsiveContainer>
                </div>
            ) : <span className="text-slate-500">No data</span>}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="text-center">
                    <div className="text-2xl font-bold">{stats.totalQuestions}</div>
                    <div className="text-[10px] text-slate-500 uppercase tracking-widest">Total</div>
                </div>
             </div>
          </div>
        </div>

        {/* AI Analysis Section */}
        <div className="glass-panel rounded-3xl p-8 border-l-4 border-indigo-500">
             <div className="flex items-center gap-3 mb-4">
                 <Brain className="w-6 h-6 text-indigo-400" />
                 <h3 className="text-xl font-bold text-white">AI Analysis</h3>
             </div>
             <p className="text-slate-300 leading-relaxed max-w-3xl">
                 {incorrect === 0 && stats.totalQuestions > 5 
                    ? "Flawless performance! Your mental calculation speed is impressive. Consider expanding the number range to challenge your cognitive limits further."
                    : incorrect > 3 
                        ? "You're building good momentum, but consistency on the edge cases needs work. The AI has identified your weak spots and will prioritize them in the next session."
                        : "Solid session. You handled most standard operations well, but slowed down on the larger transitions. Keep practicing to build muscle memory."
                 }
             </p>
        </div>

        {/* Mistakes List */}
        {mistakes.length > 0 && (
            <div className="space-y-6 animate-in slide-in-from-bottom-8 fade-in duration-700">
                <h3 className="text-2xl font-bold text-white">Learning Opportunities</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {mistakes.map((record, idx) => {
                        const key = getQuestionKey(record.question);
                        const tip = tips[key];
                        return (
                            <div key={idx} className="glass-panel p-6 rounded-2xl group hover:bg-white/5 transition-colors">
                                <div className="flex justify-between items-start mb-4">
                                    <div>
                                        <div className="text-2xl font-mono font-bold text-white mb-2">
                                            {formatQuestion(record.question)}
                                        </div>
                                        <div className="flex items-center gap-2 text-sm text-red-400 font-mono bg-red-500/10 px-2 py-1 rounded-md w-fit">
                                            <XCircle className="w-3 h-3" />
                                            {record.userAnswer}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="text-xs text-slate-500 uppercase tracking-wider mb-1">Correct</div>
                                        <div className="text-xl font-bold text-emerald-400 font-mono">{record.question.answer}</div>
                                    </div>
                                </div>

                                {tip ? (
                                    <div className="mt-4 pt-4 border-t border-white/5 text-sm text-indigo-200 leading-relaxed animate-in fade-in">
                                        <span className="text-indigo-400 font-bold block text-xs uppercase mb-1">Memorization Tip</span>
                                        {tip}
                                    </div>
                                ) : (
                                    <button 
                                        onClick={() => handleGetTip(record)}
                                        disabled={loadingTip === key}
                                        className="w-full mt-2 py-2 text-xs font-bold uppercase tracking-widest text-indigo-400 hover:text-white hover:bg-indigo-600/20 rounded-lg transition-all flex items-center justify-center gap-2"
                                    >
                                        <Lightbulb className="w-3 h-3" />
                                        {loadingTip === key ? 'Analyzing...' : 'Get AI Trick'}
                                    </button>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

export default Results;

import React, { useState } from 'react';
import { AppView, GameSettings } from '../types';
import { ArrowLeft, Sparkles, Send, GraduationCap } from 'lucide-react';
import { getGeneralStudyAdvice } from '../services/geminiService';
import ReactMarkdown from 'react-markdown';

interface StudyProps {
  settings: GameSettings;
  onBack: () => void;
}

const Study: React.FC<StudyProps> = ({ settings, onBack }) => {
  const [activeTab, setActiveTab] = useState<'reference' | 'ai-tutor'>('reference');

  const squares: { base: number; sq: number }[] = [];
  for (let i = 1; i <= 50; i++) squares.push({ base: i, sq: i * i });

  const [prompt, setPrompt] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'ai', content: string}[]>([
      {role: 'ai', content: "Hi! I'm your AI Math Tutor. Ask me for mental math tricks, how to calculate squares faster, or explain a concept!"}
  ]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
      if (!prompt.trim()) return;
      const userMsg = prompt;
      setPrompt('');
      setChatHistory(prev => [...prev, {role: 'user', content: userMsg}]);
      setLoading(true);
      const response = await getGeneralStudyAdvice(userMsg);
      setChatHistory(prev => [...prev, {role: 'ai', content: response}]);
      setLoading(false);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="glass sticky top-0 z-20 border-b-0">
        <div className="max-w-5xl mx-auto px-4 h-20 flex items-center justify-between">
