                    <ArrowLeft className="w-5 h-5" />
                </button>
                <div>
                    <h1 className="text-xl font-bold text-white flex items-center gap-2">
                        <GraduationCap className="w-5 h-5 text-indigo-400" />
                        Study Center
                    </h1>
                </div>
            </div>
            <div className="flex bg-slate-900/50 p-1 rounded-xl ring-1 ring-white/10">
                <button 
                    onClick={() => setActiveTab('reference')}
                    className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'reference' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
                >
                    Reference
                </button>
                <button 
                    onClick={() => setActiveTab('ai-tutor')}
                    className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all flex items-center gap-2 ${activeTab === 'ai-tutor' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
                >
                    <Sparkles className="w-3 h-3" />
                    AI Tutor
                </button>
            </div>
        </div>
      </header>

      <div className="flex-1 max-w-5xl w-full mx-auto p-4 md:p-8">
        {activeTab === 'reference' ? (
            <div className="animate-in fade-in slide-in-from-bottom-8 duration-500">
                <h2 className="text-3xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400 mb-8">Square Table (1-50)</h2>
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                    {squares.map((item) => (
                        <div key={item.base} className="glass-panel p-4 rounded-xl flex justify-between items-center group hover:bg-indigo-600/10 hover:border-indigo-500/30 transition-all cursor-default">
                            <span className="text-lg font-mono font-bold text-slate-500 group-hover:text-indigo-300 transition-colors">{item.base}²</span>
                            <span className="text-2xl font-bold text-white">{item.sq}</span>
                        </div>
                    ))}
                </div>
            </div>
        ) : (
            <div className="h-[calc(100vh-160px)] flex flex-col glass rounded-3xl overflow-hidden shadow-2xl animate-in zoom-in-95 duration-500 ring-1 ring-white/10">
                <div className="flex-1 overflow-y-auto p-6 space-y-6">
                    {chatHistory.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[85%] rounded-2xl p-5 shadow-lg backdrop-blur-sm ${
                                msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-br-sm' 
                                : 'bg-slate-800/80 text-slate-200 rounded-bl-sm border border-white/5'
                            }`}>
                                {msg.role === 'ai' ? (
                                    <div className="prose prose-invert prose-sm max-w-none">
                                        <ReactMarkdown>{msg.content}</ReactMarkdown>
                                    </div>
                                ) : (
                                    <p className="text-sm font-medium leading-relaxed">{msg.content}</p>
                                )}
                            </div>
                        </div>
                    ))}
                    {loading && (
                        <div className="flex justify-start">
                             <div className="bg-slate-800/80 rounded-2xl p-4 rounded-bl-sm flex items-center gap-2 border border-white/5">
                                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" />
                                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.3s]" />
                                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.5s]" />
                             </div>
                        </div>
                    )}
                </div>

                <div className="p-4 bg-slate-900/50 border-t border-white/5">
                    <div className="relative flex items-center gap-2">
                        <input
                            type="text"
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                            placeholder="Ask me anything about mental math..."
                            className="w-full bg-slate-800/50 border border-white/10 rounded-2xl pl-5 pr-14 py-4 text-white placeholder-slate-500 focus:outline-none focus:bg-slate-800 focus:border-indigo-500 transition-all"
                        />
                        <button 
                            onClick={handleSend}
                            disabled={!prompt.trim() || loading}
                            className="absolute right-2 p-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:hover:bg-indigo-600 text-white rounded-xl transition-all shadow-lg"
                        >
                            <Send className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

export default Study;

import React, { useState } from 'react';
import { AppView, GameSettings, GameStats } from './types';
import Home from './components/Home';
import Game from './components/Game';
import Results from './components/Results';
import Study from './components/Study';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);

  const [settings, setSettings] = useState<GameSettings>({
    mode: 'SQUARES',
    min: 2,
    max: 20,
    min2: 2,   // Default second range start
    max2: 10,  // Default second range end
    duration: 120,
    smartMode: true
  });

  const [lastStats, setLastStats] = useState<GameStats | null>(null);

  const handleGameFinish = (stats: GameStats) => {
    setLastStats(stats);
    setCurrentView(AppView.RESULTS);
  };

  const renderView = () => {
    switch (currentView) {
      case AppView.HOME:
        return (
          <Home 
            settings={settings} 
            setSettings={setSettings} 
            changeView={setCurrentView} 
          />
        );
      case AppView.GAME:
        return (
          <Game 
            settings={settings} 
            onFinish={handleGameFinish} 
            onExit={() => setCurrentView(AppView.HOME)}
          />
        );
      case AppView.RESULTS:
        return lastStats ? (
          <Results 
            stats={lastStats} 
            onRestart={() => setCurrentView(AppView.GAME)} 
            onHome={() => setCurrentView(AppView.HOME)} 
          />
        ) : (
          <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />
        );
      case AppView.STUDY:
        return (
          <Study 
            settings={settings}
            onBack={() => setCurrentView(AppView.HOME)}
          />
        );
      default:
        return <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />;
    }
  };

  return (
    <div className="antialiased min-h-screen">
      {renderView()}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { X, ArrowRight, Zap, Repeat, Flame } from 'lucide-react';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');

  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [streak, setStreak] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);
  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current); };
  }, [settings]);

  const getWeightedRandom = (min: number, max: number) => {
    const candidates: { val: number; weight: number }[] = [];
    const weights = weightsRef.current;
    for (let i = min; i <= max; i++) {
        const w = weights[i] !== undefined ? weights[i] : getInitialWeight(i);
        candidates.push({ val: i, weight: w }); 
    }
    let totalWeight = 0;
    for (const item of candidates) totalWeight += item.weight;
    let random = Math.random() * totalWeight;
    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) return item.val;
    }
    return candidates[candidates.length - 1]?.val || min;
  };

  const generateQuestion = useCallback(() => {
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }
    questionsSinceRetryRef.current++;

    let val1, val2, answer;
    const getRandom = (min: number, max: number) => {
        if (settings.smartMode) return getWeightedRandom(min, max);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    switch (settings.mode) {
        case 'SQUARES':
            val1 = getRandom(settings.min, settings.max);
            return { mode: 'SQUARES', val1, answer: val1 * val1, isRetry: false } as Question;
        case 'ADDITION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            return { mode: 'ADDITION', val1, val2, answer: val1 + val2, isRetry: false } as Question;
        case 'SUBTRACTION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            return { mode: 'SUBTRACTION', val1, val2, answer: val1 - val2, isRetry: false } as Question;
        case 'MULTIPLICATION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            if (settings.smartMode && weightsRef.current[val1] > 1.2 && Math.random() > 0.7) val2 = getRandom(settings.min2, settings.max2);
            return { mode: 'MULTIPLICATION', val1, val2, answer: val1 * val2, isRetry: false } as Question;
        case 'DIVISION':
            val2 = getRandom(settings.min2, settings.max2);
            answer = getRandom(settings.min, settings.max);
            val1 = val2 * answer;
            return { mode: 'DIVISION', val1, val2, answer, isRetry: false } as Question;
        default: return { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
    }
  }, [settings]);

  useEffect(() => {
    setCurrentQuestion(generateQuestion());
    questionStartTimeRef.current = Date.now();
    setStartTime(Date.now());
  }, []); 

  useEffect(() => {
    if (timeLeft <= 0) { handleFinish(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft]);

  const handleFinish = () => {
    if (settings.smartMode) saveWeights(settings.mode, weightsRef.current);
    onFinish({ totalQuestions: history.length, correct: correctCount, score, history, startTime, endTime: Date.now(), problematicKeys: [] });
  };

  const updateWeights = (q: Question, isCorrect: boolean, timeTaken: number) => {
      if (!settings.smartMode) return;
      const calcNewWeight = (currentW: number) => {
          let newW = currentW;
          if (!isCorrect) newW += 2.0;
          else {
              if (timeTaken > 5000) newW += 1.0;
              else if (timeTaken > 3000) newW += 0.2;
              else if (timeTaken < 1500) newW = Math.max(0.5, newW - 0.2);
          }
          return Math.min(newW, 10);
      };
      if (q.mode === 'SQUARES') {
          weightsRef.current[q.val1] = calcNewWeight(weightsRef.current[q.val1] || 1);
      } else if (q.mode === 'DIVISION') {
          if (q.val2) weightsRef.current[q.val2] = calcNewWeight(weightsRef.current[q.val2] || 1);
          weightsRef.current[q.answer] = calcNewWeight(weightsRef.current[q.answer] || 1);
      } else if (q.val2) {
          weightsRef.current[q.val1] = calcNewWeight(weightsRef.current[q.val1] || 1);
          weightsRef.current[q.val2] = calcNewWeight(weightsRef.current[q.val2] || 1);
      }
  };

  const handleAnswer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentQuestion) return;
    const cleanInput = inputValue.replace('−', '-');
    const userVal = parseInt(cleanInput);
    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    setHistory(prev => [...prev, { question: currentQuestion, userAnswer: isNaN(userVal) ? 0 : userVal, isCorrect, timeTaken }]);
    updateWeights(currentQuestion, isCorrect, timeTaken);

    if (isCorrect) {
      setScore(prev => prev + 1); setCorrectCount(prev => prev + 1); setStreak(prev => prev + 1);
      setFlash('green');
    } else {
      setStreak(0);
      if (settings.smartMode) retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      setFlash('red');
    }
    setTimeout(() => setFlash('none'), 300);

    setInputValue('');
    let nextQ = generateQuestion();
    let attempts = 0;
    while (attempts < 5 && !nextQ.isRetry) {
        if (nextQ.val1 === currentQuestion.val1 && nextQ.val2 === currentQuestion.val2) { /* retry */ } else { break; }
        nextQ = generateQuestion(); attempts++;
    }
    setCurrentQuestion(nextQ);
    questionStartTimeRef.current = Date.now();
  };

  // Keep focus logic - refined to ignore button clicks
  useEffect(() => {
    const handleBlur = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        // If clicking a button (like exit) or inside a button, do not force focus back immediately
        if (target.tagName === 'BUTTON' || target.closest('button')) {
            return;
        }
        inputRef.current?.focus(); 
    };
    document.addEventListener('click', handleBlur);
    return () => document.removeEventListener('click', handleBlur);
  }, []);

  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  const bgTransition = flash === 'green' ? 'bg-emerald-500/10' : flash === 'red' ? 'bg-red-500/10' : 'bg-transparent';

  return (
    <div className={`flex flex-col items-center justify-center min-h-screen relative overflow-hidden transition-colors duration-300 ${bgTransition}`}>

      {/* Progress Bar */}
      <div className="absolute top-0 left-0 w-full h-1.5 bg-white/5 z-20">
        <div 
          className="h-full bg-indigo-500 shadow-[0_0_15px_#6366f1] transition-all duration-1000 ease-linear"
          style={{ width: `${(timeLeft / settings.duration) * 100}%` }}
        />
      </div>

      <div className="absolute top-6 right-6 font-mono text-2xl font-bold text-white/30 tracking-wider z-20">
        {timeLeft}s
      </div>

      {/* Added z-50 to ensure button is clickable over other layers */}
      <div className="absolute top-6 left-6 flex gap-4 items-center z-50">
        <button onClick={onExit} className="p-3 bg-white/5 hover:bg-white/10 rounded-full transition-colors text-white/50 hover:text-white backdrop-blur-sm group">
          <X className="w-5 h-5 group-active:scale-90 transition-transform" />
        </button>
        {settings.smartMode && (
            <div className="flex items-center gap-2 px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full backdrop-blur-md text-indigo-300 text-xs font-bold animate-pulse pointer-events-none">
                <Zap className="w-3 h-3 fill-current" />
                SMART AI ACTIVE
            </div>
        )}
      </div>

      {streak > 2 && (
          <div className="absolute top-24 right-6 animate-in slide-in-from-right-10 fade-in duration-500 z-10">
              <div className="flex items-center gap-2 text-orange-400 font-bold drop-shadow-[0_0_10px_rgba(251,146,60,0.5)]">
                  <Flame className="w-6 h-6 fill-current animate-bounce" />
                  <span className="text-2xl italic">{streak}</span>
              </div>
          </div>
      )}

      <div className="w-full max-w-4xl text-center px-4 z-10">

        {/* Retry Indicator */}
        <div className="h-8 mb-6 flex items-center justify-center">
            {currentQuestion?.isRetry && (
                <div className="flex items-center gap-2 text-amber-300 text-xs font-bold bg-amber-500/10 border border-amber-500/20 px-4 py-1.5 rounded-full animate-in zoom-in duration-300 backdrop-blur-md">
                    <Repeat className="w-3 h-3" />
                    REVIEWING MISTAKE
                </div>
            )}
        </div>

        {/* Question */}
        <div className="mb-10 scale-100 md:scale-110 transition-transform duration-300">
            <h2 className="text-[5rem] md:text-[8rem] leading-none font-black text-white tracking-tighter flex items-center justify-center gap-2 drop-shadow-2xl">
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    <span className="bg-clip-text text-transparent bg-gradient-to-b from-white to-slate-400">
                        {currentQuestion.val1}
                    </span>
                    <span className="text-indigo-500 text-[4rem] md:text-[5rem] align-top -mt-8 opacity-80 font-medium">2</span>
                  </>
              ) : (
                  <>
                    <span className="bg-clip-text text-transparent bg-gradient-to-b from-white to-slate-400">{currentQuestion?.val1}</span>
                    <span className="text-indigo-500 text-[4rem] md:text-[6rem] mx-2 opacity-80">{getOperator()}</span>
                    <span className="bg-clip-text text-transparent bg-gradient-to-b from-white to-slate-400">{currentQuestion?.val2}</span>
                  </>
              )}
            </h2>
        </div>

        {/* Input */}
        <form onSubmit={handleAnswer} className="w-full flex justify-center relative">
          <input
            ref={inputRef}
            type="number"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            className="w-full max-w-md bg-transparent border-none text-center text-[5rem] font-bold text-white focus:outline-none placeholder-white/5 py-2 font-mono drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]"
            placeholder=""
            autoFocus
          />
          {/* Subtle cursor line animation if empty */}
          {!inputValue && (
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-32 h-1 bg-white/20 rounded-full animate-pulse" />
          )}
        </form>

        <div className="mt-20 flex justify-center opacity-80">
             <div className="px-8 py-3 glass rounded-full flex items-center gap-4">
                <span className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Session Score</span>
                <span className="text-3xl font-bold text-indigo-400 font-mono drop-shadow-[0_0_10px_rgba(99,102,241,0.5)]">{score}</span>
             </div>
        </div>
      </div>

      <div className="absolute bottom-8 text-white/20 text-xs font-medium tracking-widest flex items-center gap-2 animate-pulse uppercase z-10">
         Press Enter <ArrowRight className="w-3 h-3" />
      </div>
    </div>
  );
};

export default Game;

export enum AppView {
  HOME = 'HOME',
  GAME = 'GAME',
  RESULTS = 'RESULTS',
  STUDY = 'STUDY'
}

export type GameMode = 'SQUARES' | 'MULTIPLICATION' | 'ADDITION' | 'SUBTRACTION' | 'DIVISION';

export interface GameSettings {
  mode: GameMode;
  min: number;
  max: number;
  min2: number; // For multiplication second operand
  max2: number; // For multiplication second operand
  duration: number; // in seconds
  smartMode: boolean;
  kidMode: boolean;
}

export interface Question {
  mode: GameMode;
  val1: number;
  val2?: number; // undefined for SQUARES
  answer: number;
  isRetry?: boolean; // Indicates this is a spaced repetition question
}

export interface AnswerRecord {
  question: Question;
  userAnswer: number;
  isCorrect: boolean;
  timeTaken: number; // ms
}

export interface GameStats {
  totalQuestions: number;
  correct: number;
  score: number;
  history: AnswerRecord[];
  startTime: number;
  endTime: number;
  problematicKeys: string[];
}

import React, { useState } from 'react';
import { AppView, GameSettings, GameStats } from './types';
import Home from './components/Home';
import Game from './components/Game';
import Results from './components/Results';
import Study from './components/Study';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);

  const [settings, setSettings] = useState<GameSettings>({
    mode: 'ADDITION', // Default to Addition for easier entry
    min: 1,
    max: 20,
    min2: 1,   
    max2: 10,  
    duration: 60,
    smartMode: true,
    kidMode: false
  });

  const [lastStats, setLastStats] = useState<GameStats | null>(null);

  const handleGameFinish = (stats: GameStats) => {
    setLastStats(stats);
    setCurrentView(AppView.RESULTS);
  };

  const renderView = () => {
    switch (currentView) {
      case AppView.HOME:
        return (
          <Home 
            settings={settings} 
            setSettings={setSettings} 
            changeView={setCurrentView} 
          />
        );
      case AppView.GAME:
        return (
          <Game 
            settings={settings} 
            onFinish={handleGameFinish} 
            onExit={() => setCurrentView(AppView.HOME)}
          />
        );
      case AppView.RESULTS:
        return lastStats ? (
          <Results 
            stats={lastStats} 
            settings={settings}
            onRestart={() => setCurrentView(AppView.GAME)} 
            onHome={() => setCurrentView(AppView.HOME)} 
          />
        ) : (
          <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />
        );
      case AppView.STUDY:
        return (
          <Study 
            settings={settings}
            onBack={() => setCurrentView(AppView.HOME)}
          />
        );
      default:
        return <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />;
    }
  };

  return (
    <div className={`antialiased min-h-screen transition-colors duration-500 ${settings.kidMode ? 'bg-sky-100' : ''}`}>
      {renderView()}
    </div>
  );
};

export default App;

