export default Home;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { X, ArrowRight, Zap, Repeat, Flame, Star, Trophy } from 'lucide-react';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');

  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [streak, setStreak] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);
  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);

  const isKid = settings.kidMode;

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current); };
  }, [settings]);

  const getWeightedRandom = (min: number, max: number) => {
    const candidates: { val: number; weight: number }[] = [];
    const weights = weightsRef.current;
    for (let i = min; i <= max; i++) {
        const w = weights[i] !== undefined ? weights[i] : getInitialWeight(i);
        candidates.push({ val: i, weight: w }); 
    }
    let totalWeight = 0;
    for (const item of candidates) totalWeight += item.weight;
    let random = Math.random() * totalWeight;
    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) return item.val;
    }
    return candidates[candidates.length - 1]?.val || min;
  };

  const generateQuestion = useCallback(() => {
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }
    questionsSinceRetryRef.current++;

    let val1, val2, answer;
    const getRandom = (min: number, max: number) => {
        if (settings.smartMode) return getWeightedRandom(min, max);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    switch (settings.mode) {
        case 'SQUARES':
            val1 = getRandom(settings.min, settings.max);
            return { mode: 'SQUARES', val1, answer: val1 * val1, isRetry: false } as Question;
        case 'ADDITION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            return { mode: 'ADDITION', val1, val2, answer: val1 + val2, isRetry: false } as Question;
        case 'SUBTRACTION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            // Ensure positive result for subtraction in kid mode or general good practice for basic drills
            if (settings.kidMode && val2 > val1) {
                [val1, val2] = [val2, val1];
            }
            return { mode: 'SUBTRACTION', val1, val2, answer: val1 - val2, isRetry: false } as Question;
        case 'MULTIPLICATION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            if (settings.smartMode && weightsRef.current[val1] > 1.2 && Math.random() > 0.7) val2 = getRandom(settings.min2, settings.max2);
            return { mode: 'MULTIPLICATION', val1, val2, answer: val1 * val2, isRetry: false } as Question;
        case 'DIVISION':
            val2 = getRandom(settings.min2, settings.max2);
            answer = getRandom(settings.min, settings.max);
            val1 = val2 * answer;
            return { mode: 'DIVISION', val1, val2, answer, isRetry: false } as Question;
        default: return { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
    }
  }, [settings]);

  useEffect(() => {
    setCurrentQuestion(generateQuestion());
    questionStartTimeRef.current = Date.now();
    setStartTime(Date.now());
  }, []); 

  useEffect(() => {
    if (timeLeft <= 0) { handleFinish(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft]);

  const handleFinish = () => {
    if (settings.smartMode) saveWeights(settings.mode, weightsRef.current);
    onFinish({ totalQuestions: history.length, correct: correctCount, score, history, startTime, endTime: Date.now(), problematicKeys: [] });
  };

  const updateWeights = (q: Question, isCorrect: boolean, timeTaken: number) => {
      if (!settings.smartMode) return;
      const calcNewWeight = (currentW: number) => {
          let newW = currentW;
          if (!isCorrect) newW += 2.0;
          else {
              if (timeTaken > 5000) newW += 1.0;
              else if (timeTaken > 3000) newW += 0.2;
              else if (timeTaken < 1500) newW = Math.max(0.5, newW - 0.2);
          }
          return Math.min(newW, 10);
      };
      if (q.mode === 'SQUARES') {
          weightsRef.current[q.val1] = calcNewWeight(weightsRef.current[q.val1] || 1);
      } else if (q.mode === 'DIVISION') {
          if (q.val2) weightsRef.current[q.val2] = calcNewWeight(weightsRef.current[q.val2] || 1);
          weightsRef.current[q.answer] = calcNewWeight(weightsRef.current[q.answer] || 1);
      } else if (q.val2) {
          weightsRef.current[q.val1] = calcNewWeight(weightsRef.current[q.val1] || 1);
          weightsRef.current[q.val2] = calcNewWeight(weightsRef.current[q.val2] || 1);
      }
  };

  const handleAnswer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentQuestion) return;
    const cleanInput = inputValue.replace('−', '-');
    const userVal = parseInt(cleanInput);
    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    setHistory(prev => [...prev, { question: currentQuestion, userAnswer: isNaN(userVal) ? 0 : userVal, isCorrect, timeTaken }]);
    updateWeights(currentQuestion, isCorrect, timeTaken);

    if (isCorrect) {
      setScore(prev => prev + 1); setCorrectCount(prev => prev + 1); setStreak(prev => prev + 1);
      setFlash('green');
    } else {
      setStreak(0);
      if (settings.smartMode) retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      setFlash('red');
    }
    setTimeout(() => setFlash('none'), 300);

    setInputValue('');
    let nextQ = generateQuestion();
    let attempts = 0;
    while (attempts < 5 && !nextQ.isRetry) {
        if (nextQ.val1 === currentQuestion.val1 && nextQ.val2 === currentQuestion.val2) { /* retry */ } else { break; }
        nextQ = generateQuestion(); attempts++;
    }
    setCurrentQuestion(nextQ);
    questionStartTimeRef.current = Date.now();
  };

  // Keep focus logic - refined to ignore button clicks
  useEffect(() => {
    const handleBlur = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        // If clicking a button (like exit) or inside a button, do not force focus back immediately
        if (target.tagName === 'BUTTON' || target.closest('button')) {
            return;
        }
        inputRef.current?.focus(); 
    };
    document.addEventListener('click', handleBlur);
    return () => document.removeEventListener('click', handleBlur);
  }, []);

  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  const bgTransition = flash === 'green' 
    ? (isKid ? 'bg-green-100' : 'bg-emerald-500/10') 
    : flash === 'red' 
        ? (isKid ? 'bg-red-100' : 'bg-red-500/10') 
        : (isKid ? 'bg-sky-50' : 'bg-transparent');

  return (
    <div className={`flex flex-col items-center justify-center min-h-screen relative overflow-hidden transition-colors duration-300 ${bgTransition}`}>

      {/* Progress Bar */}
      <div className={`absolute top-0 left-0 w-full h-2 z-20 ${isKid ? 'bg-white' : 'bg-white/5'}`}>
        <div 
          className={`h-full transition-all duration-1000 ease-linear ${isKid ? 'bg-yellow-400' : 'bg-indigo-500 shadow-[0_0_15px_#6366f1]'}`}
          style={{ width: `${(timeLeft / settings.duration) * 100}%` }}
        />
      </div>

      <div className={`absolute top-6 right-6 font-mono text-2xl font-bold tracking-wider z-20 ${isKid ? 'text-sky-400' : 'text-white/30'}`}>
        {timeLeft}s
      </div>

      {/* Added z-50 to ensure button is clickable over other layers */}
      <div className="absolute top-6 left-6 flex gap-4 items-center z-50">
        <button 
            onClick={onExit} 
            className={`p-3 rounded-full transition-colors backdrop-blur-sm group ${isKid ? 'bg-white text-sky-400 shadow-md hover:bg-sky-50' : 'bg-white/5 hover:bg-white/10 text-white/50 hover:text-white'}`}
        >
          <X className="w-6 h-6 group-active:scale-90 transition-transform" />
        </button>
        {settings.smartMode && (
            <div className={`flex items-center gap-2 px-4 py-1.5 rounded-full backdrop-blur-md text-xs font-bold animate-pulse pointer-events-none ${isKid ? 'bg-white/50 border border-sky-200 text-sky-500' : 'bg-indigo-500/10 border border-indigo-500/20 text-indigo-300'}`}>
                <Zap className="w-3 h-3 fill-current" />
                {isKid ? "Smart Helper ON" : "SMART AI ACTIVE"}
            </div>
        )}
      </div>

      {streak > 2 && (
          <div className="absolute top-24 right-6 animate-in slide-in-from-right-10 fade-in duration-500 z-10">
              <div className={`flex items-center gap-2 font-bold ${isKid ? 'text-orange-400 drop-shadow-none' : 'text-orange-400 drop-shadow-[0_0_10px_rgba(251,146,60,0.5)]'}`}>
                  {isKid ? <Star className="w-8 h-8 fill-yellow-400 text-yellow-500 animate-spin-slow" /> : <Flame className="w-6 h-6 fill-current animate-bounce" />}
                  <span className="text-3xl italic">{streak}</span>
              </div>
          </div>
      )}

      <div className="w-full max-w-4xl text-center px-4 z-10">

        {/* Retry Indicator */}
        <div className="h-8 mb-6 flex items-center justify-center">
            {currentQuestion?.isRetry && (
                <div className={`flex items-center gap-2 text-xs font-bold px-4 py-1.5 rounded-full animate-in zoom-in duration-300 backdrop-blur-md ${isKid ? 'bg-orange-100 text-orange-500 border border-orange-200' : 'text-amber-300 bg-amber-500/10 border border-amber-500/20'}`}>
                    <Repeat className="w-3 h-3" />
                    {isKid ? "Let's try that one again!" : "REVIEWING MISTAKE"}
                </div>
            )}
        </div>

        {/* Question */}
        <div className="mb-10 scale-100 md:scale-110 transition-transform duration-300">
            <h2 className={`text-[5rem] md:text-[8rem] leading-none font-black tracking-tighter flex items-center justify-center gap-2 ${isKid ? 'text-sky-600 drop-shadow-sm' : 'text-white drop-shadow-2xl'}`}>
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    <span className={isKid ? "text-sky-600" : "bg-clip-text text-transparent bg-gradient-to-b from-white to-slate-400"}>
                        {currentQuestion.val1}
                    </span>
                    <span className={`${isKid ? 'text-yellow-400' : 'text-indigo-500'} text-[4rem] md:text-[5rem] align-top -mt-8 opacity-80 font-medium`}>2</span>
                  </>
              ) : (
                  <>
                    <span className={isKid ? "text-sky-600" : "bg-clip-text text-transparent bg-gradient-to-b from-white to-slate-400"}>{currentQuestion?.val1}</span>
                    <span className={`${isKid ? 'text-yellow-400' : 'text-indigo-500'} text-[4rem] md:text-[6rem] mx-2 opacity-80`}>{getOperator()}</span>
                    <span className={isKid ? "text-sky-600" : "bg-clip-text text-transparent bg-gradient-to-b from-white to-slate-400"}>{currentQuestion?.val2}</span>
                  </>
              )}
            </h2>
        </div>

        {/* Input */}
        <form onSubmit={handleAnswer} className="w-full flex justify-center relative">
          <input
            ref={inputRef}
            type="number"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            className={`w-full max-w-md bg-transparent border-none text-center text-[5rem] font-bold focus:outline-none py-2 font-mono ${isKid ? 'text-sky-800 placeholder-sky-200' : 'text-white placeholder-white/5 drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]'}`}
            placeholder={isKid ? "?" : ""}
            autoFocus
          />
          {/* Subtle cursor line animation if empty */}
          {!inputValue && !isKid && (
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-32 h-1 bg-white/20 rounded-full animate-pulse" />
          )}
        </form>

        <div className="mt-20 flex justify-center opacity-80">
             <div className={`px-8 py-3 rounded-full flex items-center gap-4 ${isKid ? 'bg-white shadow-lg border border-sky-100' : 'glass'}`}>
                {isKid ? <Trophy className="w-6 h-6 text-yellow-500" /> : <span className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Session Score</span>}
                <span className={`text-3xl font-bold font-mono ${isKid ? 'text-sky-600' : 'text-indigo-400 drop-shadow-[0_0_10px_rgba(99,102,241,0.5)]'}`}>{score}</span>
             </div>
        </div>
      </div>

      <div className={`absolute bottom-8 text-xs font-medium tracking-widest flex items-center gap-2 animate-pulse uppercase z-10 ${isKid ? 'text-sky-400' : 'text-white/20'}`}>
         {isKid ? "Type & Press Enter" : "Press Enter"} <ArrowRight className="w-3 h-3" />
      </div>
    </div>
  );
};

export default Game;

import React, { useState } from 'react';
import { GameStats, AnswerRecord, GameSettings } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { RefreshCcw, Home as HomeIcon, Lightbulb, XCircle, Brain, Target, Zap, Star, Trophy, Smile } from 'lucide-react';
import { getMentalMathTip } from '../services/geminiService';

interface ResultsProps {
  stats: GameStats;
  settings: GameSettings;
  onRestart: () => void;
  onHome: () => void;
}

const Results: React.FC<ResultsProps> = ({ stats, settings, onRestart, onHome }) => {
  const incorrect = stats.totalQuestions - stats.correct;
  const accuracy = stats.totalQuestions > 0 ? Math.round((stats.correct / stats.totalQuestions) * 100) : 0;

  const chartData = [
    { name: 'Correct', value: stats.correct },
    { name: 'Incorrect', value: incorrect },
  ];

  const isKid = settings.kidMode;
  const COLORS = isKid ? ['#facc15', '#f87171'] : ['#6366f1', '#ef4444']; 
  const [loadingTip, setLoadingTip] = useState<string | null>(null);
  const [tips, setTips] = useState<Record<string, string>>({});

  const getQuestionKey = (q: AnswerRecord['question']) => {
      if (q.mode === 'SQUARES') return `sq_${q.val1}`;
      return `${q.mode}_${q.val1}_${q.val2}`;
  };

  const handleGetTip = async (record: AnswerRecord) => {
    const key = getQuestionKey(record.question);
    if (tips[key]) return; 
    setLoadingTip(key);
    const tip = await getMentalMathTip(record.question);
    setTips(prev => ({ ...prev, [key]: tip }));
    setLoadingTip(null);
  };

  const mistakes = stats.history.filter(h => !h.isCorrect);
  const formatQuestion = (q: AnswerRecord['question']) => {
      let op = '';
      switch (q.mode) {
          case 'MULTIPLICATION': op = '×'; break;
          case 'ADDITION': op = '+'; break;
          case 'SUBTRACTION': op = '−'; break;
          case 'DIVISION': op = '÷'; break;
          default: op = '';
      }
      if (q.mode === 'SQUARES') return <span>{q.val1}<sup className={isKid ? "text-sky-500" : "text-indigo-400"}>2</sup></span>;
      return <span>{q.val1} <span className={isKid ? "text-sky-500" : "text-indigo-400"}>{op}</span> {q.val2}</span>;
  };

  // Styles
  const containerClass = isKid ? "min-h-screen p-6 md:p-12 overflow-y-auto bg-sky-50 text-slate-800" : "min-h-screen p-6 md:p-12 overflow-y-auto text-slate-100";
  const headerTextClass = isKid ? "text-4xl font-black text-sky-600" : "text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400";
  const cardClass = isKid ? "bg-white rounded-3xl p-8 shadow-xl border border-sky-100" : "glass rounded-3xl p-8 flex flex-col justify-between relative overflow-hidden group";

  return (
    <div className={containerClass}>
      <div className="max-w-5xl mx-auto space-y-8">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="text-center md:text-left">
            <h2 className={headerTextClass}>{isKid ? "Great Job! 🎉" : "Performance Report"}</h2>
            <p className={isKid ? "text-sky-400 font-medium mt-1" : "text-slate-400 mt-1"}>
                {isKid ? "You are a math superstar!" : `Session completed on ${new Date(stats.endTime).toLocaleTimeString()}`}
            </p>
          </div>
          <div className="flex gap-4">
            <button onClick={onHome} className={`p-4 rounded-2xl transition-colors ${isKid ? "bg-white text-sky-400 shadow-md hover:bg-sky-50" : "glass text-slate-300 hover:bg-white/10 hover:text-white"}`}>
              <HomeIcon className="w-6 h-6" />
            </button>
            <button onClick={onRestart} className={`px-8 py-4 rounded-2xl font-bold transition-all shadow-lg flex items-center gap-3 ${isKid ? "bg-yellow-400 text-white hover:bg-yellow-300 hover:shadow-yellow-300/50" : "bg-indigo-600 hover:bg-indigo-500 hover:shadow-indigo-500/30"}`}>
              <RefreshCcw className="w-5 h-5" />
              {isKid ? "Play Again" : "Play Again"}
            </button>
          </div>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

          {/* Main Score */}
          <div className={cardClass}>
             {isKid && <div className="absolute top-0 right-0 p-32 bg-yellow-100 rounded-full blur-[60px] opacity-50" />}
             {!isKid && <div className="absolute top-0 right-0 p-32 bg-indigo-600/10 rounded-full blur-[60px] group-hover:bg-indigo-600/20 transition-all" />}

             <div className={`flex items-center gap-3 mb-4 ${isKid ? 'text-yellow-500' : 'text-indigo-400'}`}>
                 {isKid ? <Trophy className="w-6 h-6" /> : <Target className="w-5 h-5" />}
                 <span className="text-xs font-bold uppercase tracking-widest">{isKid ? "Total Stars" : "Score"}</span>
             </div>
             <div className={`text-7xl font-black tracking-tighter mb-2 ${isKid ? 'text-sky-600' : 'text-white'}`}>{stats.score}</div>
             <div className={isKid ? "text-sky-400 text-sm font-bold" : "text-slate-400 text-sm"}>{isKid ? "Amazing work!" : "Total points accumulated"}</div>
          </div>

          {/* Accuracy & Speed */}
          <div className={isKid ? "bg-white rounded-3xl p-8 shadow-xl border border-sky-100" : "glass rounded-3xl p-8 flex flex-col justify-between relative overflow-hidden"}>
             <div className={`flex items-center gap-3 mb-6 ${isKid ? 'text-green-400' : 'text-emerald-400'}`}>
                 {isKid ? <Smile className="w-6 h-6" /> : <Zap className="w-5 h-5" />}
                 <span className="text-xs font-bold uppercase tracking-widest">{isKid ? "Accuracy" : "Efficiency"}</span>
             </div>
             <div className="grid grid-cols-2 gap-8">
                <div>
                   <div className={`text-4xl font-bold mb-1 ${isKid ? 'text-sky-600' : 'text-white'}`}>{accuracy}%</div>
                   <div className={`text-xs uppercase tracking-wider font-bold ${isKid ? 'text-sky-300' : 'text-slate-500'}`}>Correct</div>
                </div>
                <div>
                   <div className={`text-4xl font-bold mb-1 ${isKid ? 'text-sky-600' : 'text-white'}`}>{Math.round((stats.totalQuestions / ((stats.endTime - stats.startTime)/60000)) || 0)}</div>
                   <div className={`text-xs uppercase tracking-wider font-bold ${isKid ? 'text-sky-300' : 'text-slate-500'}`}>{isKid ? "Speed" : "Ans/Min"}</div>
                </div>
             </div>
          </div>

          {/* Chart */}
          <div className={isKid ? "bg-white rounded-3xl p-6 flex items-center justify-center relative shadow-xl border border-sky-100" : "glass rounded-3xl p-6 flex items-center justify-center relative"}>
            {stats.totalQuestions > 0 ? (
                <div className="w-full h-48">
                    <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie
                        data={chartData}
                        cx="50%"
                        cy="50%"
                        innerRadius={50}
                        outerRadius={70}
                        paddingAngle={8}
                        dataKey="value"
                        stroke="none"
                        cornerRadius={6}
                        >
                        {chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} className="drop-shadow-lg" />
                        ))}
                        </Pie>
                        <Tooltip 
                            contentStyle={isKid ? { backgroundColor: '#fff', borderColor: '#e0f2fe', borderRadius: '12px', color: '#0369a1' } : { backgroundColor: 'rgba(15, 23, 42, 0.9)', borderColor: 'rgba(255,255,255,0.1)', borderRadius: '12px' }} 
                            itemStyle={isKid ? { color: '#0369a1', fontWeight: 'bold' } : { color: '#fff' }} 
                        />
                    </PieChart>
                    </ResponsiveContainer>
                </div>
            ) : <span className="text-slate-500">No data</span>}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="text-center">
                    <div className={`text-2xl font-bold ${isKid ? 'text-sky-600' : 'text-white'}`}>{stats.totalQuestions}</div>
                    <div className={`text-[10px] uppercase tracking-widest ${isKid ? 'text-sky-400' : 'text-slate-500'}`}>Total</div>
                </div>
             </div>
          </div>
        </div>

        {/* AI Analysis Section */}
        <div className={`${isKid ? 'bg-sky-100/50 border-sky-200' : 'glass-panel border-indigo-500'} rounded-3xl p-8 border-l-4`}>
             <div className="flex items-center gap-3 mb-4">
                 <Brain className={`w-6 h-6 ${isKid ? 'text-sky-500' : 'text-indigo-400'}`} />
                 <h3 className={`text-xl font-bold ${isKid ? 'text-sky-700' : 'text-white'}`}>AI Coach</h3>
             </div>
             <p className={`leading-relaxed max-w-3xl ${isKid ? 'text-sky-800 font-medium' : 'text-slate-300'}`}>
                 {incorrect === 0 && stats.totalQuestions > 5 
                    ? (isKid ? "Wow! Zero mistakes! You are a genius! Try going a little faster next time to get even more stars!" : "Flawless performance! Your mental calculation speed is impressive. Consider expanding the number range to challenge your cognitive limits further.")
                    : incorrect > 3 
                        ? (isKid ? "Good try! I saw a few tricky ones. Let's look at the list below to learn the right answers." : "You're building good momentum, but consistency on the edge cases needs work. The AI has identified your weak spots and will prioritize them in the next session.")
                        : (isKid ? "You did really well! Keep practicing and you will be a math wizard soon!" : "Solid session. You handled most standard operations well, but slowed down on the larger transitions. Keep practicing to build muscle memory.")
                 }
             </p>
        </div>

        {/* Mistakes List */}
        {mistakes.length > 0 && (
            <div className="space-y-6 animate-in slide-in-from-bottom-8 fade-in duration-700">
                <h3 className={`text-2xl font-bold ${isKid ? 'text-sky-700' : 'text-white'}`}>{isKid ? "Let's Review" : "Learning Opportunities"}</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {mistakes.map((record, idx) => {
                        const key = getQuestionKey(record.question);
                        const tip = tips[key];
                        return (
                            <div key={idx} className={`${isKid ? 'bg-white border border-red-100' : 'glass-panel hover:bg-white/5'} p-6 rounded-2xl group transition-colors`}>
                                <div className="flex justify-between items-start mb-4">
                                    <div>
                                        <div className={`text-2xl font-mono font-bold mb-2 ${isKid ? 'text-slate-700' : 'text-white'}`}>
                                            {formatQuestion(record.question)}
                                        </div>
                                        <div className={`flex items-center gap-2 text-sm font-mono px-2 py-1 rounded-md w-fit ${isKid ? 'text-red-500 bg-red-50' : 'text-red-400 bg-red-500/10'}`}>
                                            <XCircle className="w-3 h-3" />
                                            {record.userAnswer}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className={`text-xs uppercase tracking-wider mb-1 ${isKid ? 'text-sky-400' : 'text-slate-500'}`}>Correct</div>
                                        <div className={`text-xl font-bold font-mono ${isKid ? 'text-green-500' : 'text-emerald-400'}`}>{record.question.answer}</div>
                                    </div>
                                </div>

                                {tip ? (
                                    <div className={`mt-4 pt-4 border-t text-sm leading-relaxed animate-in fade-in ${isKid ? 'border-sky-100 text-sky-700' : 'border-white/5 text-indigo-200'}`}>
                                        <span className={`font-bold block text-xs uppercase mb-1 ${isKid ? 'text-sky-400' : 'text-indigo-400'}`}>{isKid ? "Secret Trick" : "Memorization Tip"}</span>
                                        {tip}
                                    </div>
                                ) : (
                                    <button 
                                        onClick={() => handleGetTip(record)}
                                        disabled={loadingTip === key}
                                        className={`w-full mt-2 py-2 text-xs font-bold uppercase tracking-widest rounded-lg transition-all flex items-center justify-center gap-2 ${isKid ? 'text-sky-500 hover:bg-sky-50' : 'text-indigo-400 hover:text-white hover:bg-indigo-600/20'}`}
                                    >
                                        <Lightbulb className="w-3 h-3" />
                                        {loadingTip === key ? 'Thinking...' : (isKid ? 'Help Me Learn!' : 'Get AI Trick')}
                                    </button>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

