                            className={isKid 
                                ? "flex-1 bg-white hover:bg-sky-50 text-sky-400 hover:text-sky-600 font-bold py-3 rounded-xl transition-colors text-sm flex items-center justify-center gap-2 border-2 border-sky-100"
