                                        <div className={`flex items-center gap-2 text-sm font-mono px-2 py-1 rounded-md w-fit ${isKid ? 'text-red-500 bg-red-50' : 'text-red-400 bg-red-500/10'}`}>
                                            <XCircle className="w-3 h-3" />
