import React, { useState, useEffect, useRef } from 'react';

interface DraggableNumpadProps {
  onInput: (digit: string) => void;
  onEnter: () => void;
  onDelete: () => void;
  isKid: boolean;
}

const DraggableNumpad: React.FC<DraggableNumpadProps> = ({ onInput, onEnter, onDelete, isKid }) => {
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const numpadRef = useRef<HTMLDivElement>(null);
  const [isInitialized, setIsInitialized] = useState(false);

  useEffect(() => {
    const width = Math.min(320, window.innerWidth - 32);
    const x = (window.innerWidth - width) / 2;
    const y = window.innerHeight - 450; 
    setPosition({ 
        x: Math.max(16, x), 
        y: Math.max(16, y) 
    });
    setIsInitialized(true);
  }, []);

  const handlePointerDown = (e: React.PointerEvent) => {
    setIsDragging(true);
    if (numpadRef.current) {
        const rect = numpadRef.current.getBoundingClientRect();
        dragStartRef.current = {
            x: e.clientX - rect.left,
            y: e.clientY - rect.top
        };
    }
    e.currentTarget.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    const newX = e.clientX - dragStartRef.current.x;
    const newY = e.clientY - dragStartRef.current.y;
    const maxX = window.innerWidth - (numpadRef.current?.offsetWidth || 320);
    const maxY = window.innerHeight - (numpadRef.current?.offsetHeight || 400);
    setPosition({ 
        x: Math.max(0, Math.min(newX, maxX)), 
        y: Math.max(0, Math.min(newY, maxY)) 
    });
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    setIsDragging(false);
    e.currentTarget.releasePointerCapture(e.pointerId);
  };

  if (!isInitialized) return null;

  // Material 3 Styling
  const containerClass = isKid 
    ? "fixed z-50 w-[300px] bg-white border-2 border-indigo-100 shadow-2xl rounded-[32px] overflow-hidden select-none touch-none"
    : "fixed z-50 w-[300px] bg-[#1e1e1e] shadow-2xl rounded-[32px] overflow-hidden select-none touch-none ring-1 ring-white/10";

  const btnBase = "w-16 h-16 rounded-full flex items-center justify-center text-2xl font-medium transition-transform active:scale-95 select-none outline-none";

  // Theme Colors
  const numColor = isKid ? "bg-indigo-50 text-indigo-900 hover:bg-indigo-100" : "bg-[#2d2f31] text-white hover:bg-[#3d3f41]";
  const opColor = isKid ? "bg-orange-100 text-orange-900 hover:bg-orange-200" : "bg-[#422d2d] text-[#ffb4ab] hover:bg-[#533939]";
  const enterColor = isKid ? "bg-indigo-500 text-white hover:bg-indigo-600" : "bg-[#a8c7fa] text-[#042e85] hover:bg-[#8ab4f8]";

  return (
    <div 
        ref={numpadRef}
        className={containerClass}
        style={{ left: position.x, top: position.y }}
    >
        {/* Drag Handle Area */}
        <div 
            className={`h-10 flex items-center justify-center cursor-grab active:cursor-grabbing ${isKid ? 'bg-white' : 'bg-[#1e1e1e]'}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
        >
            <div className={`w-12 h-1.5 rounded-full ${isKid ? 'bg-indigo-100' : 'bg-[#444746]'}`} />
        </div>

        <div className={`px-4 pb-6 grid grid-cols-3 gap-3 ${isKid ? 'bg-white' : 'bg-[#1e1e1e]'}`}>
            {[7, 8, 9, 4, 5, 6, 1, 2, 3].map(num => (
                <button 
                    key={num} 
                    className={`${btnBase} ${numColor}`}
                    onClick={() => onInput(num.toString())}
                >
                    {num}
                </button>
            ))}

            <button className={`${btnBase} ${opColor}`} onClick={onDelete}>
                <span className="material-symbol">backspace</span>
            </button>

            <button className={`${btnBase} ${numColor}`} onClick={() => onInput('0')}>
                0
            </button>

            <button className={`${btnBase} ${enterColor}`} onClick={onEnter}>
                <span className="material-symbol">check</span>
            </button>
        </div>
    </div>
  );
};

export default DraggableNumpad;

import React, { useState } from 'react';
import { AppView, GameSettings, GameMode } from '../types';
import { clearWeights } from '../services/storageService';

interface HomeProps {
  settings: GameSettings;
  setSettings: (settings: GameSettings) => void;
  changeView: (view: AppView) => void;
}

const Home: React.FC<HomeProps> = ({ settings, setSettings, changeView }) => {
  const [localSettings, setLocalSettings] = useState<GameSettings>(settings);
  const [cleared, setCleared] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setLocalSettings(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (parseInt(value) || 0)
    }));
  };

  const handleModeChange = (mode: GameMode) => {
    setLocalSettings(prev => ({ ...prev, mode }));
  };

  const toggleKidMode = () => {
      setLocalSettings(prev => {
          const newKidMode = !prev.kidMode;
          if (newKidMode) {
              return {
                  ...prev,
                  kidMode: true,
                  mode: 'ADDITION',
                  min: 1, max: 20,
                  min2: 1, max2: 10,
                  duration: 120,
                  smartMode: true
              };
          }
          return { ...prev, kidMode: false };
      });
  };

  const handleStart = () => {
    let { min, max, min2, max2, duration, smartMode, mode, kidMode } = localSettings;
    if (min > max) [min, max] = [max, min];
    if (min2 > max2) [min2, max2] = [max2, min2];
    const finalSettings = { min, max, min2, max2, duration, smartMode, mode, kidMode };
    setSettings(finalSettings);
    changeView(AppView.GAME);
  };

  const handleClearProgress = () => {
      clearWeights();
      setCleared(true);
      setTimeout(() => setCleared(false), 2000);
  };

  const modes: { id: GameMode; label: string; icon: string }[] = [
      { id: 'SQUARES', label: 'Squares', icon: 'square_foot' },
      { id: 'ADDITION', label: 'Add', icon: 'add' },
      { id: 'SUBTRACTION', label: 'Subtract', icon: 'remove' },
      { id: 'MULTIPLICATION', label: 'Multiply', icon: 'close' },
      { id: 'DIVISION', label: 'Divide', icon: 'percent' },
  ];

  const isKid = localSettings.kidMode;

  // Material 3 Styles
  const pageBg = isKid ? "bg-[#fef7ff]" : "bg-[#121212]";
  const surfaceCard = isKid ? "bg-[#f3edf7] text-[#1d1b20]" : "bg-[#1e1e1e] text-[#e3e3e3]";
  const primaryText = isKid ? "text-[#6750a4]" : "text-[#d0bcff]";
  const primaryFill = isKid ? "bg-[#6750a4] text-white hover:bg-[#6750a4]/90" : "bg-[#d0bcff] text-[#381e72] hover:bg-[#d0bcff]/90";
  const secondaryFill = isKid ? "bg-[#e8def8] text-[#1d1b20]" : "bg-[#333537] text-[#c4c7c5]";
  const inputFill = isKid ? "bg-[#ffffff] border-b border-[#6750a4]" : "bg-[#2d2f31] border-b border-[#938f99] text-white";

  return (
    <div className={`min-h-screen flex flex-col items-center justify-center p-4 transition-colors duration-500 ${pageBg}`}>

      <div className="w-full max-w-md space-y-6">

        {/* Header */}
        <div className="text-center space-y-2 mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl mb-2 bg-gradient-to-br from-indigo-500 to-purple-600 shadow-lg">
             <span className="material-symbol text-white text-4xl">calculate</span>
          </div>
          <h1 className={`text-3xl font-bold tracking-tight ${isKid ? 'text-[#1d1b20]' : 'text-white'}`}>
            SquareMaster
          </h1>
          <p className={isKid ? "text-[#49454f]" : "text-[#c4c7c5]"}>
            {isKid ? "Math is fun! Let's play!" : "AI-Powered Mental Arithmetic"}
          </p>
        </div>

        {/* Main Card */}
        <div className={`rounded-[32px] p-6 shadow-sm ${surfaceCard}`}>

            {/* Mode Switch (Segmented Button) */}
            <div className={`flex overflow-x-auto gap-2 pb-4 mb-2 no-scrollbar`}>
                {modes.map((m) => {
                    const active = localSettings.mode === m.id;
                    const activeClass = isKid ? "bg-[#e8def8] text-[#1d1b20]" : "bg-[#4f378b] text-[#eaddff]";
                    const inactiveClass = isKid ? "hover:bg-white/50 text-[#49454f]" : "hover:bg-white/5 text-[#c4c7c5]";

                    return (
                        <button
                            key={m.id}
                            onClick={() => handleModeChange(m.id)}
                            className={`flex flex-col items-center justify-center min-w-[72px] h-[72px] rounded-2xl transition-colors ${active ? activeClass : inactiveClass}`}
                        >
                            <span className="material-symbol text-2xl mb-1">{m.icon}</span>
                            <span className="text-[10px] font-medium tracking-wide">{m.label}</span>
                        </button>
                    );
                })}
            </div>

            <div className="space-y-6">
                {/* Inputs Row */}
                <div className="grid grid-cols-2 gap-4">
                    <div className={`rounded-t-lg px-4 py-2 ${inputFill}`}>
                        <label className={`block text-xs ${isKid ? 'text-[#6750a4]' : 'text-[#d0bcff]'}`}>Min Value</label>
                        <input
                            type="number"
                            name="min"
                            value={localSettings.min}
                            onChange={handleChange}
                            className="w-full bg-transparent text-xl font-medium outline-none p-0 border-none focus:ring-0"
                        />
                    </div>
                    <div className={`rounded-t-lg px-4 py-2 ${inputFill}`}>
                        <label className={`block text-xs ${isKid ? 'text-[#6750a4]' : 'text-[#d0bcff]'}`}>Max Value</label>
                        <input
                            type="number"
                            name="max"
                            value={localSettings.max}
