                >
                    Reference
                </button>
                <button 
                    onClick={() => setActiveTab('chat')}
                    className={`flex-1 py-2 rounded-full text-sm font-medium transition-colors ${activeTab === 'chat' ? (isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]') : ''}`}
