                <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3">
                    {squares.map(s => (
                        <div key={s.base} className={`p-4 rounded-2xl flex flex-col items-center justify-center ${primaryContainer}`}>
