  const [totalGames, setTotalGames] = useState(0);

  const isKid = settings.kidMode;

  useEffect(() => {
    setTotalGames(getTotalGamesPlayed());
  }, []);

  useEffect(() => {
    setWeights(loadWeights(activeMode));
