          return { ...prev, kidMode: false };
      });
  };

  const handleStart = () => {
    let { min, max, min2, max2, duration, smartMode, mode, kidMode } = localSettings;
    if (min > max) [min, max] = [max, min];
    if (min2 > max2) [min2, max2] = [max2, min2];
