import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';
import DraggableNumpad from './DraggableNumpad';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);
  const isKid = settings.kidMode;

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.log("Error enabling fullscreen:", err);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current); };
  }, [settings]);

  const getWeightedRandom = (min: number, max: number) => {
    const candidates: { val: number; weight: number }[] = [];
    const weights = weightsRef.current;
    for (let i = min; i <= max; i++) {
        const w = weights[i] !== undefined ? weights[i] : getInitialWeight(i);
        candidates.push({ val: i, weight: w }); 
    }
    let totalWeight = 0;
    for (const item of candidates) totalWeight += item.weight;
    let random = Math.random() * totalWeight;
    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) return item.val;
    }
    return candidates[candidates.length - 1]?.val || min;
  };

  const generateQuestion = useCallback(() => {
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }
    questionsSinceRetryRef.current++;

    let val1, val2, answer;
    const getRandom = (min: number, max: number) => {
        if (settings.smartMode) return getWeightedRandom(min, max);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    switch (settings.mode) {
        case 'SQUARES':
            val1 = getRandom(settings.min, settings.max);
            return { mode: 'SQUARES', val1, answer: val1 * val1, isRetry: false } as Question;
        case 'ADDITION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            return { mode: 'ADDITION', val1, val2, answer: val1 + val2, isRetry: false } as Question;
        case 'SUBTRACTION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            if (settings.kidMode && val2 > val1) [val1, val2] = [val2, val1];
            return { mode: 'SUBTRACTION', val1, val2, answer: val1 - val2, isRetry: false } as Question;
        case 'MULTIPLICATION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            return { mode: 'MULTIPLICATION', val1, val2, answer: val1 * val2, isRetry: false } as Question;
        case 'DIVISION':
            val2 = getRandom(settings.min2, settings.max2);
            answer = getRandom(settings.min, settings.max);
            val1 = val2 * answer;
            return { mode: 'DIVISION', val1, val2, answer, isRetry: false } as Question;
        default: return { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
    }
  }, [settings]);

  useEffect(() => { setCurrentQuestion(generateQuestion()); }, []); 

  const handleStartGame = () => {
    setIsPlaying(true);
    setStartTime(Date.now());
    questionStartTimeRef.current = Date.now();
  };

  useEffect(() => {
    if (!isPlaying) return;
    if (timeLeft <= 0) { handleFinish(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isPlaying]);

  const handleFinish = () => {
    if (settings.smartMode) saveWeights(settings.mode, weightsRef.current);
    onFinish({ totalQuestions: history.length, correct: correctCount, score, history, startTime, endTime: Date.now(), problematicKeys: [] });
  };

  const processAnswer = useCallback(() => {
    if (!currentQuestion || !isPlaying) return;
    const cleanInput = inputValue.replace('−', '-');
    const userVal = parseInt(cleanInput);
    if (inputValue.trim() === '') return;

    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    setHistory(prev => [...prev, { question: currentQuestion, userAnswer: isNaN(userVal) ? 0 : userVal, isCorrect, timeTaken }]);

    if (isCorrect) {
      setScore(prev => prev + 1); setCorrectCount(prev => prev + 1);
      setFlash('green');
    } else {
      if (settings.smartMode) retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      setFlash('red');
    }
    setTimeout(() => setFlash('none'), 300);

    setInputValue('');
    let nextQ = generateQuestion();
    // Avoid immediate repeat
    let attempts = 0;
    while (attempts < 5 && !nextQ.isRetry) {
        if (nextQ.val1 === currentQuestion.val1 && nextQ.val2 === currentQuestion.val2) { /* retry */ } else { break; }
        nextQ = generateQuestion(); attempts++;
    }
    setCurrentQuestion(nextQ);
    questionStartTimeRef.current = Date.now();
  }, [currentQuestion, inputValue, generateQuestion, settings.smartMode, isPlaying]);

  const handleFormSubmit = (e: React.FormEvent) => { e.preventDefault(); processAnswer(); };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') { onExit(); return; }
        if (!isPlaying) return;
        if (e.key >= '0' && e.key <= '9') setInputValue(p => p.length > 6 ? p : p + e.key);
        else if (e.key === 'Backspace') setInputValue(p => p.slice(0, -1));
        else if (e.key === 'Enter') processAnswer();
        else if (e.key === '-' || e.key === '−') setInputValue(p => p.includes('-') ? p : '-' + p);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [processAnswer, onExit, isPlaying]);

  const handleNumpadInput = (d: string) => { if(isPlaying) setInputValue(p => p.length > 6 ? p : p + d); };
  const handleNumpadDelete = () => { if(isPlaying) setInputValue(p => p.slice(0, -1)); };
  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  const bgClass = isKid 
    ? (flash === 'green' ? 'bg-green-100' : flash === 'red' ? 'bg-red-100' : 'bg-[#fef7ff]') 
    : (flash === 'green' ? 'bg-[#0f1f12]' : flash === 'red' ? 'bg-[#2b1212]' : 'bg-[#121212]');

  const textClass = isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]';

  return (
    <div className={`flex flex-col min-h-screen relative overflow-hidden transition-colors duration-300 ${bgClass} ${textClass}`}>

      <DraggableNumpad 
          onInput={handleNumpadInput}
          onDelete={handleNumpadDelete}
          onEnter={processAnswer}
          isKid={isKid}
      />

      {/* Start Overlay */}
      {!isPlaying && (
          <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in">
              <div className={`p-8 rounded-[32px] max-w-sm w-full text-center shadow-2xl ${isKid ? 'bg-[#f3edf7]' : 'bg-[#1e1e1e] border border-white/10'}`}>
                  <div className={`w-16 h-16 mx-auto mb-4 rounded-full flex items-center justify-center ${isKid ? 'bg-indigo-100 text-indigo-700' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                      <span className="material-symbol text-3xl">drag_pan</span>
                  </div>
                  <h2 className={`text-2xl font-bold mb-2 ${isKid ? 'text-[#1d1b20]' : 'text-white'}`}>Position the Numpad</h2>
                  <p className={`mb-8 text-sm ${isKid ? 'text-[#49454f]' : 'text-[#c4c7c5]'}`}>
                      Drag the keypad to a comfortable spot before you begin.
                  </p>
                  <button
                      onClick={handleStartGame}
                      className={`w-full h-14 rounded-full font-medium text-lg flex items-center justify-center gap-2 transition-transform active:scale-95 ${isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]'}`}
                  >
                      <span className="material-symbol">play_arrow</span>
                      Start
                  </button>
              </div>
          </div>
      )}

      {/* Header */}
      <div className="flex justify-between items-center p-6 z-20">
          <div className="flex gap-3">
            <button onClick={onExit} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">close</span>
            </button>
            <button onClick={toggleFullScreen} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">{isFullscreen ? 'close_fullscreen' : 'fullscreen'}</span>
            </button>
          </div>

          <div className={`px-5 py-2 rounded-full flex items-center gap-2 ${isKid ? 'bg-indigo-50 text-indigo-900' : 'bg-[#333537] text-white'}`}>
              <span className="material-symbol text-sm">trophy</span>
              <span className="font-bold">{score}</span>
          </div>

          <div className={`w-12 h-12 rounded-full flex items-center justify-center font-mono font-bold border-2 ${timeLeft < 10 ? 'border-red-500 text-red-500' : (isKid ? 'border-indigo-200 text-indigo-900' : 'border-gray-600 text-white')}`}>
              {timeLeft}
          </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center pt-10 px-4">

        {/* Retry Label */}
        <div className="h-8 mb-4">
            {currentQuestion?.isRetry && (
                <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wider ${isKid ? 'bg-orange-100 text-orange-800' : 'bg-[#410e0b] text-[#f2b8b5]'}`}>
                    <span className="material-symbol text-sm">refresh</span>
                    Review
                </span>
            )}
        </div>

        {/* Question Display */}
        <div className="text-center mb-12 animate-slide-up">
            <h2 className="text-[5rem] md:text-[7rem] font-bold leading-none tracking-tight flex items-center justify-center gap-4">
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    <span>{currentQuestion.val1}</span>
                    <span className={`text-[3rem] md:text-[4rem] self-start mt-2 ${isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}`}>2</span>
                  </>
              ) : (
                  <>
                    <span>{currentQuestion?.val1}</span>
                    <span className={isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}>{getOperator()}</span>
                    <span>{currentQuestion?.val2}</span>
                  </>
              )}
            </h2>
        </div>

        {/* Answer Input */}
        <form onSubmit={handleFormSubmit} className="w-full flex justify-center">
            <div className={`relative min-w-[200px] border-b-4 ${isKid ? 'border-indigo-200' : 'border-gray-700'}`}>
                <input
                    type="text"
                    readOnly
                    value={inputValue}
                    className="w-full bg-transparent text-center text-[4rem] font-medium focus:outline-none py-2 font-mono"
                    placeholder="?"
                />
            </div>
        </form>

        {/* Smart Mode Indicator */}
        {settings.smartMode && (
            <div className={`mt-12 flex items-center gap-2 text-xs font-medium px-4 py-2 rounded-full ${isKid ? 'bg-white/50 text-gray-500' : 'bg-white/5 text-gray-400'}`}>
                <span className="material-symbol text-sm filled">bolt</span>
                AI Adaptive
            </div>
        )}
      </div>
    </div>
  );
};

export default Game;

export enum AppView {
  HOME = 'HOME',
  GAME = 'GAME',
  RESULTS = 'RESULTS',
  STUDY = 'STUDY',
  STATS = 'STATS'
}

export type GameMode = 'SQUARES' | 'MULTIPLICATION' | 'ADDITION' | 'SUBTRACTION' | 'DIVISION';

export interface GameSettings {
  mode: GameMode;
  min: number;
  max: number;
  min2: number; // For multiplication second operand
  max2: number; // For multiplication second operand
  duration: number; // in seconds
  smartMode: boolean;
  kidMode: boolean;
  optionsMode?: boolean; // Enable multiple choice options
}

export interface Question {
  mode: GameMode;
  val1: number;
  val2?: number; // undefined for SQUARES
  answer: number;
  isRetry?: boolean; // Indicates this is a spaced repetition question
}

export interface AnswerRecord {
  question: Question;
  userAnswer: number;
  isCorrect: boolean;
  timeTaken: number; // ms
}

export interface GameStats {
  totalQuestions: number;
  correct: number;
  score: number;
  history: AnswerRecord[];
  startTime: number;
  endTime: number;
  problematicKeys: string[];
}

import React, { useState, useEffect } from 'react';
import { AppView, GameSettings, GameMode } from '../types';
import { clearWeights } from '../services/storageService';

interface HomeProps {
  settings: GameSettings;
  setSettings: (settings: GameSettings) => void;
  changeView: (view: AppView) => void;
}

const Home: React.FC<HomeProps> = ({ settings, setSettings, changeView }) => {
  const [localSettings, setLocalSettings] = useState<GameSettings>(settings);
  const [cleared, setCleared] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.log("Error enabling fullscreen:", err);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setLocalSettings(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (parseInt(value) || 0)
    }));
  };

  const handleModeChange = (mode: GameMode) => {
    setLocalSettings(prev => ({ ...prev, mode }));
  };

  const toggleKidMode = () => {
      setLocalSettings(prev => {
          const newKidMode = !prev.kidMode;
          if (newKidMode) {
              return {
                  ...prev,
                  kidMode: true,
                  mode: 'MULTIPLICATION', // Default to multiplication as requested context often implies it
                  min: 1, max: 10,
                  min2: 1, max2: 10,
                  duration: 120,
                  smartMode: true,
                  optionsMode: false
              };
          }
          return { ...prev, kidMode: false, optionsMode: false };
      });
  };

  const handleStart = () => {
    let { min, max, min2, max2, duration, smartMode, mode, kidMode, optionsMode } = localSettings;
    if (min > max) [min, max] = [max, min];
    if (min2 > max2) [min2, max2] = [max2, min2];
    const finalSettings = { min, max, min2, max2, duration, smartMode, mode, kidMode, optionsMode };
    setSettings(finalSettings);
    changeView(AppView.GAME);
  };

  const handleClearProgress = () => {
      clearWeights();
      setCleared(true);
      setTimeout(() => setCleared(false), 2000);
  };

  const modes: { id: GameMode; label: string; icon: string }[] = [
      { id: 'SQUARES', label: 'Squares', icon: 'square_foot' },
      { id: 'ADDITION', label: 'Add', icon: 'add' },
      { id: 'SUBTRACTION', label: 'Subtract', icon: 'remove' },
      { id: 'MULTIPLICATION', label: 'Multiply', icon: 'close' },
      { id: 'DIVISION', label: 'Divide', icon: 'percent' },
  ];

  const isKid = localSettings.kidMode;
  const showOptionsToggle = isKid && localSettings.mode === 'MULTIPLICATION';

  // Material 3 Styles
  const pageBg = isKid ? "bg-[#fef7ff]" : "bg-[#121212]";
  const surfaceCard = isKid ? "bg-[#f3edf7] text-[#1d1b20]" : "bg-[#1e1e1e] text-[#e3e3e3]";
  const primaryText = isKid ? "text-[#6750a4]" : "text-[#d0bcff]";
  const primaryFill = isKid ? "bg-[#6750a4] text-white hover:bg-[#6750a4]/90" : "bg-[#d0bcff] text-[#381e72] hover:bg-[#d0bcff]/90";
  const secondaryFill = isKid ? "bg-[#e8def8] text-[#1d1b20]" : "bg-[#333537] text-[#c4c7c5]";
  const inputFill = isKid ? "bg-[#ffffff] border-b border-[#6750a4]" : "bg-[#2d2f31] border-b border-[#938f99] text-white";

  return (
    <div className={`min-h-screen flex flex-col items-center justify-center p-4 transition-colors duration-500 relative ${pageBg}`}>

      {/* Full Screen Toggle */}
      <button 
        onClick={toggleFullScreen}
        className={`absolute top-4 right-4 w-12 h-12 rounded-full flex items-center justify-center transition-colors z-10 ${isKid ? 'bg-white text-[#1d1b20] hover:bg-gray-50 shadow-sm' : 'bg-[#2d2f31] text-[#e3e3e3] hover:bg-[#3d3f41]'}`}
        title="Toggle Full Screen"
      >
        <span className="material-symbol">{isFullscreen ? 'close_fullscreen' : 'fullscreen'}</span>
      </button>

      <div className="w-full max-w-md space-y-6">

        {/* Header */}
        <div className="text-center space-y-2 mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl mb-2 bg-gradient-to-br from-indigo-500 to-purple-600 shadow-lg">
             <span className="material-symbol text-white text-4xl">calculate</span>
          </div>
          <h1 className={`text-3xl font-bold tracking-tight ${isKid ? 'text-[#1d1b20]' : 'text-white'}`}>
            SquareMaster
          </h1>
          <p className={isKid ? "text-[#49454f]" : "text-[#c4c7c5]"}>
            {isKid ? "Math is fun! Let's play!" : "AI-Powered Mental Arithmetic"}
          </p>
        </div>

        {/* Main Card */}
        <div className={`rounded-[32px] p-6 shadow-sm ${surfaceCard}`}>

            {/* Mode Switch (Segmented Button) */}
            <div className={`flex overflow-x-auto gap-2 pb-4 mb-2 no-scrollbar`}>
                {modes.map((m) => {
                    const active = localSettings.mode === m.id;
                    const activeClass = isKid ? "bg-[#e8def8] text-[#1d1b20]" : "bg-[#4f378b] text-[#eaddff]";
                    const inactiveClass = isKid ? "hover:bg-white/50 text-[#49454f]" : "hover:bg-white/5 text-[#c4c7c5]";

                    return (
                        <button
                            key={m.id}
                            onClick={() => handleModeChange(m.id)}
                            className={`flex flex-col items-center justify-center min-w-[72px] h-[72px] rounded-2xl transition-colors ${active ? activeClass : inactiveClass}`}
                        >
                            <span className="material-symbol text-2xl mb-1">{m.icon}</span>
                            <span className="text-[10px] font-medium tracking-wide">{m.label}</span>
                        </button>
                    );
                })}
            </div>

            <div className="space-y-6">
                {/* Inputs Row */}
                <div className="grid grid-cols-2 gap-4">
                    <div className={`rounded-t-lg px-4 py-2 ${inputFill}`}>
                        <label className={`block text-xs ${isKid ? 'text-[#6750a4]' : 'text-[#d0bcff]'}`}>Min Value</label>
                        <input
                            type="number"
                            name="min"
                            value={localSettings.min}
                            onChange={handleChange}
                            className="w-full bg-transparent text-xl font-medium outline-none p-0 border-none focus:ring-0"
                        />
                    </div>
                    <div className={`rounded-t-lg px-4 py-2 ${inputFill}`}>
                        <label className={`block text-xs ${isKid ? 'text-[#6750a4]' : 'text-[#d0bcff]'}`}>Max Value</label>
                        <input
                            type="number"
                            name="max"
                            value={localSettings.max}
                            onChange={handleChange}
                            className="w-full bg-transparent text-xl font-medium outline-none p-0 border-none focus:ring-0"
                        />
                    </div>
                </div>

                {localSettings.mode !== 'SQUARES' && (
                    <div className="grid grid-cols-2 gap-4 animate-fade-in">
                        <div className={`rounded-t-lg px-4 py-2 ${inputFill}`}>
                            <label className={`block text-xs ${isKid ? 'text-[#6750a4]' : 'text-[#d0bcff]'}`}>Operand 2 Min</label>
                            <input
                                type="number"
                                name="min2"
                                value={localSettings.min2}
                                onChange={handleChange}
                                className="w-full bg-transparent text-xl font-medium outline-none p-0 border-none focus:ring-0"
                            />
                        </div>
                        <div className={`rounded-t-lg px-4 py-2 ${inputFill}`}>
                            <label className={`block text-xs ${isKid ? 'text-[#6750a4]' : 'text-[#d0bcff]'}`}>Operand 2 Max</label>
                            <input
                                type="number"
                                name="max2"
                                value={localSettings.max2}
                                onChange={handleChange}
                                className="w-full bg-transparent text-xl font-medium outline-none p-0 border-none focus:ring-0"
                            />
                        </div>
                    </div>
                )}

                {/* Duration Slider style */}
                <div className="pt-2">
                    <div className="flex justify-between mb-2">
                        <label className={`text-sm font-medium ${isKid ? 'text-[#49454f]' : 'text-[#c4c7c5]'}`}>Duration</label>
                        <span className={`text-sm font-bold ${primaryText}`}>{localSettings.duration}s</span>
                    </div>
                    <input 
                        type="range" 
                        min="10" 
                        max="300" 
                        step="10"
                        name="duration"
                        value={localSettings.duration}
                        onChange={handleChange}
                        className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                    />
                </div>

                {/* Smart Mode Toggle */}
                <div className="flex justify-between items-center py-2">
                    <div className="flex items-center gap-3">
                         <div className={`p-2 rounded-full ${isKid ? 'bg-[#e8def8] text-[#1d1b20]' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                            <span className="material-symbol">smart_toy</span>
                         </div>
                         <div className="flex flex-col">
                             <span className={`text-sm font-medium ${isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]'}`}>Smart AI</span>
                             <span className="text-xs text-gray-500">Adaptive difficulty</span>
                         </div>
                    </div>
                    <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" name="smartMode" checked={localSettings.smartMode} onChange={handleChange} className="sr-only peer" />
                        <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-indigo-600"></div>
                    </label>
                </div>

                {/* Kid Mode Toggle */}
                <div className="flex justify-between items-center py-2">
                    <div className="flex items-center gap-3">
                         <div className={`p-2 rounded-full ${isKid ? 'bg-[#e8def8] text-[#1d1b20]' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                            <span className="material-symbol">face</span>
                         </div>
                         <div className="flex flex-col">
                             <span className={`text-sm font-medium ${isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]'}`}>Kid Mode</span>
                             <span className="text-xs text-gray-500">Fun theme & simpler UI</span>
                         </div>
                    </div>
                    <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" checked={localSettings.kidMode} onChange={toggleKidMode} className="sr-only peer" />
                        <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-indigo-600"></div>
                    </label>
                </div>

                {/* Multiple Choice Toggle (Conditional) */}
                {showOptionsToggle && (
                   <div className="flex justify-between items-center py-2 animate-fade-in">
                       <div className="flex items-center gap-3">
                            <div className={`p-2 rounded-full ${isKid ? 'bg-[#e8def8] text-[#1d1b20]' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                               <span className="material-symbol">list_alt</span>
                            </div>
                            <div className="flex flex-col">
                                <span className={`text-sm font-medium ${isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]'}`}>Multiple Choice</span>
                                <span className="text-xs text-gray-500">Pick from options</span>
                            </div>
                       </div>
                       <label className="relative inline-flex items-center cursor-pointer">
                           <input type="checkbox" name="optionsMode" checked={!!localSettings.optionsMode} onChange={handleChange} className="sr-only peer" />
                           <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-indigo-600"></div>
                       </label>
                   </div>
                )}
            </div>

            {/* FAB / CTA */}
            <button
                onClick={handleStart}
                className={`mt-8 w-full h-14 rounded-full font-medium text-lg shadow-md transition-transform active:scale-[0.98] flex items-center justify-center gap-2 ${primaryFill}`}
            >
                <span className="material-symbol">play_arrow</span>
                Start Session
            </button>
        </div>

        {/* Secondary Actions */}
        <div className="flex gap-4">
             <button
                onClick={() => changeView(AppView.STUDY)}
                className={`flex-1 h-12 rounded-full text-sm font-medium flex items-center justify-center gap-2 transition-colors ${secondaryFill}`}
            >
                <span className="material-symbol text-lg">school</span>
                Study
            </button>
            <button
                onClick={() => changeView(AppView.STATS)}
                className={`flex-1 h-12 rounded-full text-sm font-medium flex items-center justify-center gap-2 transition-colors ${secondaryFill}`}
            >
                <span className="material-symbol text-lg">monitoring</span>
                Stats
            </button>
        </div>

        <button
            onClick={handleClearProgress}
            className={`w-full mt-2 h-10 rounded-full text-xs font-medium flex items-center justify-center gap-2 transition-colors opacity-50 hover:opacity-100 ${isKid ? 'text-red-900' : 'text-[#f2b8b5]'}`}
        >
            <span className="material-symbol text-sm">{cleared ? 'check' : 'delete'}</span>
            {cleared ? 'Reset!' : 'Clear Data'}
        </button>

      </div>
    </div>
  );
};

export default Home;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';
import DraggableNumpad from './DraggableNumpad';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [options, setOptions] = useState<number[]>([]);

  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);
  const isKid = settings.kidMode;
  const isOptionsMode = settings.kidMode && settings.optionsMode && settings.mode === 'MULTIPLICATION';

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.log("Error enabling fullscreen:", err);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current); };
  }, [settings]);

  const getWeightedRandom = (min: number, max: number) => {
    const candidates: { val: number; weight: number }[] = [];
    const weights = weightsRef.current;
    for (let i = min; i <= max; i++) {
        const w = weights[i] !== undefined ? weights[i] : getInitialWeight(i);
        candidates.push({ val: i, weight: w }); 
    }
    let totalWeight = 0;
    for (const item of candidates) totalWeight += item.weight;
    let random = Math.random() * totalWeight;
    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) return item.val;
    }
    return candidates[candidates.length - 1]?.val || min;
  };

  const generateOptions = (answer: number) => {
      const opts = new Set<number>();
      opts.add(answer);

      let safetyCounter = 0;
      while (opts.size < 4 && safetyCounter < 50) {
          safetyCounter++;
          const offset = Math.floor(Math.random() * 8) + 1; // 1-8 deviation
          const sign = Math.random() > 0.5 ? 1 : -1;
          const val = answer + (offset * sign);

          if (val > 0 && val !== answer) {
              opts.add(val);
          }
      }

      // Fallback if loop failed to find unique positive numbers
      if (opts.size < 4) {
          if (answer > 10) opts.add(answer - 10);
          opts.add(answer + 10);
          opts.add(answer + 1);
      }

      return Array.from(opts).slice(0, 4).sort(() => Math.random() - 0.5);
  };

  const generateQuestion = useCallback(() => {
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }
    questionsSinceRetryRef.current++;

    let val1, val2, answer;
    const getRandom = (min: number, max: number) => {
        if (settings.smartMode) return getWeightedRandom(min, max);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    let q: Question;
    switch (settings.mode) {
        case 'SQUARES':
            val1 = getRandom(settings.min, settings.max);
            q = { mode: 'SQUARES', val1, answer: val1 * val1, isRetry: false } as Question;
            break;
        case 'ADDITION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            q = { mode: 'ADDITION', val1, val2, answer: val1 + val2, isRetry: false } as Question;
            break;
        case 'SUBTRACTION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            if (settings.kidMode && val2 > val1) [val1, val2] = [val2, val1];
            q = { mode: 'SUBTRACTION', val1, val2, answer: val1 - val2, isRetry: false } as Question;
            break;
        case 'MULTIPLICATION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            q = { mode: 'MULTIPLICATION', val1, val2, answer: val1 * val2, isRetry: false } as Question;
            break;
        case 'DIVISION':
            val2 = getRandom(settings.min2, settings.max2);
            answer = getRandom(settings.min, settings.max);
            val1 = val2 * answer;
            q = { mode: 'DIVISION', val1, val2, answer, isRetry: false } as Question;
            break;
        default: q = { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
    }
    return q;
  }, [settings]);

  useEffect(() => { 
      const q = generateQuestion();
      setCurrentQuestion(q);
      if (isOptionsMode) setOptions(generateOptions(q.answer));
  }, []); 

  const handleStartGame = () => {
    setIsPlaying(true);
    setStartTime(Date.now());
    questionStartTimeRef.current = Date.now();
  };

  useEffect(() => {
    if (!isPlaying) return;
    if (timeLeft <= 0) { handleFinish(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isPlaying]);

  const handleFinish = () => {
    if (settings.smartMode) saveWeights(settings.mode, weightsRef.current);
    onFinish({ totalQuestions: history.length, correct: correctCount, score, history, startTime, endTime: Date.now(), problematicKeys: [] });
  };

  const processAnswer = useCallback((overrideValue?: number) => {
    if (!currentQuestion || !isPlaying) return;

    let userVal: number;
    if (overrideValue !== undefined) {
        userVal = overrideValue;
    } else {
        const cleanInput = inputValue.replace('−', '-');
        userVal = parseInt(cleanInput);
        if (inputValue.trim() === '') return;
    }

    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    setHistory(prev => [...prev, { question: currentQuestion, userAnswer: isNaN(userVal) ? 0 : userVal, isCorrect, timeTaken }]);

    if (isCorrect) {
      setScore(prev => prev + 1); setCorrectCount(prev => prev + 1);
      setFlash('green');
    } else {
      if (settings.smartMode) retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      setFlash('red');
    }
    setTimeout(() => setFlash('none'), 300);

    setInputValue('');
    let nextQ = generateQuestion();
    // Avoid immediate repeat
    let attempts = 0;
    while (attempts < 5 && !nextQ.isRetry) {
        if (nextQ.val1 === currentQuestion.val1 && nextQ.val2 === currentQuestion.val2) { /* retry */ } else { break; }
        nextQ = generateQuestion(); attempts++;
    }
    setCurrentQuestion(nextQ);
    if (isOptionsMode) setOptions(generateOptions(nextQ.answer));
    questionStartTimeRef.current = Date.now();
  }, [currentQuestion, inputValue, generateQuestion, settings.smartMode, isPlaying, isOptionsMode]);

  const handleFormSubmit = (e: React.FormEvent) => { e.preventDefault(); processAnswer(); };

  useEffect(() => {
    if (isOptionsMode) return; // Disable keyboard typing in options mode for clarity, or let it work? Let's disable to focus on clicks.

    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') { onExit(); return; }
        if (!isPlaying) return;
        if (e.key >= '0' && e.key <= '9') setInputValue(p => p.length > 6 ? p : p + e.key);
        else if (e.key === 'Backspace') setInputValue(p => p.slice(0, -1));
        else if (e.key === 'Enter') processAnswer();
        else if (e.key === '-' || e.key === '−') setInputValue(p => p.includes('-') ? p : '-' + p);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [processAnswer, onExit, isPlaying, isOptionsMode]);

  const handleNumpadInput = (d: string) => { if(isPlaying) setInputValue(p => p.length > 6 ? p : p + d); };
  const handleNumpadDelete = () => { if(isPlaying) setInputValue(p => p.slice(0, -1)); };
  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  const bgClass = isKid 
    ? (flash === 'green' ? 'bg-green-100' : flash === 'red' ? 'bg-red-100' : 'bg-[#fef7ff]') 
    : (flash === 'green' ? 'bg-[#0f1f12]' : flash === 'red' ? 'bg-[#2b1212]' : 'bg-[#121212]');

  const textClass = isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]';

  return (
    <div className={`flex flex-col min-h-screen relative overflow-hidden transition-colors duration-300 ${bgClass} ${textClass}`}>

      {/* Conditionally render Numpad only if NOT in Options Mode */}
      {!isOptionsMode && (
          <DraggableNumpad 
              onInput={handleNumpadInput}
              onDelete={handleNumpadDelete}
              onEnter={() => processAnswer()}
              isKid={isKid}
          />
      )}

      {/* Start Overlay */}
      {!isPlaying && (
          <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in">
              <div className={`p-8 rounded-[32px] max-w-sm w-full text-center shadow-2xl ${isKid ? 'bg-[#f3edf7]' : 'bg-[#1e1e1e] border border-white/10'}`}>
                  <div className={`w-16 h-16 mx-auto mb-4 rounded-full flex items-center justify-center ${isKid ? 'bg-indigo-100 text-indigo-700' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                      <span className="material-symbol text-3xl">{isOptionsMode ? 'touch_app' : 'drag_pan'}</span>
                  </div>
                  <h2 className={`text-2xl font-bold mb-2 ${isKid ? 'text-[#1d1b20]' : 'text-white'}`}>
                      {isOptionsMode ? 'Ready?' : 'Position the Numpad'}
                  </h2>
                  <p className={`mb-8 text-sm ${isKid ? 'text-[#49454f]' : 'text-[#c4c7c5]'}`}>
                      {isOptionsMode ? 'Select the correct answer from the options.' : 'Drag the keypad to a comfortable spot before you begin.'}
                  </p>
                  <button
                      onClick={handleStartGame}
                      className={`w-full h-14 rounded-full font-medium text-lg flex items-center justify-center gap-2 transition-transform active:scale-95 ${isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]'}`}
                  >
                      <span className="material-symbol">play_arrow</span>
                      Start
                  </button>
              </div>
          </div>
      )}

      {/* Header */}
      <div className="flex justify-between items-center p-6 z-20">
          <div className="flex gap-3">
            <button onClick={onExit} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">close</span>
            </button>
            <button onClick={toggleFullScreen} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">{isFullscreen ? 'close_fullscreen' : 'fullscreen'}</span>
            </button>
          </div>

          <div className={`px-5 py-2 rounded-full flex items-center gap-2 ${isKid ? 'bg-indigo-50 text-indigo-900' : 'bg-[#333537] text-white'}`}>
              <span className="material-symbol text-sm">trophy</span>
              <span className="font-bold">{score}</span>
          </div>

          <div className={`w-12 h-12 rounded-full flex items-center justify-center font-mono font-bold border-2 ${timeLeft < 10 ? 'border-red-500 text-red-500' : (isKid ? 'border-indigo-200 text-indigo-900' : 'border-gray-600 text-white')}`}>
              {timeLeft}
          </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center pt-10 px-4">

        {/* Retry Label */}
        <div className="h-8 mb-4">
            {currentQuestion?.isRetry && (
                <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wider ${isKid ? 'bg-orange-100 text-orange-800' : 'bg-[#410e0b] text-[#f2b8b5]'}`}>
                    <span className="material-symbol text-sm">refresh</span>
                    Review
                </span>
            )}
        </div>

        {/* Question Display */}
        <div className="text-center mb-12 animate-slide-up">
            <h2 className="text-[5rem] md:text-[7rem] font-bold leading-none tracking-tight flex items-center justify-center gap-4">
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    <span>{currentQuestion.val1}</span>
                    <span className={`text-[3rem] md:text-[4rem] self-start mt-2 ${isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}`}>2</span>
                  </>
              ) : (
                  <>
                    <span>{currentQuestion?.val1}</span>
                    <span className={isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}>{getOperator()}</span>
                    <span>{currentQuestion?.val2}</span>
                  </>
              )}
            </h2>
        </div>

        {/* Answer Area: Either Text Input or Multiple Choice Buttons */}
        {isOptionsMode ? (
            <div className="w-full max-w-lg grid grid-cols-2 gap-4 animate-fade-in">
                {options.map((opt, idx) => (
                    <button
                        key={idx}
                        onClick={() => processAnswer(opt)}
                        className={`h-24 rounded-2xl text-4xl font-bold transition-transform active:scale-95 shadow-sm ${
                            isKid 
                            ? 'bg-white text-indigo-900 border-2 border-indigo-100 hover:border-indigo-300' 
                            : 'bg-[#1e1e1e] text-[#e3e3e3] border border-white/10 hover:bg-[#2d2f31]'
                        }`}
                    >
                        {opt}
                    </button>
                ))}
            </div>
        ) : (
            <form onSubmit={handleFormSubmit} className="w-full flex justify-center">
                <div className={`relative min-w-[200px] border-b-4 ${isKid ? 'border-indigo-200' : 'border-gray-700'}`}>
                    <input
                        type="text"
                        readOnly
                        value={inputValue}
                        className="w-full bg-transparent text-center text-[4rem] font-medium focus:outline-none py-2 font-mono"
                        placeholder="?"
                    />
                </div>
            </form>
        )}

        {/* Smart Mode Indicator */}
        {settings.smartMode && (
            <div className={`mt-12 flex items-center gap-2 text-xs font-medium px-4 py-2 rounded-full ${isKid ? 'bg-white/50 text-gray-500' : 'bg-white/5 text-gray-400'}`}>
                <span className="material-symbol text-sm filled">bolt</span>
                AI Adaptive
            </div>
        )}
      </div>
    </div>
  );
};

export default Game;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';
import DraggableNumpad from './DraggableNumpad';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [options, setOptions] = useState<number[]>([]);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);

  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);
  const isKid = settings.kidMode;
  const isOptionsMode = settings.kidMode && settings.optionsMode && settings.mode === 'MULTIPLICATION';

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.log("Error enabling fullscreen:", err);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current); };
  }, [settings]);

  const getWeightedRandom = (min: number, max: number) => {
    const candidates: { val: number; weight: number }[] = [];
    const weights = weightsRef.current;
    for (let i = min; i <= max; i++) {
        const w = weights[i] !== undefined ? weights[i] : getInitialWeight(i);
        candidates.push({ val: i, weight: w }); 
    }
    let totalWeight = 0;
    for (const item of candidates) totalWeight += item.weight;
    let random = Math.random() * totalWeight;
    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) return item.val;
    }
    return candidates[candidates.length - 1]?.val || min;
  };

  const generateOptions = (answer: number) => {
      const opts = new Set<number>();
      opts.add(answer);

      let safetyCounter = 0;
      while (opts.size < 4 && safetyCounter < 50) {
          safetyCounter++;
          const offset = Math.floor(Math.random() * 8) + 1; // 1-8 deviation
          const sign = Math.random() > 0.5 ? 1 : -1;
          const val = answer + (offset * sign);

          if (val > 0 && val !== answer) {
