                         </div>
                         <div className="flex flex-col">
                             <span className={`text-sm font-medium ${isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]'}`}>Smart AI</span>
                             <span className="text-xs text-gray-500">Adaptive difficulty</span>
