import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';
import DraggableNumpad from './DraggableNumpad';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [options, setOptions] = useState<number[]>([]);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);

  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);
  const isKid = settings.kidMode;
  const isOptionsMode = !!settings.optionsMode;

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.log("Error enabling fullscreen:", err);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode, isKid);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings, isKid]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current, isKid); };
  }, [settings, isKid]);

  const getWeightedRandom = (min: number, max: number) => {
    const candidates: { val: number; weight: number }[] = [];
    const weights = weightsRef.current;
    for (let i = min; i <= max; i++) {
        const w = weights[i] !== undefined ? weights[i] : getInitialWeight(i);
        candidates.push({ val: i, weight: w }); 
    }
    let totalWeight = 0;
    for (const item of candidates) totalWeight += item.weight;
    let random = Math.random() * totalWeight;
    for (const item of candidates) {
        random -= item.weight;
        if (random <= 0) return item.val;
    }
    return candidates[candidates.length - 1]?.val || min;
  };

  // Improved Smart Options Generation
  const generateOptions = (q: Question) => {
      const { answer, mode, val1, val2 } = q;
      const opts = new Set<number>();
      opts.add(answer);

      const add = (n: number) => {
          if (n > 0 && n !== answer && Number.isInteger(n)) opts.add(n);
      };

      if (mode === 'SQUARES') {
          // Common square mistakes
          add((val1 - 1) ** 2);
          add((val1 + 1) ** 2);
          // Transposition of digits (e.g. 13^2 = 169 vs 196)
          const s = answer.toString();
          if (s.length > 1) {
              const rev = parseInt(s.split('').reverse().join(''));
              if (rev !== answer) add(rev);
          }
          add(answer + 10);
          add(answer - 10);
      } else if (mode === 'MULTIPLICATION' && val2 !== undefined) {
          // Off by one operand group
          add(val1 * (val2 + 1));
          add(val1 * (val2 - 1));
          add((val1 + 1) * val2);
          add((val1 - 1) * val2);
      } else if (mode === 'ADDITION' || mode === 'SUBTRACTION') {
          // Off by small amounts
          add(answer + 1);
          add(answer - 1);
          add(answer + 2);
          add(answer - 2);
          add(answer + 10);
          add(answer - 10);
      } else if (mode === 'DIVISION') {
          add(answer + 1);
          add(answer - 1);
          add(answer + 2);
          add(answer * 2);
      }

      // Fallback: Random offset logic if we don't have enough options yet
      let safetyCounter = 0;
      while (opts.size < 4 && safetyCounter < 50) {
          safetyCounter++;
          const offset = Math.floor(Math.random() * 5) + 1; // 1-5 deviation
          const sign = Math.random() > 0.5 ? 1 : -1;
          const val = answer + (offset * sign);
          add(val);
      }

      // Last Resort: Just increment
      while (opts.size < 4) {
          add(answer + opts.size + 1);
      }

      return Array.from(opts).slice(0, 4).sort(() => Math.random() - 0.5);
  };

  const generateQuestion = useCallback(() => {
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }
    questionsSinceRetryRef.current++;

    let val1, val2, answer;
    const getRandom = (min: number, max: number) => {
        if (settings.smartMode) return getWeightedRandom(min, max);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    let q: Question;
    switch (settings.mode) {
        case 'SQUARES':
            val1 = getRandom(settings.min, settings.max);
            q = { mode: 'SQUARES', val1, answer: val1 * val1, isRetry: false } as Question;
            break;
        case 'ADDITION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            q = { mode: 'ADDITION', val1, val2, answer: val1 + val2, isRetry: false } as Question;
            break;
        case 'SUBTRACTION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            if (settings.kidMode && val2 > val1) [val1, val2] = [val2, val1];
            q = { mode: 'SUBTRACTION', val1, val2, answer: val1 - val2, isRetry: false } as Question;
            break;
        case 'MULTIPLICATION':
            val1 = getRandom(settings.min, settings.max);
            val2 = getRandom(settings.min2, settings.max2);
            q = { mode: 'MULTIPLICATION', val1, val2, answer: val1 * val2, isRetry: false } as Question;
            break;
        case 'DIVISION':
            val2 = getRandom(settings.min2, settings.max2);
            answer = getRandom(settings.min, settings.max);
            val1 = val2 * answer;
            q = { mode: 'DIVISION', val1, val2, answer, isRetry: false } as Question;
            break;
        default: q = { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
    }
    return q;
  }, [settings]);

  useEffect(() => { 
      const q = generateQuestion();
      setCurrentQuestion(q);
      if (isOptionsMode) setOptions(generateOptions(q));
  }, []); 

  const handleStartGame = () => {
    setIsPlaying(true);
    setStartTime(Date.now());
    questionStartTimeRef.current = Date.now();
  };

  useEffect(() => {
    if (!isPlaying) return;
    if (timeLeft <= 0) { handleFinish(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isPlaying]);

  const handleFinish = () => {
    if (settings.smartMode) saveWeights(settings.mode, weightsRef.current, isKid);
    onFinish({ totalQuestions: history.length, correct: correctCount, score, history, startTime, endTime: Date.now(), problematicKeys: [] });
  };

  const updateWeight = (val: number, isCorrect: boolean) => {
      // Logic: 
      // Correct -> Decrease weight (harder to pick, known better)
      // Incorrect -> Increase weight (pick more often)
      const currentW = weightsRef.current[val] !== undefined ? weightsRef.current[val] : getInitialWeight(val);
      const newW = isCorrect ? Math.max(0.2, currentW * 0.9) : Math.min(5.0, currentW * 1.5);
      weightsRef.current[val] = newW;
  };

  const processAnswer = useCallback((overrideValue?: number, skipFlash?: boolean) => {
    if (!currentQuestion || !isPlaying) return;

    let userVal: number;
    if (overrideValue !== undefined) {
        userVal = overrideValue;
    } else {
        const cleanInput = inputValue.replace('−', '-');
        userVal = parseInt(cleanInput);
        if (inputValue.trim() === '') return;
    }

    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    setHistory(prev => [...prev, { question: currentQuestion, userAnswer: isNaN(userVal) ? 0 : userVal, isCorrect, timeTaken }]);

    if (settings.smartMode) {
        updateWeight(currentQuestion.val1, isCorrect);
        if (currentQuestion.val2 !== undefined) updateWeight(currentQuestion.val2, isCorrect);
    }

    if (isCorrect) {
      setScore(prev => prev + 1); setCorrectCount(prev => prev + 1);
      if (!skipFlash) {
          setFlash('green');
          setTimeout(() => setFlash('none'), 300);
      }
    } else {
      if (settings.smartMode) retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      if (!skipFlash) {
          setFlash('red');
          setTimeout(() => setFlash('none'), 300);
      }
    }

    setInputValue('');
    let nextQ = generateQuestion();
    // Avoid immediate repeat
    let attempts = 0;
    while (attempts < 5 && !nextQ.isRetry) {
        if (nextQ.val1 === currentQuestion.val1 && nextQ.val2 === currentQuestion.val2) { /* retry */ } else { break; }
        nextQ = generateQuestion(); attempts++;
    }
    setCurrentQuestion(nextQ);
    if (isOptionsMode) setOptions(generateOptions(nextQ));
    questionStartTimeRef.current = Date.now();
  }, [currentQuestion, inputValue, generateQuestion, settings.smartMode, isPlaying, isOptionsMode]);

  const handleOptionClick = (val: number) => {
      if (selectedOption !== null || !isPlaying) return;

      setSelectedOption(val);
      const isCorrect = val === currentQuestion?.answer;

      // Feedback Phase
      setFlash(isCorrect ? 'green' : 'red');
      setTimeout(() => setFlash('none'), 300);

      // Delay to show button colors
      setTimeout(() => {
          processAnswer(val, true); // Commit answer, skip duplicate flash
          setSelectedOption(null);
      }, 700);
  };

  const handleFormSubmit = (e: React.FormEvent) => { e.preventDefault(); processAnswer(); };

  useEffect(() => {
    if (isOptionsMode) return; 

    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') { onExit(); return; }
        if (!isPlaying) return;
        if (e.key >= '0' && e.key <= '9') setInputValue(p => p.length > 6 ? p : p + e.key);
        else if (e.key === 'Backspace') setInputValue(p => p.slice(0, -1));
        else if (e.key === 'Enter') processAnswer();
        else if (e.key === '-' || e.key === '−') setInputValue(p => p.includes('-') ? p : '-' + p);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [processAnswer, onExit, isPlaying, isOptionsMode]);

  const handleNumpadInput = (d: string) => { if(isPlaying) setInputValue(p => p.length > 6 ? p : p + d); };
  const handleNumpadDelete = () => { if(isPlaying) setInputValue(p => p.slice(0, -1)); };
  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  const bgClass = isKid 
    ? (flash === 'green' ? 'bg-green-100' : flash === 'red' ? 'bg-red-100' : 'bg-[#fef7ff]') 
    : (flash === 'green' ? 'bg-[#0f1f12]' : flash === 'red' ? 'bg-[#2b1212]' : 'bg-[#121212]');

  const textClass = isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]';

  return (
    <div className={`flex flex-col min-h-screen relative overflow-hidden transition-colors duration-300 ${bgClass} ${textClass}`}>

      {/* Conditionally render Numpad only if NOT in Options Mode */}
      {!isOptionsMode && (
          <DraggableNumpad 
              onInput={handleNumpadInput}
              onDelete={handleNumpadDelete}
              onEnter={() => processAnswer()}
              isKid={isKid}
          />
      )}

      {/* Start Overlay */}
      {!isPlaying && (
          <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in">
              <div className={`p-8 rounded-[32px] max-w-sm w-full text-center shadow-2xl ${isKid ? 'bg-[#f3edf7]' : 'bg-[#1e1e1e] border border-white/10'}`}>
                  <div className={`w-16 h-16 mx-auto mb-4 rounded-full flex items-center justify-center ${isKid ? 'bg-indigo-100 text-indigo-700' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                      <span className="material-symbol text-3xl">{isOptionsMode ? 'touch_app' : 'drag_pan'}</span>
                  </div>
                  <h2 className={`text-2xl font-bold mb-2 ${isKid ? 'text-[#1d1b20]' : 'text-white'}`}>
                      {isOptionsMode ? 'Ready?' : 'Position the Numpad'}
                  </h2>
                  <p className={`mb-8 text-sm ${isKid ? 'text-[#49454f]' : 'text-[#c4c7c5]'}`}>
                      {isOptionsMode ? 'Select the correct answer from the options.' : 'Drag the keypad to a comfortable spot before you begin.'}
                  </p>
                  <button
                      onClick={handleStartGame}
                      className={`w-full h-14 rounded-full font-medium text-lg flex items-center justify-center gap-2 transition-transform active:scale-95 ${isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]'}`}
                  >
                      <span className="material-symbol">play_arrow</span>
                      Start
                  </button>
              </div>
          </div>
      )}

      {/* Header */}
      <div className="flex justify-between items-center p-6 z-20">
          <div className="flex gap-3">
            <button onClick={onExit} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">close</span>
            </button>
            <button onClick={toggleFullScreen} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">{isFullscreen ? 'close_fullscreen' : 'fullscreen'}</span>
            </button>
          </div>

          <div className={`px-5 py-2 rounded-full flex items-center gap-2 ${isKid ? 'bg-indigo-50 text-indigo-900' : 'bg-[#333537] text-white'}`}>
              <span className="material-symbol text-sm">trophy</span>
              <span className="font-bold">{score}</span>
          </div>

          <div className={`w-12 h-12 rounded-full flex items-center justify-center font-mono font-bold border-2 ${timeLeft < 10 ? 'border-red-500 text-red-500' : (isKid ? 'border-indigo-200 text-indigo-900' : 'border-gray-600 text-white')}`}>
              {timeLeft}
          </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center pt-10 px-4">

        {/* Retry Label */}
        <div className="h-8 mb-4">
            {currentQuestion?.isRetry && (
                <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wider ${isKid ? 'bg-orange-100 text-orange-800' : 'bg-[#410e0b] text-[#f2b8b5]'}`}>
                    <span className="material-symbol text-sm">refresh</span>
                    Review
                </span>
            )}
        </div>

        {/* Question Display */}
        <div className="text-center mb-12 animate-slide-up">
            <h2 className="text-[5rem] md:text-[7rem] font-bold leading-none tracking-tight flex items-center justify-center gap-4">
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    <span>{currentQuestion.val1}</span>
                    <span className={`text-[3rem] md:text-[4rem] self-start mt-2 ${isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}`}>2</span>
                  </>
              ) : (
                  <>
                    <span>{currentQuestion?.val1}</span>
                    <span className={isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}>{getOperator()}</span>
                    <span>{currentQuestion?.val2}</span>
                  </>
              )}
            </h2>
        </div>

        {/* Answer Area: Either Text Input or Multiple Choice Buttons */}
        {isOptionsMode ? (
            <div className="w-full max-w-lg grid grid-cols-2 gap-4 animate-fade-in">
                {options.map((opt, idx) => {
                    let btnClass = isKid 
                        ? 'bg-white text-indigo-900 border-2 border-indigo-100 hover:border-indigo-300' 
                        : 'bg-[#1e1e1e] text-[#e3e3e3] border border-white/10 hover:bg-[#2d2f31]';

                    if (selectedOption !== null) {
                        if (opt === currentQuestion?.answer) {
                             btnClass = isKid 
                                ? 'bg-green-400 text-white border-green-500 shadow-md scale-105' 
                                : 'bg-green-900 text-green-100 border-green-700';
                        } else if (opt === selectedOption) {
                             btnClass = isKid
                                ? 'bg-red-400 text-white border-red-500'
                                : 'bg-red-900 text-red-100 border-red-700';
                        } else {
                             btnClass += " opacity-25";
                        }
                    }

                    return (
                        <button
                            key={`${idx}-${questionStartTimeRef.current}`}
                            onClick={() => handleOptionClick(opt)}
                            disabled={selectedOption !== null}
                            className={`h-24 rounded-2xl text-4xl font-bold transition-all active:scale-95 shadow-sm focus:outline-none ${btnClass}`}
                        >
                            {opt}
                        </button>
                    )
                })}
            </div>
        ) : (
            <form onSubmit={handleFormSubmit} className="w-full flex justify-center">
                <div className={`relative min-w-[200px] border-b-4 ${isKid ? 'border-indigo-200' : 'border-gray-700'}`}>
                    <input
                        type="text"
                        readOnly
                        value={inputValue}
                        className="w-full bg-transparent text-center text-[4rem] font-medium focus:outline-none py-2 font-mono"
                        placeholder="?"
                    />
                </div>
            </form>
        )}

        {/* Smart Mode Indicator */}
        {settings.smartMode && (
            <div className={`mt-12 flex items-center gap-2 text-xs font-medium px-4 py-2 rounded-full ${isKid ? 'bg-white/50 text-gray-500' : 'bg-white/5 text-gray-400'}`}>
                <span className="material-symbol text-sm filled">bolt</span>
                AI Adaptive
            </div>
        )}
      </div>
    </div>
  );
};

export default Game;

export enum AppView {
  HOME = 'HOME',
  GAME = 'GAME',
  RESULTS = 'RESULTS',
  STUDY = 'STUDY',
  STATS = 'STATS'
}

export type GameMode = 'SQUARES' | 'MULTIPLICATION' | 'ADDITION' | 'SUBTRACTION' | 'DIVISION';

export interface GameSettings {
  mode: GameMode;
  min: number;
  max: number;
  min2: number; // For multiplication second operand
  max2: number; // For multiplication second operand
  duration: number; // in seconds
  smartMode: boolean;
  kidMode: boolean;
  optionsMode?: boolean; // Enable multiple choice options
}

export interface Question {
  mode: GameMode;
  val1: number;
  val2?: number; // undefined for SQUARES
  answer: number;
  isRetry?: boolean; // Indicates this is a spaced repetition question
}

export interface AnswerRecord {
  question: Question;
  userAnswer: number;
  isCorrect: boolean;
  timeTaken: number; // ms
}

export interface GameStats {
  totalQuestions: number;
  correct: number;
  score: number;
  history: AnswerRecord[];
  startTime: number;
  endTime: number;
  problematicKeys: string[];
}

export interface SessionRecord {
  id: string;
  timestamp: number;
  mode: GameMode;
  score: number;
  total: number;
  correct: number;
  isKid: boolean;
  history?: AnswerRecord[];
  duration?: number; // seconds
  optionsMode?: boolean;
}

import React, { useState, useEffect } from 'react';
import { AppView, GameSettings, GameStats, SessionRecord } from './types';
import Home from './components/Home';
import Game from './components/Game';
import Results from './components/Results';
import Study from './components/Study';
import Stats from './components/Stats';
import { incrementGamesPlayed, loadSettings, saveSettings, saveSession } from './services/storageService';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);

  const [settings, setSettings] = useState<GameSettings>(() => {
    const saved = loadSettings();
    return saved || {
      mode: 'ADDITION', // Default to Addition for easier entry
      min: 1,
      max: 20,
      min2: 1,   
      max2: 10,  
      duration: 60,
      smartMode: true,
      kidMode: false
    };
  });

  const [lastStats, setLastStats] = useState<GameStats | null>(null);
  const [historicalSettings, setHistoricalSettings] = useState<GameSettings | null>(null);

  // Persist settings whenever they change
  useEffect(() => {
    saveSettings(settings);
  }, [settings]);

  const handleGameFinish = (stats: GameStats) => {
    incrementGamesPlayed(settings.kidMode);

    // Save Session History
    const session: SessionRecord = {
        id: Date.now().toString() + Math.random().toString().slice(2),
        timestamp: Date.now(),
        mode: settings.mode,
        score: stats.score,
        total: stats.totalQuestions,
        correct: stats.correct,
        isKid: settings.kidMode,
        history: stats.history,
        duration: settings.duration,
        optionsMode: !!settings.optionsMode
    };
    saveSession(session);

    setLastStats(stats);
    setCurrentView(AppView.RESULTS);
  };

  const handleSessionSelect = (session: SessionRecord) => {
      // Reconstruct GameStats from the saved session
      setLastStats({
          totalQuestions: session.total,
          correct: session.correct,
          score: session.score,
          history: session.history || [],
          startTime: session.timestamp, // approximate
          endTime: session.timestamp,
          problematicKeys: []
      });

      // Create a temporary settings object to ensure the Results view matches the session style (Kid vs Pro)
      // We retain the current user settings for everything else, but force the mode/theme
      setHistoricalSettings({
          ...settings,
          mode: session.mode,
          kidMode: session.isKid
      });

      setCurrentView(AppView.RESULTS);
  };

  const renderView = () => {
    switch (currentView) {
      case AppView.HOME:
        return (
          <Home 
            settings={settings} 
            setSettings={setSettings} 
            changeView={setCurrentView} 
          />
        );
      case AppView.GAME:
        return (
          <Game 
            settings={settings} 
            onFinish={handleGameFinish} 
            onExit={() => setCurrentView(AppView.HOME)}
          />
        );
      case AppView.RESULTS:
        const displaySettings = historicalSettings || settings;
        return lastStats ? (
          <Results 
            stats={lastStats} 
            settings={displaySettings}
            onRestart={() => { 
                setHistoricalSettings(null);
                setCurrentView(AppView.GAME); 
            }} 
            onHome={() => { 
                setHistoricalSettings(null);
                setCurrentView(AppView.HOME); 
            }} 
          />
        ) : (
          <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />
        );
      case AppView.STUDY:
        return (
          <Study 
            settings={settings}
            onBack={() => setCurrentView(AppView.HOME)}
          />
        );
      case AppView.STATS:
        return (
            <Stats 
                settings={settings}
                onBack={() => setCurrentView(AppView.HOME)}
                onSessionSelect={handleSessionSelect}
            />
        );
      default:
        return <Home settings={settings} setSettings={setSettings} changeView={setCurrentView} />;
    }
  };

  return (
    <div className={`antialiased min-h-screen transition-colors duration-500 ${settings.kidMode ? 'bg-sky-100' : ''}`}>
      {renderView()}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { GameSettings, GameMode, SessionRecord } from '../types';
import { loadWeights, getTotalGamesPlayed, loadSessions } from '../services/storageService';

interface StatsProps {
  settings: GameSettings;
  onBack: () => void;
  onSessionSelect: (session: SessionRecord) => void;
}

const Stats: React.FC<StatsProps> = ({ settings, onBack, onSessionSelect }) => {
  const [activeMode, setActiveMode] = useState<GameMode>('SQUARES');
  const [weights, setWeights] = useState<Record<number, number>>({});
  const [totalGames, setTotalGames] = useState(0);
  const [sessions, setSessions] = useState<SessionRecord[]>([]);

  const isKid = settings.kidMode;

  useEffect(() => {
    setTotalGames(getTotalGamesPlayed(isKid));
    // Load and filter sessions for the current profile (Kid vs Pro)
    const allSessions = loadSessions();
    setSessions(allSessions.filter(s => s.isKid === isKid));
  }, [isKid]);

  useEffect(() => {
    setWeights(loadWeights(activeMode, isKid));
  }, [activeMode, isKid]);

  // Determine grid range based on mode heuristics or data
  const getRange = () => {
      if (activeMode === 'SQUARES') return Array.from({length: 30}, (_, i) => i + 1); // 1-30
      if (activeMode === 'MULTIPLICATION') return Array.from({length: 20}, (_, i) => i + 1); // 1-20 tables
      return Array.from({length: 20}, (_, i) => i + 1); // Default
  };

  const getMasteryColor = (val: number) => {
      const w = weights[val];
      if (w === undefined) return isKid ? 'bg-gray-100 text-gray-400' : 'bg-[#2d2f31] text-gray-500'; // Unknown

      // Weight logic: < 0.8 = Mastered (Green), > 1.2 = Needs Work (Red), else Neutral
      // Higher weight means it appeared more often or was answered incorrectly
      if (w <= 0.8) return isKid ? 'bg-green-200 text-green-800' : 'bg-[#0f291e] text-[#6dd58c] border border-[#6dd58c]/30';
      if (w >= 1.5) return isKid ? 'bg-red-200 text-red-800' : 'bg-[#3c1414] text-[#f2b8b5] border border-[#f2b8b5]/30';
      if (w > 1.0) return isKid ? 'bg-orange-100 text-orange-800' : 'bg-[#2a2012] text-[#ffb4ab] border border-[#ffb4ab]/30';
      return isKid ? 'bg-blue-50 text-blue-800' : 'bg-[#1e2b3b] text-[#a8c7fa]'; // In progress
  };

  const getModeIcon = (mode: GameMode) => {
      switch(mode) {
          case 'SQUARES': return 'square_foot';
          case 'ADDITION': return 'add';
          case 'SUBTRACTION': return 'remove';
          case 'MULTIPLICATION': return 'close';
          case 'DIVISION': return 'percent';
          default: return 'calculate';
      }
  };

  const getModeLabel = (mode: GameMode) => {
      switch(mode) {
          case 'SQUARES': return 'Squares';
          case 'ADDITION': return 'Addition';
          case 'SUBTRACTION': return 'Subtraction';
          case 'MULTIPLICATION': return 'Multiplication';
          case 'DIVISION': return 'Division';
          default: return mode;
      }
  };

  const getExpectedScore = (session: SessionRecord) => {
      if (!session.duration) return null; // Legacy data might not have duration

      const minutes = session.duration / 60;
      let rate = 20; // Base Questions Per Minute

      if (session.isKid) {
          switch (session.mode) {
              case 'ADDITION':
              case 'SUBTRACTION': rate = 15; break; 
              case 'MULTIPLICATION':
              case 'DIVISION': rate = 10; break; 
              case 'SQUARES': rate = 10; break; 
              default: rate = 10;
          }
      } else {
          // Pro Mode rates
          switch (session.mode) {
              case 'SQUARES': rate = 30; break; // Fast recall
              case 'ADDITION':
              case 'SUBTRACTION': rate = 25; break; 
              case 'MULTIPLICATION': rate = 20; break; 
              case 'DIVISION': rate = 15; break; 
          }
      }

      // Multiple Choice is generally faster for recognition
      if (session.optionsMode) rate *= 1.25;

      return Math.round(rate * minutes);
  };

  const modes: { id: GameMode; label: string }[] = [
      { id: 'SQUARES', label: 'Squares' },
      { id: 'MULTIPLICATION', label: 'Multiply' },
      { id: 'ADDITION', label: 'Add' },
      { id: 'SUBTRACTION', label: 'Subtract' },
  ];

  // Theme Constants
  const pageBg = isKid ? "bg-[#fef7ff]" : "bg-[#121212]";
  const textMain = isKid ? "text-[#1d1b20]" : "text-[#e3e3e3]";
  const textSub = isKid ? "text-[#49454f]" : "text-[#c4c7c5]";
  const surface = isKid ? "bg-[#f3edf7]" : "bg-[#1e1e1e]";
  const surfaceContainer = isKid ? "bg-white" : "bg-[#2d2f31]";

  return (
    <div className={`min-h-screen flex flex-col ${pageBg} ${textMain}`}>

        {/* Header */}
        <div className={`p-4 flex items-center gap-4 ${surface}`}>
            <button onClick={onBack} className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
                <span className="material-symbol">arrow_back</span>
            </button>
            <h1 className="text-xl font-bold">Progress Stats {isKid && "(Kid Mode)"}</h1>
        </div>

        <div className="p-4 md:p-6 max-w-4xl mx-auto w-full space-y-6">

            {/* Overview Cards */}
            <div className="grid grid-cols-2 gap-4">
                <div className={`p-6 rounded-[24px] ${isKid ? 'bg-[#e8def8] text-[#1d1b20]' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                    <div className="flex items-center gap-2 mb-2 opacity-80">
                        <span className="material-symbol">stadia_controller</span>
                        <span className="text-xs font-bold uppercase tracking-wider">Sessions</span>
                    </div>
                    <span className="text-4xl font-bold">{totalGames}</span>
                </div>
                <div className={`p-6 rounded-[24px] ${isKid ? 'bg-[#c3ecd2] text-[#05210f]' : 'bg-[#334841] text-[#cce8e0]'}`}>
                    <div className="flex items-center gap-2 mb-2 opacity-80">
                        <span className="material-symbol">verified</span>
                        <span className="text-xs font-bold uppercase tracking-wider">Mastery</span>
                    </div>
                    <span className="text-4xl font-bold">
                        {Object.keys(weights).filter(k => weights[parseInt(k)] <= 0.9).length}
                    </span>
                    <span className="text-sm ml-2 opacity-70">concepts</span>
                </div>
            </div>

            {/* Heatmap Section */}
            <div className={`rounded-[24px] p-6 ${surfaceContainer}`}>
                <div className="flex items-center justify-between mb-6">
                    <h2 className="text-lg font-bold">Proficiency Heatmap</h2>
                    <div className="flex gap-2">
                        {/* Legend */}
                        <div className="flex items-center gap-1 text-[10px] uppercase font-bold tracking-wide opacity-60">
                            <div className={`w-3 h-3 rounded-full ${isKid ? 'bg-green-400' : 'bg-[#6dd58c]'}`}></div>
                            <span>Strong</span>
                        </div>
                        <div className="flex items-center gap-1 text-[10px] uppercase font-bold tracking-wide opacity-60">
                            <div className={`w-3 h-3 rounded-full ${isKid ? 'bg-red-400' : 'bg-[#f2b8b5]'}`}></div>
                            <span>Weak</span>
                        </div>
                    </div>
                </div>

                {/* Mode Selector Chips */}
                <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar">
                    {modes.map(m => (
                        <button
                            key={m.id}
                            onClick={() => setActiveMode(m.id)}
                            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                                activeMode === m.id 
                                ? (isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]')
                                : (isKid ? 'bg-white border border-[#79747e]' : 'bg-transparent border border-[#938f99]')
                            }`}
                        >
                            {m.label}
                        </button>
                    ))}
                </div>

                {/* The Grid */}
                <div className="grid grid-cols-5 sm:grid-cols-6 md:grid-cols-8 gap-3 mt-4">
                    {getRange().map(num => (
                        <div 
                            key={num} 
                            className={`aspect-square rounded-2xl flex items-center justify-center text-lg font-bold transition-transform hover:scale-105 ${getMasteryColor(num)}`}
                        >
                            {num}
                        </div>
                    ))}
                </div>

                <p className={`text-xs text-center mt-6 ${textSub}`}>
                    * Numbers show base operands (e.g., "12" represents 12², 12×N, etc.)
                </p>
            </div>

            {/* Recent Sessions List */}
            <div className={`rounded-[24px] p-6 ${surfaceContainer}`}>
                <h2 className="text-lg font-bold mb-4">Recent Sessions</h2>
                <div className="space-y-3">
                    {sessions.length === 0 && (
                        <p className={`text-sm opacity-50 text-center py-4 ${textSub}`}>No games played yet. Start a session!</p>
                    )}
                    {sessions.map((session) => {
                        const expected = getExpectedScore(session);
                        return (
                            <div 
                                key={session.id} 
                                onClick={() => onSessionSelect(session)}
                                className={`flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-colors ${surface} hover:opacity-80 active:scale-[0.98]`}
                            >
                                <div className="flex items-center gap-4">
                                    <div className={`p-3 rounded-xl flex items-center justify-center ${isKid ? 'bg-indigo-100 text-indigo-700' : 'bg-white/5 text-gray-300'}`}>
                                        <span className="material-symbol text-xl">{getModeIcon(session.mode)}</span>
                                    </div>
                                    <div>
                                        <div className="font-bold text-sm flex items-center gap-2">
                                            {getModeLabel(session.mode)}
                                            {session.optionsMode && (
                                                <span className={`text-[10px] px-1.5 py-0.5 rounded border ${isKid ? 'border-indigo-200 text-indigo-700' : 'border-gray-600 text-gray-400'}`}>
                                                    MCQ
                                                </span>
                                            )}
                                        </div>
                                        <div className={`text-xs ${textSub}`}>
                                            {new Date(session.timestamp).toLocaleDateString()} • {session.duration ? `${session.duration}s` : ''}
                                        </div>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <div className="flex flex-col items-end">
                                        <div className={`font-mono font-bold text-xl ${session.correct === session.total ? (isKid ? 'text-green-600' : 'text-green-400') : ''}`}>
                                            {session.score} <span className="text-xs font-normal opacity-50">/ {session.total}</span>
                                        </div>
                                        {expected !== null && (
                                            <div className="text-[10px] font-medium opacity-60">
                                                Exp: {expected}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    </div>
  );
};

export default Stats;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';
import DraggableNumpad from './DraggableNumpad';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [streak, setStreak] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [options, setOptions] = useState<number[]>([]);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);

  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);
  const recentQuestionsRef = useRef<string[]>([]); // To track short-term history and avoid repeats

  const isKid = settings.kidMode;
  const isOptionsMode = !!settings.optionsMode;

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.log("Error enabling fullscreen:", err);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode, isKid);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings, isKid]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current, isKid); };
  }, [settings, isKid]);

  // Enhanced SRS Scoring: Selects candidates based on Difficulty (Weight) + Novelty + Randomness
  const getSmartNumber = (min: number, max: number, avoidValues: number[] = []) => {
      const candidates: number[] = [];
      const range = max - min + 1;

      // If range is huge, sample it. If small, check all.
      const sampleSize = range > 40 ? 15 : range;

      // Always include some purely random candidates to ensure exploration
      for (let i = 0; i < sampleSize; i++) {
          const val = range > 40 
            ? Math.floor(Math.random() * range) + min 
            : min + i;
          if (!avoidValues.includes(val)) candidates.push(val);
      }

      let bestCandidate = candidates[0];
      let maxScore = -Infinity;

      candidates.forEach(val => {
          const weight = weightsRef.current[val] ?? getInitialWeight(val);

          // Score = Weight * RandomFactor
          // High weight (difficult) items have higher chance of being picked
          const noise = 0.8 + (Math.random() * 0.4); // 0.8 to 1.2
          const score = weight * noise;

          if (score > maxScore) {
              maxScore = score;
              bestCandidate = val;
          }
      });

      return bestCandidate;
  };

  // Improved Smart Options Generation
  const generateOptions = (q: Question) => {
      const { answer, mode, val1, val2 } = q;
      const opts = new Set<number>();
      opts.add(answer);

      const add = (n: number) => {
          if (n > 0 && n !== answer && Number.isInteger(n)) opts.add(n);
      };

      if (mode === 'SQUARES') {
          // Common square mistakes
          add((val1 - 1) ** 2);
          add((val1 + 1) ** 2);
          // Transposition of digits (e.g. 13^2 = 169 vs 196)
          const s = answer.toString();
          if (s.length > 1) {
              const rev = parseInt(s.split('').reverse().join(''));
              if (rev !== answer) add(rev);
          }
          add(answer + 10);
          add(answer - 10);
      } else if (mode === 'MULTIPLICATION' && val2 !== undefined) {
          // Off by one operand group
          add(val1 * (val2 + 1));
          add(val1 * (val2 - 1));
          add((val1 + 1) * val2);
          add((val1 - 1) * val2);
      } else if (mode === 'ADDITION' || mode === 'SUBTRACTION') {
          add(answer + 1);
          add(answer - 1);
          add(answer + 2);
          add(answer - 2);
          add(answer + 10);
          add(answer - 10);
      } else if (mode === 'DIVISION') {
          add(answer + 1);
          add(answer - 1);
          add(answer + 2);
          add(answer * 2);
      }

      // Fallback: Random offset logic if we don't have enough options yet
      let safetyCounter = 0;
      while (opts.size < 4 && safetyCounter < 50) {
          safetyCounter++;
          const offset = Math.floor(Math.random() * 5) + 1; // 1-5 deviation
          const sign = Math.random() > 0.5 ? 1 : -1;
          const val = answer + (offset * sign);
          add(val);
      }

      // Last Resort: Just increment
      while (opts.size < 4) {
          add(answer + opts.size + 1);
      }

      return Array.from(opts).slice(0, 4).sort(() => Math.random() - 0.5);
  };

  const generateQuestion = useCallback(() => {
    // 1. Check Retry Queue (Immediate Spaced Repetition)
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        // Only pop from retry if we've done at least 1-2 filler questions, or if queue is getting big
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }
    questionsSinceRetryRef.current++;

    let val1, val2, answer;

    // Helper to get numbers, using Smart SRS if enabled, else pure random
    const getNum = (min: number, max: number, avoid: number[] = []) => {
        if (settings.smartMode) return getSmartNumber(min, max, avoid);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    let q: Question;

    // We try to generate a question that isn't in the immediate recent history
    // Attempt up to 3 times to find a fresh one
    for(let attempt=0; attempt<3; attempt++) {
        switch (settings.mode) {
            case 'SQUARES':
                val1 = getNum(settings.min, settings.max);
                q = { mode: 'SQUARES', val1, answer: val1 * val1, isRetry: false } as Question;
                break;
            case 'ADDITION':
                val1 = getNum(settings.min, settings.max);
                val2 = getNum(settings.min2, settings.max2);
                q = { mode: 'ADDITION', val1, val2, answer: val1 + val2, isRetry: false } as Question;
                break;
            case 'SUBTRACTION':
                val1 = getNum(settings.min, settings.max);
                val2 = getNum(settings.min2, settings.max2);
                if (settings.kidMode && val2 > val1) [val1, val2] = [val2, val1];
                q = { mode: 'SUBTRACTION', val1, val2, answer: val1 - val2, isRetry: false } as Question;
                break;
            case 'MULTIPLICATION':
                val1 = getNum(settings.min, settings.max);
                val2 = getNum(settings.min2, settings.max2);
                q = { mode: 'MULTIPLICATION', val1, val2, answer: val1 * val2, isRetry: false } as Question;
                break;
            case 'DIVISION':
                val2 = getNum(settings.min2, settings.max2);
                answer = getNum(settings.min, settings.max);
                val1 = val2 * answer;
                q = { mode: 'DIVISION', val1, val2, answer, isRetry: false } as Question;
                break;
            default: q = { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
        }

        // Check uniqueness against recent history
        const key = q.mode === 'SQUARES' ? `${q.val1}` : `${q.val1}_${q.val2}`;
        if (!recentQuestionsRef.current.includes(key)) {
            break; // Found a fresh one
        }
    }

    return q!;
  }, [settings]);

  useEffect(() => { 
      const q = generateQuestion();
      setCurrentQuestion(q);
      if (isOptionsMode) setOptions(generateOptions(q));
  }, []); 

  const handleStartGame = () => {
    setIsPlaying(true);
    setStartTime(Date.now());
    questionStartTimeRef.current = Date.now();
    setStreak(0);
  };

  useEffect(() => {
    if (!isPlaying) return;
    if (timeLeft <= 0) { handleFinish(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isPlaying]);

  const handleFinish = () => {
    if (settings.smartMode) saveWeights(settings.mode, weightsRef.current, isKid);
    onFinish({ totalQuestions: history.length, correct: correctCount, score, history, startTime, endTime: Date.now(), problematicKeys: [] });
  };

  // Enhanced Weight Update: considers Reaction Time for long-term mastery tracking
  const updateWeight = (val: number, isCorrect: boolean, timeMs: number) => {
      const currentW = weightsRef.current[val] !== undefined ? weightsRef.current[val] : getInitialWeight(val);
      let newW = currentW;

      if (isCorrect) {
          // Mastery Bonus: If answered quickly (< 2.5s), decrease weight significantly
          // If answered slowly (> 5s), decrease weight slightly
          if (timeMs < 2500) newW = currentW * 0.7; // Fast -> Mastered
          else if (timeMs < 5000) newW = currentW * 0.9; // Avg -> Learning
          else newW = currentW * 0.98; // Slow -> Struggling but correct

          newW = Math.max(0.1, newW); // Clamp minimum weight
      } else {
          // Penalty: Wrong answer spikes the weight to ensure repetition
          newW = Math.min(10.0, currentW * 2.0); 
      }
      weightsRef.current[val] = newW;
  };

  const processAnswer = useCallback((overrideValue?: number, skipFlash?: boolean) => {
    if (!currentQuestion || !isPlaying) return;

    let userVal: number;
    if (overrideValue !== undefined) {
        userVal = overrideValue;
    } else {
        const cleanInput = inputValue.replace('−', '-');
        userVal = parseInt(cleanInput);
        if (inputValue.trim() === '') return;
    }

    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    setHistory(prev => [...prev, { question: currentQuestion, userAnswer: isNaN(userVal) ? 0 : userVal, isCorrect, timeTaken }]);

    // Update Short Term History (Last 4 items)
    const key = currentQuestion.mode === 'SQUARES' ? `${currentQuestion.val1}` : `${currentQuestion.val1}_${currentQuestion.val2}`;
    recentQuestionsRef.current = [key, ...recentQuestionsRef.current].slice(0, 4);

    if (settings.smartMode) {
        updateWeight(currentQuestion.val1, isCorrect, timeTaken);
        if (currentQuestion.val2 !== undefined) updateWeight(currentQuestion.val2, isCorrect, timeTaken);
    }

    if (isCorrect) {
      setScore(prev => prev + 1); 
      setCorrectCount(prev => prev + 1);
      setStreak(prev => prev + 1);
      if (!skipFlash) {
          setFlash('green');
          setTimeout(() => setFlash('none'), 300);
      }
    } else {
      setStreak(0);
      if (settings.smartMode) retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      if (!skipFlash) {
          setFlash('red');
          setTimeout(() => setFlash('none'), 300);
      }
    }

    setInputValue('');
    const nextQ = generateQuestion();
    setCurrentQuestion(nextQ);
    if (isOptionsMode) setOptions(generateOptions(nextQ));
    questionStartTimeRef.current = Date.now();
  }, [currentQuestion, inputValue, generateQuestion, settings.smartMode, isPlaying, isOptionsMode]);

  const handleOptionClick = (val: number) => {
      if (selectedOption !== null || !isPlaying) return;

      setSelectedOption(val);
      const isCorrect = val === currentQuestion?.answer;

      // Feedback Phase
      setFlash(isCorrect ? 'green' : 'red');
      setTimeout(() => setFlash('none'), 300);

      // Delay to show button colors
      setTimeout(() => {
          processAnswer(val, true); // Commit answer, skip duplicate flash
          setSelectedOption(null);
      }, 700);
  };

  const handleFormSubmit = (e: React.FormEvent) => { e.preventDefault(); processAnswer(); };

  useEffect(() => {
    if (isOptionsMode) return; 

    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') { onExit(); return; }
        if (!isPlaying) return;
        if (e.key >= '0' && e.key <= '9') setInputValue(p => p.length > 6 ? p : p + e.key);
        else if (e.key === 'Backspace') setInputValue(p => p.slice(0, -1));
        else if (e.key === 'Enter') processAnswer();
        else if (e.key === '-' || e.key === '−') setInputValue(p => p.includes('-') ? p : '-' + p);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [processAnswer, onExit, isPlaying, isOptionsMode]);

  const handleNumpadInput = (d: string) => { if(isPlaying) setInputValue(p => p.length > 6 ? p : p + d); };
  const handleNumpadDelete = () => { if(isPlaying) setInputValue(p => p.slice(0, -1)); };
  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  const bgClass = isKid 
    ? (flash === 'green' ? 'bg-green-100' : flash === 'red' ? 'bg-red-100' : 'bg-[#fef7ff]') 
    : (flash === 'green' ? 'bg-[#0f1f12]' : flash === 'red' ? 'bg-[#2b1212]' : 'bg-[#121212]');

  const textClass = isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]';

  return (
    <div className={`flex flex-col min-h-screen relative overflow-hidden transition-colors duration-300 ${bgClass} ${textClass}`}>

      {/* Conditionally render Numpad only if NOT in Options Mode */}
      {!isOptionsMode && (
          <DraggableNumpad 
              onInput={handleNumpadInput}
              onDelete={handleNumpadDelete}
              onEnter={() => processAnswer()}
              isKid={isKid}
          />
      )}

      {/* Start Overlay */}
      {!isPlaying && (
          <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in">
              <div className={`p-8 rounded-[32px] max-w-sm w-full text-center shadow-2xl ${isKid ? 'bg-[#f3edf7]' : 'bg-[#1e1e1e] border border-white/10'}`}>
                  <div className={`w-16 h-16 mx-auto mb-4 rounded-full flex items-center justify-center ${isKid ? 'bg-indigo-100 text-indigo-700' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                      <span className="material-symbol text-3xl">{isOptionsMode ? 'touch_app' : 'drag_pan'}</span>
                  </div>
                  <h2 className={`text-2xl font-bold mb-2 ${isKid ? 'text-[#1d1b20]' : 'text-white'}`}>
                      {isOptionsMode ? 'Ready?' : 'Position the Numpad'}
                  </h2>
                  <p className={`mb-8 text-sm ${isKid ? 'text-[#49454f]' : 'text-[#c4c7c5]'}`}>
                      {isOptionsMode ? 'Select the correct answer from the options.' : 'Drag the keypad to a comfortable spot before you begin.'}
                  </p>
                  <button
                      onClick={handleStartGame}
                      className={`w-full h-14 rounded-full font-medium text-lg flex items-center justify-center gap-2 transition-transform active:scale-95 ${isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]'}`}
                  >
                      <span className="material-symbol">play_arrow</span>
                      Start
                  </button>
              </div>
          </div>
      )}

      {/* Header */}
      <div className="flex justify-between items-center p-6 z-20">
          <div className="flex gap-3">
            <button onClick={onExit} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">close</span>
            </button>
            <button onClick={toggleFullScreen} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">{isFullscreen ? 'close_fullscreen' : 'fullscreen'}</span>
            </button>
          </div>

          <div className={`px-5 py-2 rounded-full flex items-center gap-2 ${isKid ? 'bg-indigo-50 text-indigo-900' : 'bg-[#333537] text-white'}`}>
              <span className="material-symbol text-sm">trophy</span>
              <span className="font-bold">{score}</span>
              {streak > 2 && (
                  <span className="ml-2 text-xs font-bold text-orange-500 animate-pulse">
                      {streak}🔥
                  </span>
              )}
          </div>

          <div className={`w-12 h-12 rounded-full flex items-center justify-center font-mono font-bold border-2 ${timeLeft < 10 ? 'border-red-500 text-red-500' : (isKid ? 'border-indigo-200 text-indigo-900' : 'border-gray-600 text-white')}`}>
              {timeLeft}
          </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center pt-10 px-4">

        {/* Retry Label */}
        <div className="h-8 mb-4">
            {currentQuestion?.isRetry && (
                <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wider ${isKid ? 'bg-orange-100 text-orange-800' : 'bg-[#410e0b] text-[#f2b8b5]'}`}>
                    <span className="material-symbol text-sm">refresh</span>
                    Review
                </span>
            )}
        </div>

        {/* Question Display */}
        <div className="text-center mb-12 animate-slide-up">
            <h2 className="text-[5rem] md:text-[7rem] font-bold leading-none tracking-tight flex items-center justify-center gap-4">
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    <span>{currentQuestion.val1}</span>
                    <span className={`text-[3rem] md:text-[4rem] self-start mt-2 ${isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}`}>2</span>
                  </>
              ) : (
                  <>
                    <span>{currentQuestion?.val1}</span>
                    <span className={isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}>{getOperator()}</span>
                    <span>{currentQuestion?.val2}</span>
                  </>
              )}
            </h2>
        </div>

        {/* Answer Area: Either Text Input or Multiple Choice Buttons */}
        {isOptionsMode ? (
            <div className="w-full max-w-lg grid grid-cols-2 gap-4 animate-fade-in">
                {options.map((opt, idx) => {
                    let btnClass = isKid 
                        ? 'bg-white text-indigo-900 border-2 border-indigo-100 hover:border-indigo-300' 
                        : 'bg-[#1e1e1e] text-[#e3e3e3] border border-white/10 hover:bg-[#2d2f31]';

                    if (selectedOption !== null) {
                        if (opt === currentQuestion?.answer) {
                             btnClass = isKid 
                                ? 'bg-green-400 text-white border-green-500 shadow-md scale-105' 
                                : 'bg-green-900 text-green-100 border-green-700';
                        } else if (opt === selectedOption) {
                             btnClass = isKid
                                ? 'bg-red-400 text-white border-red-500'
                                : 'bg-red-900 text-red-100 border-red-700';
                        } else {
                             btnClass += " opacity-25";
                        }
                    }

                    return (
                        <button
                            key={`${idx}-${questionStartTimeRef.current}`}
                            onClick={() => handleOptionClick(opt)}
                            disabled={selectedOption !== null}
                            className={`h-24 rounded-2xl text-4xl font-bold transition-all active:scale-95 shadow-sm focus:outline-none ${btnClass}`}
                        >
                            {opt}
                        </button>
                    )
                })}
            </div>
        ) : (
            <form onSubmit={handleFormSubmit} className="w-full flex justify-center">
                <div className={`relative min-w-[200px] border-b-4 ${isKid ? 'border-indigo-200' : 'border-gray-700'}`}>
                    <input
                        type="text"
                        readOnly
                        value={inputValue}
                        className="w-full bg-transparent text-center text-[4rem] font-medium focus:outline-none py-2 font-mono"
                        placeholder="?"
                    />
                </div>
            </form>
        )}

        {/* Smart Mode Indicator */}
        {settings.smartMode && (
            <div className={`mt-12 flex items-center gap-2 text-xs font-medium px-4 py-2 rounded-full ${isKid ? 'bg-white/50 text-gray-500' : 'bg-white/5 text-gray-400'}`}>
                <span className="material-symbol text-sm filled">bolt</span>
                AI Adaptive
            </div>
        )}
      </div>
    </div>
  );
};

export default Game;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppView, GameSettings, GameStats, Question, AnswerRecord } from '../types';
import { loadWeights, saveWeights, getInitialWeight } from '../services/storageService';
import DraggableNumpad from './DraggableNumpad';

interface GameProps {
  settings: GameSettings;
  onFinish: (stats: GameStats) => void;
  onExit: () => void;
}

const Game: React.FC<GameProps> = ({ settings, onFinish, onExit }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(settings.duration);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [history, setHistory] = useState<AnswerRecord[]>([]);
  const [startTime, setStartTime] = useState(Date.now());
  const [flash, setFlash] = useState<'none' | 'green' | 'red'>('none');
  const [score, setScore] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [streak, setStreak] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [options, setOptions] = useState<number[]>([]);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);

  const questionStartTimeRef = useRef<number>(Date.now());
  const weightsRef = useRef<Record<number, number>>({});
  const retryQueueRef = useRef<Question[]>([]);
  const questionsSinceRetryRef = useRef(0);

  // Anti-Repetition & Spaced Repetition State
  const recentQuestionsRef = useRef<string[]>([]); // Strict no-repeat buffer (last 3-4 items)
  const operandLastSeenRef = useRef<Record<number, number>>({}); // Tracks turn number when operand was last used
  const turnCounterRef = useRef(0); // Global turn counter for this session

  const isKid = settings.kidMode;
  const isOptionsMode = !!settings.optionsMode;

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.log("Error enabling fullscreen:", err);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    if (settings.smartMode) {
        const persisted = loadWeights(settings.mode, isKid);
        const activeWeights: Record<number, number> = {};
        const initRange = (min: number, max: number) => {
            for (let i = min; i <= max; i++) {
                if (activeWeights[i] === undefined) activeWeights[i] = getInitialWeight(i, persisted[i]);
            }
        };
        initRange(settings.min, settings.max);
        if (settings.mode !== 'SQUARES') initRange(settings.min2, settings.max2);
        weightsRef.current = activeWeights;
    }
  }, [settings, isKid]);

  useEffect(() => {
    return () => { if (settings.smartMode) saveWeights(settings.mode, weightsRef.current, isKid); };
  }, [settings, isKid]);

  // Enhanced Probabilistic Selection Algorithm
  // Solves "Repetitive" issues by using Weighted Random Sampling (Roulette Wheel) + Staleness Factors
  const getSmartNumber = (min: number, max: number, avoidValues: number[] = []) => {
      const range = max - min + 1;
      let candidates: number[] = [];

      // 1. Candidate Pool Selection
      if (range <= 40) {
          // Small range: Consider everyone
          candidates = Array.from({length: range}, (_, i) => min + i);
      } else {
          // Large range: Sample 20 candidates + ensure some high-weight ones are considered
          const pool = new Set<number>();
          // Random samples
          while(pool.size < 15) {
              pool.add(Math.floor(Math.random() * range) + min);
          }
          // Explicitly add a few known "hard" numbers if they are in range
          Object.keys(weightsRef.current).forEach(k => {
              const val = parseInt(k);
              if (val >= min && val <= max && weightsRef.current[val] > 1.2) {
                 if (Math.random() > 0.5) pool.add(val); // 50% chance to include known hard ones
              }
          });
          candidates = Array.from(pool);
      }

      // 2. Scoring (Weight + Staleness + Noise)
      let totalScore = 0;
      const scoredCandidates = candidates.map(val => {
          // Base weight (Difficulty)
          const weight = weightsRef.current[val] ?? getInitialWeight(val);

          // Staleness (How long since last seen?)
          // If turnCounter is 100 and lastSeen is 10, turnsSince = 90.
          // Multiplier grows as it stays unseen.
          const lastSeen = operandLastSeenRef.current[val] || -10; // Default to -10 so new items feel fresh
          const turnsSince = turnCounterRef.current - lastSeen;

          // Boost factor:
          // Recently seen (0-3 turns): Penalty (0.1x - 0.5x)
          // Moderately seen (4-10 turns): Normal (1.0x)
          // Long unseen (>10 turns): Boost (1.5x - 3.0x)
          let stalenessMult = 1.0;
          if (turnsSince < 4) stalenessMult = 0.2; // heavy penalty for immediate repeats
          else if (turnsSince > 15) stalenessMult = 1.5 + (Math.min(turnsSince, 50) * 0.05);

          // Random Noise (prevents deterministic loops)
          const noise = 0.8 + Math.random() * 0.4; 

          let score = weight * stalenessMult * noise;

          // Manual avoids (passed from caller)
          if (avoidValues.includes(val)) score = 0;

          totalScore += score;
          return { val, score };
      });

      // 3. Roulette Wheel Selection
      // Instead of just picking Max(score), we pick probabilistically.
      // This ensures variety while still favoring high scores.
      if (totalScore <= 0) return candidates[Math.floor(Math.random() * candidates.length)]; // Fallback

      let random = Math.random() * totalScore;
      for (const item of scoredCandidates) {
          random -= item.score;
          if (random <= 0) return item.val;
      }

      return scoredCandidates[scoredCandidates.length - 1].val;
  };

  // Improved Smart Options Generation
  const generateOptions = (q: Question) => {
      const { answer, mode, val1, val2 } = q;
      const opts = new Set<number>();
      opts.add(answer);

      const add = (n: number) => {
          if (n > 0 && n !== answer && Number.isInteger(n)) opts.add(n);
      };

      if (mode === 'SQUARES') {
          add((val1 - 1) ** 2);
          add((val1 + 1) ** 2);
          const s = answer.toString();
          if (s.length > 1) {
              const rev = parseInt(s.split('').reverse().join(''));
              if (rev !== answer) add(rev);
          }
          add(answer + 10);
          add(answer - 10);
      } else if (mode === 'MULTIPLICATION' && val2 !== undefined) {
          add(val1 * (val2 + 1));
          add(val1 * (val2 - 1));
          add((val1 + 1) * val2);
          add((val1 - 1) * val2);
      } else if (mode === 'ADDITION' || mode === 'SUBTRACTION') {
          add(answer + 1);
          add(answer - 1);
          add(answer + 2);
          add(answer - 2);
          add(answer + 10);
          add(answer - 10);
      } else if (mode === 'DIVISION') {
          add(answer + 1);
          add(answer - 1);
          add(answer + 2);
          add(answer * 2);
      }

      let safetyCounter = 0;
      while (opts.size < 4 && safetyCounter < 50) {
          safetyCounter++;
          const offset = Math.floor(Math.random() * 5) + 1;
          const sign = Math.random() > 0.5 ? 1 : -1;
          const val = answer + (offset * sign);
          add(val);
      }
      while (opts.size < 4) {
          add(answer + opts.size + 1);
      }

      return Array.from(opts).slice(0, 4).sort(() => Math.random() - 0.5);
  };

  const generateQuestion = useCallback(() => {
    // 1. Check Retry Queue (Immediate Spaced Repetition)
    // Only pop from retry if we've done at least 2 filler questions, or if queue is getting big
    if (settings.smartMode && retryQueueRef.current.length > 0) {
        if (questionsSinceRetryRef.current >= 2 || retryQueueRef.current.length > 3) {
            const retryQ = retryQueueRef.current.shift();
            if (retryQ) {
                questionsSinceRetryRef.current = 0;
                return { ...retryQ, isRetry: true };
            }
        }
    }
    questionsSinceRetryRef.current++;
    turnCounterRef.current++;

    // Helper to get numbers
    const getNum = (min: number, max: number, avoid: number[] = []) => {
        if (settings.smartMode) return getSmartNumber(min, max, avoid);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    };

    let q: Question | null = null;
    let attempts = 0;

    // Retry loop to ensure we don't pick a recently seen EXACT question
    while (attempts < 5) {
        let val1, val2, answer;

        switch (settings.mode) {
            case 'SQUARES':
                val1 = getNum(settings.min, settings.max);
                q = { mode: 'SQUARES', val1, answer: val1 * val1, isRetry: false } as Question;
                break;
            case 'ADDITION':
                val1 = getNum(settings.min, settings.max);
                val2 = getNum(settings.min2, settings.max2);
                q = { mode: 'ADDITION', val1, val2, answer: val1 + val2, isRetry: false } as Question;
                break;
            case 'SUBTRACTION':
                val1 = getNum(settings.min, settings.max);
                val2 = getNum(settings.min2, settings.max2);
                if (settings.kidMode && val2 > val1) [val1, val2] = [val2, val1];
                q = { mode: 'SUBTRACTION', val1, val2, answer: val1 - val2, isRetry: false } as Question;
                break;
            case 'MULTIPLICATION':
                val1 = getNum(settings.min, settings.max);
                val2 = getNum(settings.min2, settings.max2);
                q = { mode: 'MULTIPLICATION', val1, val2, answer: val1 * val2, isRetry: false } as Question;
                break;
            case 'DIVISION':
                val2 = getNum(settings.min2, settings.max2);
                answer = getNum(settings.min, settings.max);
                val1 = val2 * answer;
                q = { mode: 'DIVISION', val1, val2, answer, isRetry: false } as Question;
                break;
            default: 
                q = { mode: 'SQUARES', val1: 2, answer: 4 } as Question;
        }

        // Check recent history
        const key = q.mode === 'SQUARES' ? `${q.val1}` : `${q.val1}_${q.val2}`;
        if (!recentQuestionsRef.current.includes(key)) {
            // Update operand last seen stats for the chosen numbers
            operandLastSeenRef.current[q.val1] = turnCounterRef.current;
            if (q.val2 !== undefined) operandLastSeenRef.current[q.val2] = turnCounterRef.current;
            break; 
        }
        attempts++;
    }

    return q!;
  }, [settings]);

  useEffect(() => { 
      const q = generateQuestion();
      setCurrentQuestion(q);
      if (isOptionsMode) setOptions(generateOptions(q));
  }, []); 

  const handleStartGame = () => {
    setIsPlaying(true);
    setStartTime(Date.now());
    questionStartTimeRef.current = Date.now();
    setStreak(0);
    // Reset session specific tracking
    turnCounterRef.current = 0;
    operandLastSeenRef.current = {};
    recentQuestionsRef.current = [];
    questionsSinceRetryRef.current = 0;
    retryQueueRef.current = [];
  };

  useEffect(() => {
    if (!isPlaying) return;
    if (timeLeft <= 0) { handleFinish(); return; }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isPlaying]);

  const handleFinish = () => {
    if (settings.smartMode) saveWeights(settings.mode, weightsRef.current, isKid);
    onFinish({ totalQuestions: history.length, correct: correctCount, score, history, startTime, endTime: Date.now(), problematicKeys: [] });
  };

  const updateWeight = (val: number, isCorrect: boolean, timeMs: number) => {
      const currentW = weightsRef.current[val] !== undefined ? weightsRef.current[val] : getInitialWeight(val);
      let newW = currentW;

      if (isCorrect) {
          // Mastery Bonus: 
          // Fast (< 2.5s) -> significant drop
          // Medium (< 5s) -> small drop
          // Slow (> 5s) -> tiny drop (maintenance)
          if (timeMs < 2500) newW = currentW * 0.7; 
          else if (timeMs < 5000) newW = currentW * 0.9; 
          else newW = currentW * 0.98;

          newW = Math.max(0.1, newW); // Clamp minimum weight
      } else {
          // Penalty: Wrong answer spikes the weight
          newW = Math.min(10.0, currentW * 2.0); 
      }
      weightsRef.current[val] = newW;
  };

  const processAnswer = useCallback((overrideValue?: number, skipFlash?: boolean) => {
    if (!currentQuestion || !isPlaying) return;

    let userVal: number;
    if (overrideValue !== undefined) {
        userVal = overrideValue;
    } else {
        const cleanInput = inputValue.replace('−', '-');
        userVal = parseInt(cleanInput);
        if (inputValue.trim() === '') return;
    }

    const isCorrect = userVal === currentQuestion.answer;
    const timeTaken = Date.now() - questionStartTimeRef.current;

    setHistory(prev => [...prev, { question: currentQuestion, userAnswer: isNaN(userVal) ? 0 : userVal, isCorrect, timeTaken }]);

    // Update Short Term History (Last 5 items)
    const key = currentQuestion.mode === 'SQUARES' ? `${currentQuestion.val1}` : `${currentQuestion.val1}_${currentQuestion.val2}`;
    recentQuestionsRef.current = [key, ...recentQuestionsRef.current].slice(0, 5);

    if (settings.smartMode) {
        updateWeight(currentQuestion.val1, isCorrect, timeTaken);
        if (currentQuestion.val2 !== undefined) updateWeight(currentQuestion.val2, isCorrect, timeTaken);
    }

    if (isCorrect) {
      setScore(prev => prev + 1); 
      setCorrectCount(prev => prev + 1);
      setStreak(prev => prev + 1);
      if (!skipFlash) {
          setFlash('green');
          setTimeout(() => setFlash('none'), 300);
      }
    } else {
      setStreak(0);
      if (settings.smartMode) retryQueueRef.current.push({ ...currentQuestion, isRetry: true });
      if (!skipFlash) {
          setFlash('red');
          setTimeout(() => setFlash('none'), 300);
      }
    }

    setInputValue('');
    const nextQ = generateQuestion();
    setCurrentQuestion(nextQ);
    if (isOptionsMode) setOptions(generateOptions(nextQ));
    questionStartTimeRef.current = Date.now();
  }, [currentQuestion, inputValue, generateQuestion, settings.smartMode, isPlaying, isOptionsMode]);

  const handleOptionClick = (val: number) => {
      if (selectedOption !== null || !isPlaying) return;

      setSelectedOption(val);
      const isCorrect = val === currentQuestion?.answer;

      // Feedback Phase
      setFlash(isCorrect ? 'green' : 'red');
      setTimeout(() => setFlash('none'), 300);

      // Delay to show button colors
      setTimeout(() => {
          processAnswer(val, true); // Commit answer, skip duplicate flash
          setSelectedOption(null);
      }, 700);
  };

  const handleFormSubmit = (e: React.FormEvent) => { e.preventDefault(); processAnswer(); };

  useEffect(() => {
    if (isOptionsMode) return; 

    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') { onExit(); return; }
        if (!isPlaying) return;
        if (e.key >= '0' && e.key <= '9') setInputValue(p => p.length > 6 ? p : p + e.key);
        else if (e.key === 'Backspace') setInputValue(p => p.slice(0, -1));
        else if (e.key === 'Enter') processAnswer();
        else if (e.key === '-' || e.key === '−') setInputValue(p => p.includes('-') ? p : '-' + p);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [processAnswer, onExit, isPlaying, isOptionsMode]);

  const handleNumpadInput = (d: string) => { if(isPlaying) setInputValue(p => p.length > 6 ? p : p + d); };
  const handleNumpadDelete = () => { if(isPlaying) setInputValue(p => p.slice(0, -1)); };
  const getOperator = () => {
      switch (currentQuestion?.mode) {
          case 'MULTIPLICATION': return '×';
          case 'ADDITION': return '+';
          case 'SUBTRACTION': return '−';
          case 'DIVISION': return '÷';
          default: return '';
      }
  };

  const bgClass = isKid 
    ? (flash === 'green' ? 'bg-green-100' : flash === 'red' ? 'bg-red-100' : 'bg-[#fef7ff]') 
    : (flash === 'green' ? 'bg-[#0f1f12]' : flash === 'red' ? 'bg-[#2b1212]' : 'bg-[#121212]');

  const textClass = isKid ? 'text-[#1d1b20]' : 'text-[#e3e3e3]';

  return (
    <div className={`flex flex-col min-h-screen relative overflow-hidden transition-colors duration-300 ${bgClass} ${textClass}`}>

      {/* Conditionally render Numpad only if NOT in Options Mode */}
      {!isOptionsMode && (
          <DraggableNumpad 
              onInput={handleNumpadInput}
              onDelete={handleNumpadDelete}
              onEnter={() => processAnswer()}
              isKid={isKid}
          />
      )}

      {/* Start Overlay */}
      {!isPlaying && (
          <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in">
              <div className={`p-8 rounded-[32px] max-w-sm w-full text-center shadow-2xl ${isKid ? 'bg-[#f3edf7]' : 'bg-[#1e1e1e] border border-white/10'}`}>
                  <div className={`w-16 h-16 mx-auto mb-4 rounded-full flex items-center justify-center ${isKid ? 'bg-indigo-100 text-indigo-700' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                      <span className="material-symbol text-3xl">{isOptionsMode ? 'touch_app' : 'drag_pan'}</span>
                  </div>
                  <h2 className={`text-2xl font-bold mb-2 ${isKid ? 'text-[#1d1b20]' : 'text-white'}`}>
                      {isOptionsMode ? 'Ready?' : 'Position the Numpad'}
                  </h2>
                  <p className={`mb-8 text-sm ${isKid ? 'text-[#49454f]' : 'text-[#c4c7c5]'}`}>
                      {isOptionsMode ? 'Select the correct answer from the options.' : 'Drag the keypad to a comfortable spot before you begin.'}
                  </p>
                  <button
                      onClick={handleStartGame}
                      className={`w-full h-14 rounded-full font-medium text-lg flex items-center justify-center gap-2 transition-transform active:scale-95 ${isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]'}`}
                  >
                      <span className="material-symbol">play_arrow</span>
                      Start
                  </button>
              </div>
          </div>
      )}

      {/* Header */}
      <div className="flex justify-between items-center p-6 z-20">
          <div className="flex gap-3">
            <button onClick={onExit} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">close</span>
            </button>
            <button onClick={toggleFullScreen} className={`w-12 h-12 rounded-full flex items-center justify-center ${isKid ? 'bg-white hover:bg-gray-100' : 'bg-[#2d2f31] hover:bg-[#3d3f41]'} transition-colors`}>
                <span className="material-symbol">{isFullscreen ? 'close_fullscreen' : 'fullscreen'}</span>
            </button>
          </div>

          <div className={`px-5 py-2 rounded-full flex items-center gap-2 ${isKid ? 'bg-indigo-50 text-indigo-900' : 'bg-[#333537] text-white'}`}>
              <span className="material-symbol text-sm">trophy</span>
              <span className="font-bold">{score}</span>
              {streak > 2 && (
                  <span className="ml-2 text-xs font-bold text-orange-500 animate-pulse">
                      {streak}🔥
                  </span>
              )}
          </div>

          <div className={`w-12 h-12 rounded-full flex items-center justify-center font-mono font-bold border-2 ${timeLeft < 10 ? 'border-red-500 text-red-500' : (isKid ? 'border-indigo-200 text-indigo-900' : 'border-gray-600 text-white')}`}>
              {timeLeft}
          </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center pt-10 px-4">

        {/* Retry Label */}
        <div className="h-8 mb-4">
            {currentQuestion?.isRetry && (
                <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wider ${isKid ? 'bg-orange-100 text-orange-800' : 'bg-[#410e0b] text-[#f2b8b5]'}`}>
                    <span className="material-symbol text-sm">refresh</span>
                    Review
                </span>
            )}
        </div>

        {/* Question Display */}
        <div className="text-center mb-12 animate-slide-up">
            <h2 className="text-[5rem] md:text-[7rem] font-bold leading-none tracking-tight flex items-center justify-center gap-4">
              {currentQuestion?.mode === 'SQUARES' ? (
                  <>
                    <span>{currentQuestion.val1}</span>
                    <span className={`text-[3rem] md:text-[4rem] self-start mt-2 ${isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}`}>2</span>
                  </>
              ) : (
                  <>
                    <span>{currentQuestion?.val1}</span>
                    <span className={isKid ? 'text-indigo-500' : 'text-[#d0bcff]'}>{getOperator()}</span>
                    <span>{currentQuestion?.val2}</span>
                  </>
              )}
            </h2>
        </div>

        {/* Answer Area: Either Text Input or Multiple Choice Buttons */}
        {isOptionsMode ? (
            <div className="w-full max-w-lg grid grid-cols-2 gap-4 animate-fade-in">
                {options.map((opt, idx) => {
                    let btnClass = isKid 
                        ? 'bg-white text-indigo-900 border-2 border-indigo-100 hover:border-indigo-300' 
                        : 'bg-[#1e1e1e] text-[#e3e3e3] border border-white/10 hover:bg-[#2d2f31]';

                    if (selectedOption !== null) {
                        if (opt === currentQuestion?.answer) {
                             btnClass = isKid 
                                ? 'bg-green-400 text-white border-green-500 shadow-md scale-105' 
                                : 'bg-green-900 text-green-100 border-green-700';
                        } else if (opt === selectedOption) {
                             btnClass = isKid
                                ? 'bg-red-400 text-white border-red-500'
                                : 'bg-red-900 text-red-100 border-red-700';
                        } else {
                             btnClass += " opacity-25";
                        }
                    }

                    return (
                        <button
                            key={`${idx}-${questionStartTimeRef.current}`}
                            onClick={() => handleOptionClick(opt)}
                            disabled={selectedOption !== null}
                            className={`h-24 rounded-2xl text-4xl font-bold transition-all active:scale-95 shadow-sm focus:outline-none ${btnClass}`}
                        >
                            {opt}
                        </button>
                    )
                })}
            </div>
        ) : (
            <form onSubmit={handleFormSubmit} className="w-full flex justify-center">
                <div className={`relative min-w-[200px] border-b-4 ${isKid ? 'border-indigo-200' : 'border-gray-700'}`}>
                    <input
                        type="text"
                        readOnly
                        value={inputValue}
                        className="w-full bg-transparent text-center text-[4rem] font-medium focus:outline-none py-2 font-mono"
                        placeholder="?"
                    />
                </div>
            </form>
        )}

        {/* Smart Mode Indicator */}
        {settings.smartMode && (
            <div className={`mt-12 flex items-center gap-2 text-xs font-medium px-4 py-2 rounded-full ${isKid ? 'bg-white/50 text-gray-500' : 'bg-white/5 text-gray-400'}`}>
                <span className="material-symbol text-sm filled">bolt</span>
                AI Adaptive
            </div>
        )}
      </div>
    </div>
  );
};

export default Game;

import React, { useState, useEffect, useMemo } from 'react';
import { GameSettings, GameMode, SessionRecord, AnswerRecord } from '../types';
import { loadWeights, getTotalGamesPlayed, loadSessions } from '../services/storageService';

interface StatsProps {
  settings: GameSettings;
  onBack: () => void;
  onSessionSelect: (session: SessionRecord) => void;
}

const Stats: React.FC<StatsProps> = ({ settings, onBack, onSessionSelect }) => {
  const [activeMode, setActiveMode] = useState<GameMode>('MULTIPLICATION'); // Default to Multiply as per user focus
  const [weights, setWeights] = useState<Record<number, number>>({});
  const [totalGames, setTotalGames] = useState(0);
  const [sessions, setSessions] = useState<SessionRecord[]>([]);
  const [selectedOperand, setSelectedOperand] = useState<number | null>(null);

  const isKid = settings.kidMode;

  useEffect(() => {
    setTotalGames(getTotalGamesPlayed(isKid));
    const allSessions = loadSessions();
    setSessions(allSessions.filter(s => s.isKid === isKid));
  }, [isKid]);

  useEffect(() => {
    setWeights(loadWeights(activeMode, isKid));
  }, [activeMode, isKid]);

  // Determine grid range
  const getRange = () => {
      if (activeMode === 'SQUARES') return Array.from({length: 30}, (_, i) => i + 1);
      if (activeMode === 'MULTIPLICATION') return Array.from({length: 20}, (_, i) => i + 1);
      return Array.from({length: 20}, (_, i) => i + 1);
  };

  const getMasteryColor = (val: number) => {
      const w = weights[val];
      if (w === undefined) return isKid ? 'bg-gray-100 text-gray-400' : 'bg-[#2d2f31] text-gray-500';
      if (w <= 0.8) return isKid ? 'bg-green-200 text-green-800' : 'bg-[#0f291e] text-[#6dd58c] border border-[#6dd58c]/30';
      if (w >= 1.5) return isKid ? 'bg-red-200 text-red-800' : 'bg-[#3c1414] text-[#f2b8b5] border border-[#f2b8b5]/30';
      if (w > 1.0) return isKid ? 'bg-orange-100 text-orange-800' : 'bg-[#2a2012] text-[#ffb4ab] border border-[#ffb4ab]/30';
      return isKid ? 'bg-blue-50 text-blue-800' : 'bg-[#1e2b3b] text-[#a8c7fa]';
  };

  const getModeIcon = (mode: GameMode) => {
      switch(mode) {
          case 'SQUARES': return 'square_foot';
          case 'ADDITION': return 'add';
          case 'SUBTRACTION': return 'remove';
          case 'MULTIPLICATION': return 'close';
          case 'DIVISION': return 'percent';
          default: return 'calculate';
      }
  };

  const getModeLabel = (mode: GameMode) => {
      switch(mode) {
          case 'SQUARES': return 'Squares';
          case 'ADDITION': return 'Addition';
          case 'SUBTRACTION': return 'Subtraction';
          case 'MULTIPLICATION': return 'Multiplication';
          case 'DIVISION': return 'Division';
          default: return mode;
      }
  };

  const getExpectedScore = (session: SessionRecord) => {
      if (!session.duration) return null;
      const minutes = session.duration / 60;
      let rate = 20;
      if (session.isKid) {
          switch (session.mode) {
              case 'ADDITION': case 'SUBTRACTION': rate = 15; break; 
              default: rate = 10;
          }
      } else {
          switch (session.mode) {
              case 'SQUARES': rate = 30; break;
              case 'ADDITION': case 'SUBTRACTION': rate = 25; break; 
              case 'MULTIPLICATION': rate = 20; break; 
              case 'DIVISION': rate = 15; break; 
          }
      }
      if (session.optionsMode) rate *= 1.25;
      return Math.round(rate * minutes);
  };

  // Detailed Stats Calculation
  const breakdown = useMemo(() => {
    if (selectedOperand === null) return null;

    // Filter relevant answers from all sessions
    const relevantAnswers: AnswerRecord[] = [];
    sessions.forEach(s => {
        if (s.mode === activeMode && s.history) {
            s.history.forEach(a => {
                if (activeMode === 'SQUARES') {
                    if (a.question.val1 === selectedOperand) relevantAnswers.push(a);
                } else {
                    if (a.question.val1 === selectedOperand || a.question.val2 === selectedOperand) {
                        relevantAnswers.push(a);
                    }
                }
            });
        }
    });

    if (activeMode === 'SQUARES') {
        // For squares, we just summarize the single fact
        const total = relevantAnswers.length;
        const correct = relevantAnswers.filter(a => a.isCorrect).length;
        const avgTime = total ? relevantAnswers.reduce((sum, a) => sum + a.timeTaken, 0) / total : 0;
        const recent = relevantAnswers.slice(-5).reverse(); // Last 5
        return { type: 'SINGLE', total, correct, avgTime, recent };
    }

    // For operations, group by counterpart
    const statsByCounterpart: Record<number, { 
        total: number, 
        correct: number, 
        timeSum: number, 
        slowCount: number,
        lastResult: AnswerRecord
    }> = {};

    relevantAnswers.forEach(a => {
        // Identify counterpart
        let cp = a.question.val1 === selectedOperand ? a.question.val2 : a.question.val1;
        if (cp === undefined) return;

        if (!statsByCounterpart[cp]) {
            statsByCounterpart[cp] = { total: 0, correct: 0, timeSum: 0, slowCount: 0, lastResult: a };
        }

        const entry = statsByCounterpart[cp];
        entry.total++;
        if (a.isCorrect) entry.correct++;
        entry.timeSum += a.timeTaken;
        if (a.timeTaken > 5000) entry.slowCount++; // > 5s is slow
        // Keep track of the most recent attempt (sessions are roughly sorted by date, but logic might vary, assumption here is sequential processing or we check timestamp if needed. Since sessions are loaded newest first usually? No, check loadSessions. It does unshift so index 0 is newest. But here we iterate. Let's assume order.)
        // Actually, simple iteration overwrites, so the last one processed is the "last" in the array. 
        // loadSessions() -> [newest, ..., oldest].
        // We iterated sessions array which is [newest...]. So the first one we find is actually the LATEST.
        // But `relevantAnswers` collects them. 
        // Let's refine: We want the NEWEST result.
        // We will process the array and if we already have a result, we might keep it if we process newest first.
        // sessions are [newest, ...].
        // So first encounter is the latest.
        if (statsByCounterpart[cp].total === 1) { 
             entry.lastResult = a; // Initialize with the first found (newest)
        }
    });

    return { type: 'TABLE', stats: statsByCounterpart };
  }, [selectedOperand, sessions, activeMode]);

  const modes: { id: GameMode; label: string }[] = [
      { id: 'SQUARES', label: 'Squares' },
      { id: 'MULTIPLICATION', label: 'Multiply' },
      { id: 'ADDITION', label: 'Add' },
      { id: 'SUBTRACTION', label: 'Subtract' },
  ];

  // Colors
  const pageBg = isKid ? "bg-[#fef7ff]" : "bg-[#121212]";
  const textMain = isKid ? "text-[#1d1b20]" : "text-[#e3e3e3]";
  const textSub = isKid ? "text-[#49454f]" : "text-[#c4c7c5]";
  const surface = isKid ? "bg-[#f3edf7]" : "bg-[#1e1e1e]";
  const surfaceContainer = isKid ? "bg-white" : "bg-[#2d2f31]";
  const modalBg = isKid ? "bg-white" : "bg-[#2d2f31]";

  return (
    <div className={`min-h-screen flex flex-col ${pageBg} ${textMain}`}>

        {/* Header */}
        <div className={`p-4 flex items-center gap-4 ${surface}`}>
            <button onClick={onBack} className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
                <span className="material-symbol">arrow_back</span>
            </button>
            <h1 className="text-xl font-bold">Progress Stats {isKid && "(Kid Mode)"}</h1>
        </div>

        <div className="p-4 md:p-6 max-w-4xl mx-auto w-full space-y-6">

            {/* Overview Cards */}
            <div className="grid grid-cols-2 gap-4">
                <div className={`p-6 rounded-[24px] ${isKid ? 'bg-[#e8def8] text-[#1d1b20]' : 'bg-[#4f378b] text-[#eaddff]'}`}>
                    <div className="flex items-center gap-2 mb-2 opacity-80">
                        <span className="material-symbol">stadia_controller</span>
                        <span className="text-xs font-bold uppercase tracking-wider">Sessions</span>
                    </div>
                    <span className="text-4xl font-bold">{totalGames}</span>
                </div>
                <div className={`p-6 rounded-[24px] ${isKid ? 'bg-[#c3ecd2] text-[#05210f]' : 'bg-[#334841] text-[#cce8e0]'}`}>
                    <div className="flex items-center gap-2 mb-2 opacity-80">
                        <span className="material-symbol">verified</span>
                        <span className="text-xs font-bold uppercase tracking-wider">Mastery</span>
                    </div>
                    <span className="text-4xl font-bold">
                        {Object.keys(weights).filter(k => weights[parseInt(k)] <= 0.9).length}
                    </span>
                    <span className="text-sm ml-2 opacity-70">concepts</span>
                </div>
            </div>

            {/* Heatmap Section */}
            <div className={`rounded-[24px] p-6 ${surfaceContainer}`}>
                <div className="flex items-center justify-between mb-6">
                    <h2 className="text-lg font-bold">Proficiency Heatmap</h2>
                    <div className="flex gap-2">
                         <div className="flex items-center gap-1 text-[10px] uppercase font-bold tracking-wide opacity-60">
                            <div className={`w-3 h-3 rounded-full ${isKid ? 'bg-green-400' : 'bg-[#6dd58c]'}`}></div>
                            <span>Strong</span>
                        </div>
                        <div className="flex items-center gap-1 text-[10px] uppercase font-bold tracking-wide opacity-60">
                            <div className={`w-3 h-3 rounded-full ${isKid ? 'bg-red-400' : 'bg-[#f2b8b5]'}`}></div>
                            <span>Weak</span>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar">
                    {modes.map(m => (
                        <button
                            key={m.id}
                            onClick={() => { setActiveMode(m.id); setSelectedOperand(null); }}
                            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                                activeMode === m.id 
                                ? (isKid ? 'bg-[#6750a4] text-white' : 'bg-[#d0bcff] text-[#381e72]')
                                : (isKid ? 'bg-white border border-[#79747e]' : 'bg-transparent border border-[#938f99]')
                            }`}
                        >
                            {m.label}
                        </button>
                    ))}
                </div>

                <div className="grid grid-cols-5 sm:grid-cols-6 md:grid-cols-8 gap-3 mt-4">
                    {getRange().map(num => (
                        <button
                            key={num} 
                            onClick={() => setSelectedOperand(num)}
                            className={`aspect-square rounded-2xl flex items-center justify-center text-lg font-bold transition-transform hover:scale-105 active:scale-95 ${getMasteryColor(num)}`}
                        >
                            {num}
                        </button>
                    ))}
                </div>
                <p className={`text-xs text-center mt-6 ${textSub}`}>
                    Tap a number to see detailed breakdown for that table.
                </p>
            </div>

            {/* Recent Sessions List */}
            <div className={`rounded-[24px] p-6 ${surfaceContainer}`}>
                <h2 className="text-lg font-bold mb-4">Recent Sessions</h2>
                <div className="space-y-3">
                    {sessions.length === 0 && (
                        <p className={`text-sm opacity-50 text-center py-4 ${textSub}`}>No games played yet.</p>
                    )}
                    {sessions.map((session) => {
                        const expected = getExpectedScore(session);
                        return (
                            <div 
                                key={session.id} 
                                onClick={() => onSessionSelect(session)}
                                className={`flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-colors ${surface} hover:opacity-80 active:scale-[0.98]`}
                            >
                                <div className="flex items-center gap-4">
                                    <div className={`p-3 rounded-xl flex items-center justify-center ${isKid ? 'bg-indigo-100 text-indigo-700' : 'bg-white/5 text-gray-300'}`}>
                                        <span className="material-symbol text-xl">{getModeIcon(session.mode)}</span>
                                    </div>
                                    <div>
                                        <div className="font-bold text-sm flex items-center gap-2">
                                            {getModeLabel(session.mode)}
                                            {session.optionsMode && (
                                                <span className={`text-[10px] px-1.5 py-0.5 rounded border ${isKid ? 'border-indigo-200 text-indigo-700' : 'border-gray-600 text-gray-400'}`}>MCQ</span>
                                            )}
                                        </div>
                                        <div className={`text-xs ${textSub}`}>
                                            {new Date(session.timestamp).toLocaleDateString()}
                                        </div>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <div className={`font-mono font-bold text-xl ${session.correct === session.total ? 'text-green-500' : ''}`}>
                                        {session.score} <span className="text-xs font-normal opacity-50">/ {session.total}</span>
                                    </div>
                                    {expected && <div className="text-[10px] opacity-60">Exp: {expected}</div>}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>

        {/* Breakdown Modal */}
        {selectedOperand !== null && breakdown && (
            <div className="fixed inset-0 z-50 flex items-end md:items-center justify-center bg-black/60 backdrop-blur-sm p-0 md:p-4 animate-fade-in" onClick={() => setSelectedOperand(null)}>
                <div className={`w-full md:max-w-md max-h-[85vh] flex flex-col rounded-t-[32px] md:rounded-[32px] overflow-hidden shadow-2xl animate-slide-up ${modalBg} ${textMain}`} onClick={e => e.stopPropagation()}>

                    {/* Modal Header */}
                    <div className={`p-6 pb-4 flex items-center justify-between ${surface}`}>
                        <div>
                            <div className={`text-xs font-bold uppercase tracking-wider opacity-60`}>Detailed Analysis</div>
                            <h2 className="text-2xl font-bold">
                                {activeMode === 'SQUARES' ? `${selectedOperand}²` : `Table of ${selectedOperand}`}
                            </h2>
                        </div>
                        <button onClick={() => setSelectedOperand(null)} className="w-10 h-10 rounded-full flex items-center justify-center bg-black/10 hover:bg-black/20 dark:bg-white/10 dark:hover:bg-white/20">
                            <span className="material-symbol">close</span>
                        </button>
                    </div>

                    {/* Modal Content */}
                    <div className="overflow-y-auto p-4 space-y-2">
                        {breakdown.type === 'SINGLE' && (
                           <div className="space-y-4 text-center p-8">
                               <div className="text-6xl font-bold">{selectedOperand! * selectedOperand!}</div>
                               <div className="grid grid-cols-2 gap-4 mt-8">
                                   <div className={`p-4 rounded-2xl ${surface}`}>
                                       <div className="text-xs opacity-60 uppercase">Accuracy</div>
                                       <div className="text-2xl font-bold">
                                        {breakdown.total ? Math.round((breakdown.correct / breakdown.total) * 100) : 0}%
                                       </div>
                                   </div>
                                   <div className={`p-4 rounded-2xl ${surface}`}>
                                       <div className="text-xs opacity-60 uppercase">Avg Time</div>
                                       <div className="text-2xl font-bold">
                                        {(breakdown.avgTime / 1000).toFixed(1)}s
                                       </div>
                                   </div>
                               </div>
                               <div className="text-left mt-6">
                                   <h3 className="text-sm font-bold opacity-60 mb-2">Recent Attempts</h3>
                                   <div className="flex gap-2">
                                       {breakdown.recent.map((r, i) => (
                                           <div key={i} className={`flex-1 h-2 rounded-full ${r.isCorrect ? (r.timeTaken < 3000 ? 'bg-green-500' : 'bg-yellow-500') : 'bg-red-500'}`} />
                                       ))}
                                   </div>
                               </div>
                           </div> 
                        )}

                        {breakdown.type === 'TABLE' && (
                            <>
                                {Array.from({length: 12}, (_, i) => i + 1).map(k => {
                                    const stat = breakdown.stats[k];
                                    const hasData = !!stat;
                                    const accuracy = hasData ? Math.round((stat.correct / stat.total) * 100) : 0;
                                    const avgTime = hasData ? stat.timeSum / stat.total : 0;
                                    const isSlow = avgTime > 4000;
                                    const opChar = activeMode === 'MULTIPLICATION' ? '×' : activeMode === 'ADDITION' ? '+' : activeMode === 'SUBTRACTION' ? '−' : '÷';

                                    let statusColor = isKid ? "text-gray-400" : "text-gray-600";
                                    let statusText = "Unseen";
                                    let rowBg = "bg-transparent";

                                    if (hasData) {
                                        if (accuracy < 80) {
                                            statusColor = "text-red-500";
                                            statusText = "Struggling";
                                            rowBg = isKid ? "bg-red-50" : "bg-red-900/10";
                                        } else if (isSlow) {
                                            statusColor = "text-yellow-500";
                                            statusText = "Slow";
                                            rowBg = isKid ? "bg-yellow-50" : "bg-yellow-900/10";
                                        } else {
                                            statusColor = "text-green-500";
                                            statusText = "Mastered";
                                            rowBg = isKid ? "bg-green-50" : "bg-green-900/10";
                                        }

                                        // Override if last attempt was wrong
                                        if (!stat.lastResult.isCorrect) {
                                            statusText = "Last: Wrong";
                                            statusColor = "text-red-500";
                                        }
                                    }

                                    return (
                                        <div key={k} className={`flex items-center justify-between p-4 rounded-xl ${rowBg}`}>
                                            <div className="flex items-center gap-4">
                                                <div className={`text-xl font-mono font-bold w-24`}>
                                                    {selectedOperand} {opChar} {k}
                                                </div>
                                            </div>

                                            {hasData ? (
                                                <div className="text-right">
                                                    <div className={`text-xs font-bold uppercase tracking-wider mb-0.5 ${statusColor}`}>
                                                        {statusText}
                                                    </div>
                                                    <div className="text-sm font-medium opacity-80">
                                                        {(avgTime/1000).toFixed(1)}s avg • {accuracy}%
                                                    </div>
                                                </div>
                                            ) : (
                                                <div className="text-sm opacity-30 italic">Not practiced</div>
                                            )}
                                        </div>
                                    )
                                })}
                                {/* Show extra practiced numbers if they exist (outside 1-12) */}
                                {Object.keys(breakdown.stats).map(kStr => parseInt(kStr)).filter(k => k > 12).sort((a,b)=>a-b).map(k => {
                                     const stat = breakdown.stats[k];
                                     const accuracy = Math.round((stat.correct / stat.total) * 100);
                                     const avgTime = stat.timeSum / stat.total;
                                     const opChar = activeMode === 'MULTIPLICATION' ? '×' : activeMode === 'ADDITION' ? '+' : activeMode === 'SUBTRACTION' ? '−' : '÷';
                                     return (
                                        <div key={k} className={`flex items-center justify-between p-4 rounded-xl ${isKid ? 'bg-indigo-50' : 'bg-[#1e1e1e] border border-white/5'}`}>
                                            <div className="text-xl font-mono font-bold w-24">
                                                {selectedOperand} {opChar} {k}
                                            </div>
                                            <div className="text-right">
                                                <div className="text-xs font-bold uppercase tracking-wider mb-0.5 text-indigo-500">
                                                    Extra
                                                </div>
                                                <div className="text-sm font-medium opacity-80">
                                                    {(avgTime/1000).toFixed(1)}s avg • {accuracy}%
                                                </div>
                                            </div>
                                        </div>
                                     )
                                })}
                            </>
                        )}
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Stats;

import React, { useState, useEffect, useMemo } from 'react';
import { GameSettings, GameMode, SessionRecord, AnswerRecord } from '../types';
import { loadWeights, getTotalGamesPlayed, loadSessions } from '../services/storageService';

interface StatsProps {
  settings: GameSettings;
  onBack: () => void;
  onSessionSelect: (session: SessionRecord) => void;
}

const Stats: React.FC<StatsProps> = ({ settings, onBack, onSessionSelect }) => {
  const [activeMode, setActiveMode] = useState<GameMode>('MULTIPLICATION'); // Default to Multiply as per user focus
  const [weights, setWeights] = useState<Record<number, number>>({});
  const [totalGames, setTotalGames] = useState(0);
  const [sessions, setSessions] = useState<SessionRecord[]>([]);
  const [selectedOperand, setSelectedOperand] = useState<number | null>(null);

  const isKid = settings.kidMode;

  useEffect(() => {
    setTotalGames(getTotalGamesPlayed(isKid));
    const allSessions = loadSessions();
    setSessions(allSessions.filter(s => s.isKid === isKid));
  }, [isKid]);

  useEffect(() => {
    setWeights(loadWeights(activeMode, isKid));
  }, [activeMode, isKid]);

